import React, { useState } from 'react';
import { DollarSign, Lock, Eye, EyeOff, X, TrendingUp, Percent } from 'lucide-react';
import { SaleItem } from '../types';

interface SummaryProps {
  items: SaleItem[];
  onPreview: () => void;
}

export const Summary: React.FC<SummaryProps> = ({ items, onPreview }) => {
  const [showRevenue, setShowRevenue] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);

  const totalRevenue = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalCost = items.reduce((sum, item) => sum + ((item.costPrice || 0) * item.quantity), 0);
  const totalProfit = totalRevenue - totalCost;
  const profitPercentage = totalRevenue > 0 ? (totalProfit / totalRevenue) * 100 : 0;

  const handleUnlock = (e: React.FormEvent) => {
      e.preventDefault();
      if (password === '1997') {
          setShowRevenue(true);
          setShowModal(false);
          setPassword('');
          setError(false);
      } else {
          setError(true);
          setPassword('');
      }
  };

  return (
    <>
        {/* Custom Password Modal */}
        {showModal && (
            <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4 animate-fade-up">
                <div className="bg-gray-800 border border-gray-600 w-full max-w-xs p-6 rounded-2xl shadow-2xl">
                    <div className="flex justify-between items-center mb-4">
                        <h3 className="text-white font-bold">إلغاء إخفاء الأرقام</h3>
                        <button onClick={() => setShowModal(false)} className="text-gray-400 hover:text-white">
                            <X size={20} />
                        </button>
                    </div>
                    <form onSubmit={handleUnlock} className="space-y-4">
                        <div>
                            <input 
                                type="password" 
                                autoFocus
                                placeholder="أدخل كلمة المرور"
                                value={password}
                                onChange={(e) => {
                                    setPassword(e.target.value);
                                    setError(false);
                                }}
                                className={`w-full bg-gray-900 border ${error ? 'border-red-500' : 'border-gray-600'} text-white px-4 py-2 rounded-xl text-center outline-none focus:border-[#FA8072]`}
                            />
                            {error && <p className="text-red-400 text-xs mt-2 text-center">كلمة المرور غير صحيحة</p>}
                        </div>
                        <button type="submit" className="w-full bg-[#FA8072] hover:bg-[#e67365] text-white font-bold py-2 rounded-xl transition-colors">
                            تأكيد
                        </button>
                    </form>
                </div>
            </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6 print-break-inside-avoid">
             {/* Main Sales Card */}
            <div className="md:col-span-3 bg-gray-800 text-white p-5 rounded-2xl shadow-lg border border-gray-700 relative overflow-hidden flex items-center justify-between">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <p className="text-gray-400 text-xs font-medium">إجمالي المبيعات اليومية</p>
                        {showRevenue ? (
                            <button onClick={() => setShowRevenue(false)} className="text-gray-500 hover:text-white print:hidden" title="إخفاء">
                                <EyeOff size={14} />
                            </button>
                        ) : (
                            <Lock size={12} className="text-gray-500" />
                        )}
                    </div>

                    <div className="relative">
                        <h3 className={`text-3xl font-black text-[#FA8072] transition-all duration-500 ${showRevenue ? '' : 'blur-md select-none opacity-40'}`}>
                            {totalRevenue.toLocaleString('en-US')} 
                            <span className="text-sm text-gray-500 font-normal mr-1"> ل.س</span>
                        </h3>
                        {!showRevenue && (
                            <button onClick={() => setShowModal(true)} className="absolute inset-0 w-full h-full z-10 outline-none cursor-pointer bg-transparent border-none"></button>
                        )}
                    </div>
                </div>
                <div className="bg-[#FA8072]/10 p-3 rounded-2xl">
                    <TrendingUp size={28} className="text-[#FA8072]" />
                </div>
            </div>

            {/* Percentage Card */}
            <div className="md:col-span-1 bg-gray-800 text-white p-5 rounded-2xl shadow-lg border border-gray-700 flex items-center justify-between">
                <div className="flex flex-col">
                    <span className="text-gray-400 text-xs font-medium mb-1">نسبة الربح</span>
                    <div className="flex items-baseline gap-1">
                        <span className={`text-2xl font-black text-green-400 ${showRevenue ? '' : 'blur-sm opacity-40'}`}>
                            {profitPercentage.toFixed(1)}
                        </span>
                        <span className="text-xs text-green-500/60 font-bold">%</span>
                    </div>
                </div>
                <div className="bg-green-500/10 p-3 rounded-2xl">
                    <Percent size={20} className="text-green-500" />
                </div>
            </div>
        </div>
    </>
  );
};

import React, { useState } from 'react';
import { Lock, User, LogIn, AlertCircle } from 'lucide-react';

interface LoginProps {
  onLogin: () => void;
}

export const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Credentials as requested: Admin / 1997
    if (username === 'Admin' && password === '1997') {
      setError('');
      onLogin();
    } else {
      setError('اسم المستخدم أو كلمة المرور غير صحيحة');
      setPassword('');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-900 p-4" dir="rtl">
      <div className="bg-gray-800 w-full max-w-md p-10 rounded-[2.5rem] shadow-2xl border border-gray-700 animate-fade-up relative overflow-hidden">

        {/* Decorative Background Elements */}
        <div className="absolute -top-24 -right-24 w-48 h-48 bg-[#FA8072]/10 rounded-full blur-3xl"></div>
        <div className="absolute -bottom-24 -left-24 w-48 h-48 bg-blue-500/10 rounded-full blur-3xl"></div>

        {/* Logo & Header */}
        <div className="text-center mb-10 relative">
          <div className="inline-flex justify-center mb-6 relative group">
             <div className="absolute inset-0 bg-[#FA8072]/20 blur-2xl rounded-full scale-150"></div>
             <div className="relative bg-gray-900 p-4 rounded-3xl border border-gray-700 shadow-xl">
                 <img 
                    src="/logo.png" 
                    alt="Logo" 
                    className="h-20 w-auto object-contain drop-shadow-lg"
                    onError={(e) => { (e.target as HTMLImageElement).src = 'https://cdn-icons-png.flaticon.com/512/3014/3014502.png'; }}
                 />
             </div>
          </div>
          <h1 className="text-3xl font-black text-white mb-2 tracking-tight">نظام مبيعات كوكيز</h1>
          <p className="text-gray-500 text-xs font-bold uppercase tracking-widest">مرحباً بك مجدداً</p>
        </div>

        {/* Login Form */}
        <form onSubmit={handleSubmit} className="space-y-6 relative">

          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2 pr-2">
              <User size={14} className="text-[#FA8072]" />
              اسم المستخدم
            </label>
            <input
              type="text"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              className="w-full bg-gray-900/50 border border-gray-700 text-white rounded-2xl px-5 py-4 outline-none focus:border-[#FA8072] focus:ring-1 focus:ring-[#FA8072]/50 transition-all text-left dir-ltr placeholder:text-right placeholder:text-gray-600"
              placeholder="Username"
              required
              autoFocus
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2 pr-2">
              <Lock size={14} className="text-[#FA8072]" />
              كلمة المرور
            </label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full bg-gray-900/50 border border-gray-700 text-white rounded-2xl px-5 py-4 outline-none focus:border-[#FA8072] focus:ring-1 focus:ring-[#FA8072]/50 transition-all text-left dir-ltr placeholder:text-right placeholder:text-gray-600"
              placeholder="••••"
              required
            />
          </div>

          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-400 px-4 py-3 rounded-xl text-[10px] font-bold flex items-center gap-2 animate-shake">
              <AlertCircle size={14} />
              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full bg-gradient-to-r from-[#FA8072] to-orange-600 hover:from-orange-500 hover:to-orange-700 text-white font-black py-4 rounded-2xl transition-all flex items-center justify-center gap-3 shadow-xl shadow-orange-900/30 active:scale-95"
          >
            <LogIn size={20} />
            دخول للنظام
          </button>
        </form>

        <div className="mt-10 text-center text-[10px] text-gray-700 font-bold uppercase tracking-[0.2em]">
          Cookies Management System v2.0
        </div>
      </div>
    </div>
  );
};

