import React, { useState, useMemo } from 'react';
import { X, ChevronDown, ChevronUp, ArrowRight, Folder, CalendarDays, ShoppingCart, ShoppingBag, Zap } from 'lucide-react';
import { ArchivedDay, SaleItem, PurchaseInvoice } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  currentSales?: SaleItem[]; // Added to show immediate data
  currentPurchases?: PurchaseInvoice[]; // Added to show immediate data
  onClose: () => void;
  onClearHistory: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateOrder: (date: string, orderId: string, updatedItems: SaleItem[]) => void;
}

type NavStep = 'years' | 'months' | 'days';
type ViewType = 'sales' | 'purchases';

export const HistoryModal: React.FC<HistoryModalProps> = ({ 
  history, currentSales = [], currentPurchases = [], onClose, onClearHistory, onPreviewInvoice, onUpdateOrder 
}) => {
  const [step, setStep] = useState<NavStep>('years');
  const [viewType, setViewType] = useState<ViewType>('sales');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);

  // Merge history with a virtual "Today" entry if there are active sales/purchases
  const fullHistory = useMemo(() => {
      const merged = [...history];
      if (currentSales.length > 0 || currentPurchases.length > 0) {
          const today = new Date();
          const todayStr = today.toLocaleDateString('ar-SY');

          // Check if today already exists in history (unlikely if active sales exist)
          const existingTodayIdx = merged.findIndex(d => d.date === todayStr);

          const todayEntry: ArchivedDay = {
              id: 'today-active',
              date: `${todayStr} (نشط حالياً)`,
              timestamp: Date.now(),
              totalRevenue: currentSales.reduce((s, i) => s + (i.price * i.quantity), 0),
              totalExpenses: currentPurchases.reduce((s, i) => s + i.totalAmount, 0),
              totalItems: currentSales.length,
              items: currentSales,
              purchaseInvoices: currentPurchases
          };

          if (existingTodayIdx > -1) {
              // Merge if exists (though logically currentSales should be cleared on archive)
              merged[existingTodayIdx] = todayEntry;
          } else {
              merged.push(todayEntry);
          }
      }
      return merged;
  }, [history, currentSales, currentPurchases]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(fullHistory.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [fullHistory]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      fullHistory
        .filter(day => new Date(day.timestamp).getFullYear().toString() === selectedYear)
        .map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [fullHistory, selectedYear]);

  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return fullHistory.filter(day => {
      const d = new Date(day.timestamp);
      return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    }).sort((a,b) => b.timestamp - a.timestamp);
  }, [fullHistory, selectedYear, selectedMonth]);

  const getMonthName = (monthIndex: number) => {
    return new Date(2000, monthIndex).toLocaleString('ar-SY', { month: 'long' });
  };

  const renderContent = () => {
    if (step === 'years') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {years.length > 0 ? years.map(year => (
                <button key={year} onClick={() => { setSelectedYear(year); setStep('months'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <Folder size={48} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-black text-white">{year}</span>
                </button>
            )) : (
              <div className="col-span-full py-20 text-center flex flex-col items-center gap-4">
                  <div className="bg-gray-700/30 p-6 rounded-full">
                      <Zap size={48} className="text-gray-600" />
                  </div>
                  <p className="text-gray-500 font-bold">لا توجد عمليات بيع مؤرشفة بعد</p>
                  <p className="text-gray-600 text-xs">سجل أول عملية بيع لتظهر هنا تلقائياً</p>
              </div>
            )}
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => { setSelectedMonth(monthIdx); setStep('days'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <CalendarDays size={48} className="text-blue-400 group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-4 animate-fade-up h-full">
            <div className="flex bg-gray-900 p-1 rounded-xl border border-gray-700">
                <button onClick={() => setViewType('sales')} className={`flex-1 py-2 text-xs font-black rounded-lg transition-all ${viewType === 'sales' ? 'bg-white text-black shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>أرشيف المبيعات</button>
                <button onClick={() => setViewType('purchases')} className={`flex-1 py-2 text-xs font-black rounded-lg transition-all ${viewType === 'purchases' ? 'bg-[#FA8072] text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>أرشيف المشتريات</button>
            </div>

            <div className="flex-1 overflow-y-auto space-y-3 pr-1 custom-scrollbar">
                {currentDaysData.map(day => {
                    const purchaseTotal = (day.purchaseInvoices || []).reduce((s,i) => s + i.totalAmount, 0);
                    const dayTotal = viewType === 'sales' ? day.totalRevenue : purchaseTotal;
                    const isToday = day.id === 'today-active';

                    return (
                        <div key={day.id} className={`rounded-xl border overflow-hidden shadow-sm transition-all ${isToday ? 'border-orange-500/50 bg-orange-500/5' : 'border-gray-700 bg-gray-800'}`}>
                            <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className={`p-4 flex justify-between items-center cursor-pointer transition-colors ${isToday ? 'bg-orange-500/10' : 'bg-gray-900/50 hover:bg-gray-900'}`}>
                                <div className="flex items-center gap-3">
                                    <div className="text-gray-500">{expandedDayId === day.id ? <ChevronUp size={18} /> : <ChevronDown size={18} />}</div>
                                    <div className="flex flex-col">
                                        <span className={`font-bold ${isToday ? 'text-orange-400' : 'text-white'}`}>{day.date}</span>
                                        {isToday && <span className="text-[9px] font-black uppercase text-orange-600 animate-pulse">بيانات مباشرة</span>}
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    <span className={`font-black text-lg ${viewType === 'sales' ? (isToday ? 'text-orange-400' : 'text-green-400') : 'text-red-400'}`}>
                                        {dayTotal.toLocaleString()}
                                    </span>
                                    <span className="text-[10px] text-gray-600 font-bold uppercase tracking-widest">ل.س</span>
                                </div>
                            </div>

                            {expandedDayId === day.id && (
                                <div className="p-4 bg-gray-900/30 border-t border-gray-700 animate-fade-up">
                                    {viewType === 'sales' ? (
                                        <div className="space-y-2">
                                            {day.items.length > 0 ? (
                                                day.items.map((item, idx) => (
                                                    <div key={idx} className="flex justify-between items-center text-xs p-3 bg-gray-800 rounded-lg border border-gray-700/50">
                                                        <div className="flex items-center gap-2">
                                                            <ShoppingBag size={14} className="text-gray-500" />
                                                            <span className="text-white font-medium">{item.name} <span className="text-gray-500 font-normal">({item.quantity})</span></span>
                                                        </div>
                                                        <span className="text-white font-bold">{(item.price * item.quantity).toLocaleString()}</span>
                                                    </div>
                                                ))
                                            ) : (
                                                <p className="text-center py-4 text-gray-600 text-[10px] italic">لا توجد مبيعات مسجلة</p>
                                            )}
                                            {day.items.length > 0 && (
                                                <button onClick={() => onPreviewInvoice(day.items)} className="w-full mt-2 py-2 bg-gray-700 hover:bg-[#FA8072] text-white rounded-lg text-xs font-bold transition-all">معاينة الفاتورة اليومية</button>
                                            )}
                                        </div>
                                    ) : (
                                        <div className="space-y-2">
                                            {(day.purchaseInvoices || []).length > 0 ? (
                                                (day.purchaseInvoices || []).map((inv, idx) => (
                                                    <div key={idx} className="flex justify-between items-center text-xs p-3 bg-gray-800 rounded-lg border border-red-900/10">
                                                        <div className="flex items-center gap-2">
                                                            <ShoppingCart size={14} className="text-red-400/50" />
                                                            <span className="text-gray-300 font-bold">{inv.supplierName}</span>
                                                        </div>
                                                        <span className="text-red-400 font-black">{inv.totalAmount.toLocaleString()}</span>
                                                    </div>
                                                ))
                                            ) : (
                                                <p className="text-center py-4 text-gray-600 text-[10px] italic">لا توجد مشتريات لهذا اليوم</p>
                                            )}
                                        </div>
                                    )}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
  };

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-md z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-3xl w-full max-w-4xl shadow-2xl border border-gray-700 flex flex-col h-[85vh] overflow-hidden animate-fade-up">
        <div className="p-5 border-b border-gray-700 flex justify-between items-center bg-gray-900/50">
            <div className="flex items-center gap-4">
                {step !== 'years' && (
                    <button onClick={() => {
                        if (step === 'days') { setStep('months'); setSelectedMonth(-1); } 
                        else if (step === 'months') { setStep('years'); setSelectedYear(''); }
                    }} className="bg-gray-700 hover:bg-[#FA8072] p-2 rounded-full text-white transition-colors">
                        <ArrowRight size={20} />
                    </button>
                )}
                <div>
                    <h3 className="font-black text-xl text-white">سجل المبيعات</h3>
                    <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest">
                        {selectedYear} {selectedMonth !== -1 ? `• ${getMonthName(selectedMonth)}` : ''}
                    </p>
                </div>
            </div>
            <button onClick={onClose} className="p-2 text-gray-400 hover:text-white transition-colors"><X size={24} /></button>
        </div>
        <div className="p-6 flex-1 overflow-y-auto">{renderContent()}</div>
        <div className="p-4 bg-gray-900/50 border-t border-gray-700 flex justify-center">
            <div className="flex items-center gap-6">
                <div className="flex items-center gap-2"><div className="w-2.5 h-2.5 rounded-full bg-blue-400"></div><span className="text-[10px] text-gray-500 font-bold">تصفح زمنـي</span></div>
                <div className="flex items-center gap-2"><div className="w-2.5 h-2.5 rounded-full bg-orange-500 animate-pulse"></div><span className="text-[10px] text-gray-500 font-bold">مزامنة حية</span></div>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, Suspense, useCallback } from 'react';
import { Header } from './components/Header';
import { POSInterface } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { Login } from './components/Login';
import { SaleItem, Product, ArchivedDay, SaleType, Customer, PurchaseInvoice, Supplier } from './types';
import { Loader2, X } from 'lucide-react';

const InvoiceModal = React.lazy(() => import('./components/InvoiceModal').then(m => ({ default: m.InvoiceModal })));
const ProductManager = React.lazy(() => import('./components/ProductManager').then(m => ({ default: m.ProductManager })));
const HistoryModal = React.lazy(() => import('./components/HistoryModal').then(m => ({ default: m.HistoryModal })));
const DataManagementModal = React.lazy(() => import('./components/DataManagementModal').then(m => ({ default: m.DataManagementModal })));
const CustomerManager = React.lazy(() => import('./components/CustomerManager').then(m => ({ default: m.CustomerManager })));
const ExpensesModal = React.lazy(() => import('./components/ExpensesModal').then(m => ({ default: m.ExpensesModal })));
const AnalyticsModal = React.lazy(() => import('./components/AnalyticsModal').then(m => ({ default: m.AnalyticsModal })));

const ModalLoader = () => <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center"><div className="bg-gray-800 p-4 rounded-full border border-gray-700"><Loader2 className="animate-spin text-[#FA8072]" size={32} /></div></div>;

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => sessionStorage.getItem('isAuth') === 'true');
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date>(() => new Date());
  const [showLock, setShowLock] = useState<{ target: string } | null>(null);
  const [lockPass, setLockPass] = useState('');
  const [lockError, setLockError] = useState(false);

  // Core Data States
  const [sales, setSales] = useState<SaleItem[]>(() => JSON.parse(localStorage.getItem('dailySales') || '[]'));
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'));
  const [history, setHistory] = useState<ArchivedDay[]>(() => JSON.parse(localStorage.getItem('salesHistory') || '[]'));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('products') || '[]'));
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('customers') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('suppliers') || '[]'));

  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [modals, setModals] = useState({ products: false, customers: false, history: false, data: false, expenses: false, analytics: false });

  // Persistence logic
  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
    localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
    localStorage.setItem('salesHistory', JSON.stringify(history));
    localStorage.setItem('products', JSON.stringify(products));
    localStorage.setItem('customers', JSON.stringify(customers));
    localStorage.setItem('suppliers', JSON.stringify(suppliers));
    setLastSyncTime(new Date());
  }, [sales, purchaseInvoices, history, products, customers, suppliers]);

  const handleOpenProtected = (target: string) => setShowLock({ target });

  const verifyLock = () => {
    if (lockPass === '1997') {
      if (showLock?.target === 'full_reset') {
          localStorage.clear();
          window.location.reload();
      } else if (showLock) {
          setModals(m => ({ ...m, [showLock.target]: true }));
      }
      setShowLock(null);
      setLockPass('');
      setLockError(false);
    } else {
      setLockError(true);
    }
  };

  const completeOrder = useCallback((items: any[], name?: string, id?: string, type: SaleType = 'retail') => {
      const orderId = Date.now().toString();
      const now = new Date();
      const time = now.toLocaleTimeString('ar-SY', { hour: '2-digit', minute: '2-digit' });
      const nextNum = sales.length > 0 ? Math.max(...sales.map(s => s.customerNumber || 0)) + 1 : 1;

      const finalItems: SaleItem[] = items.map(i => ({ 
        ...i, 
        id: Math.random().toString(36).substring(2, 11), 
        orderId, 
        customerNumber: nextNum, 
        customerName: name || '', 
        customerId: id || '', 
        saleType: type, 
        time 
      }));

      // Immediate Sync: Update local sales state
      setSales(prev => [...prev, ...finalItems]);
  }, [sales]);

  const handleExportData = () => {
    const backup = {
      dailySales: sales,
      dailyPurchaseInvoices: purchaseInvoices,
      salesHistory: history,
      products: products,
      customers: customers,
      suppliers: suppliers,
      exportDate: new Date().toISOString()
    };
    const blob = new Blob([JSON.stringify(backup, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `cookies-backup-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportData = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = JSON.parse(e.target?.result as string);
        if (data.dailySales) setSales(data.dailySales);
        if (data.dailyPurchaseInvoices) setPurchaseInvoices(data.dailyPurchaseInvoices);
        if (data.salesHistory) setHistory(data.salesHistory);
        if (data.products) setProducts(data.products);
        if (data.customers) setCustomers(data.customers);
        if (data.suppliers) setSuppliers(data.suppliers);

        // Save to localstorage immediately to ensure persistence
        localStorage.setItem('dailySales', JSON.stringify(data.dailySales || []));
        localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(data.dailyPurchaseInvoices || []));
        localStorage.setItem('salesHistory', JSON.stringify(data.salesHistory || []));
        localStorage.setItem('products', JSON.stringify(data.products || []));
        localStorage.setItem('customers', JSON.stringify(data.customers || []));
        localStorage.setItem('suppliers', JSON.stringify(data.suppliers || []));

        alert('تمت استعادة البيانات بنجاح، سيتم إعادة تحميل الصفحة للتأكيد');
        window.location.reload();
      } catch (err) {
        alert('خطأ في قراءة ملف النسخة الاحتياطية');
      }
    };
    reader.readAsText(file);
  };

  if (!isAuthenticated) return <Login onLogin={() => { sessionStorage.setItem('isAuth', 'true'); setIsAuthenticated(true); }} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => handleOpenProtected('history')} 
        onOpenDataManagement={() => handleOpenProtected('data')} 
        onOpenExpenses={() => handleOpenProtected('expenses')}
        onOpenAnalytics={() => handleOpenProtected('analytics')}
        isOnline={navigator.onLine} 
        lastSyncTime={lastSyncTime} 
        onManualSync={() => {
            setIsSyncing(true);
            setTimeout(() => setIsSyncing(false), 800);
        }} 
        onQuickBackup={handleExportData} 
        isSyncing={isSyncing}
      />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />

        <POSInterface 
            onCompleteOrder={completeOrder} 
            products={products} 
            customers={customers} 
            onOpenProductManager={() => setModals(m => ({...m, products: true}))} 
            onOpenCustomerManager={() => setModals(m => ({...m, customers: true}))} 
        />

        <div className="mt-8">
            <SalesTable 
                items={sales} 
                onDeleteItem={id => setSales(s => s.filter(i => i.id !== id))} 
                onDeleteOrder={oid => setSales(s => s.filter(i => i.orderId !== oid))} 
                onPreviewInvoice={setInvoiceItems}
                onUpdateItemPrice={(id, p) => setSales(s => s.map(i => i.id === id ? {...i, price: p} : i))}
            />
        </div>
      </main>

      <footer className="mt-12 py-8 border-t border-gray-800/50 text-center no-print">
         <button onClick={() => handleOpenProtected('full_reset')} className="text-gray-700 text-[10px] font-bold tracking-widest uppercase">نظام مبيعات كوكيز v2.5 • 2026</button>
      </footer>

      <Suspense fallback={<ModalLoader />}>
        {modals.analytics && <AnalyticsModal history={history} currentSales={sales} currentPurchases={purchaseInvoices} onClose={() => setModals(m => ({ ...m, analytics: false }))} />}
        {modals.expenses && (
            <ExpensesModal 
                isOpen={modals.expenses} 
                onClose={() => setModals(m => ({...m, expenses: false}))} 
                currentPurchases={purchaseInvoices} 
                archivedHistory={history} 
                onAddInvoice={v => setPurchaseInvoices(p => [...p, v])} 
                onDeleteInvoice={id => setPurchaseInvoices(p => p.filter(v => v.id !== id))} 
                suppliers={suppliers} 
                onAddSupplier={s => setSuppliers(p => [...p, {...s, id: Date.now().toString()}])} 
                onDeleteSupplier={id => setSuppliers(p => p.filter(s => s.id !== id))} 
            />
        )}
        {modals.history && (
            <HistoryModal 
                history={history} 
                currentSales={sales} 
                onClose={() => setModals(m => ({...m, history: false}))} 
                onClearHistory={() => setHistory([])} 
                onPreviewInvoice={setInvoiceItems} 
                onUpdateOrder={(d, o, i) => setHistory(h => h.map(day => day.date === d ? {...day, items: day.items.map(item => item.orderId === o ? i.find(x => x.id === item.id) || item : item)} : day))} 
            />
        )}
        {modals.products && <ProductManager isOpen={modals.products} onClose={() => setModals(m => ({...m, products: false}))} products={products} onAddProduct={p => setProducts(s => [...s, {...p, id: Date.now().toString()}])} onUpdateProduct={(id, u) => setProducts(s => s.map(p => p.id === id ? {...p, ...u} : p))} onDeleteProduct={id => setProducts(s => s.filter(p => p.id !== id))} />}
        {modals.customers && <CustomerManager isOpen={modals.customers} onClose={() => setModals(m => ({...m, customers: false}))} customers={customers} onAddCustomer={c => setCustomers(s => [...s, {...c, id: Date.now().toString()}])} onDeleteCustomer={id => setCustomers(s => s.filter(c => c.id !== id))} />}
        {modals.data && <DataManagementModal onClose={() => setModals(m => ({...m, data: false}))} onExport={handleExportData} onImport={handleImportData} />}
        {invoiceItems && <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />}
      </Suspense>

      {showLock && (
        <div className="fixed inset-0 bg-black/90 z-[200] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-gray-800 border border-gray-700 p-6 rounded-3xl w-full max-w-xs shadow-2xl animate-fade-up relative">
            <button 
                onClick={() => { setShowLock(null); setLockPass(''); setLockError(false); }} 
                className="absolute top-4 left-4 text-gray-500 hover:text-white transition-colors"
            >
                <X size={20} />
            </button>
            <div className="text-center mb-6">
                <div className="w-12 h-12 bg-[#FA8072]/20 rounded-full flex items-center justify-center mx-auto mb-3">
                    <Loader2 className="text-[#FA8072] animate-pulse" size={24} />
                </div>
                <h3 className="text-white font-black text-lg">تأكيد الإجراء</h3>
                <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest mt-1">يرجى إدخال رمز التحقق (1997)</p>
            </div>

            <input 
                type="password" 
                value={lockPass} 
                onChange={e => setLockPass(e.target.value)} 
                placeholder="رمز الدخول" 
                className={`w-full bg-gray-900 border ${lockError ? 'border-red-500' : 'border-gray-700'} text-white p-4 rounded-2xl mb-4 text-center outline-none focus:border-[#FA8072] text-xl tracking-widest`} 
                autoFocus 
                onKeyDown={e => e.key === 'Enter' && verifyLock()} 
            />

            {lockError && <p className="text-red-500 text-[10px] text-center mb-4 font-bold animate-pulse">رمز الدخول غير صحيح!</p>}

            <button 
                onClick={verifyLock} 
                className="w-full bg-gradient-to-r from-[#FA8072] to-orange-600 text-white py-4 rounded-2xl font-black text-sm shadow-lg shadow-orange-900/20 active:scale-95 transition-all"
            >
                تأكيد الإجراء
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ShoppingCart, Settings, Edit3, Trash2, CheckCircle, Plus, Minus, UserPlus, X, BadgeDollarSign, Check } from 'lucide-react';
import { Product, UnitType, SaleType, Customer } from '../types';

interface POSInterfaceProps {
  onCompleteOrder: (items: any[], customerName?: string, customerId?: string, saleType?: SaleType) => void;
  products: Product[];
  customers: Customer[];
  onOpenProductManager: () => void;
  onOpenCustomerManager: () => void;
}

export const POSInterface: React.FC<POSInterfaceProps> = ({ 
    onCompleteOrder, products, customers, onOpenProductManager, onOpenCustomerManager 
}) => {
  const [cart, setCart] = useState<any[]>([]);
  const [saleType, setSaleType] = useState<SaleType>('retail');
  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [manualCustomerName, setManualCustomerName] = useState(''); 
  const [showCustomInput, setShowCustomInput] = useState(false);
  const [customForm, setCustomForm] = useState({ name: '', price: '', cost: '', unit: 'piece' as UnitType });

  // States for inline editing in cart
  const [editingPriceId, setEditingPriceId] = useState<string | null>(null);
  const [tempPrice, setTempPrice] = useState<string>('');

  const [editingQtyId, setEditingQtyId] = useState<string | null>(null);
  const [tempQty, setTempQty] = useState<string>('');

  // Update existing cart prices when saleType changes
  useEffect(() => {
    setCart(prev => prev.map(item => {
      const productDef = products.find(p => p.name === item.name && p.unitType === item.unitType);
      if (productDef) {
        return {
          ...item,
          price: saleType === 'wholesale' ? (productDef.wholesalePrice || productDef.price) : productDef.price
        };
      }
      return item;
    }));
  }, [saleType, products]);

  const addToCart = (p: Product) => {
    setCart(prev => {
      const idx = prev.findIndex(i => i.name === p.name && i.unitType === p.unitType);
      const activePrice = saleType === 'wholesale' ? (p.wholesalePrice || p.price) : p.price;

      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], quantity: next[idx].quantity + 1, price: activePrice };
        return next;
      }
      return [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: p.name, 
        price: activePrice, 
        costPrice: p.costPrice || 0, 
        quantity: 1, 
        unitType: p.unitType 
      }];
    });
  };

  const addCustomToCart = () => {
    if (!customForm.name || !customForm.price) return;
    setCart(prev => [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: customForm.name, 
        price: parseFloat(customForm.price) || 0, 
        costPrice: parseFloat(customForm.cost) || 0,
        quantity: 1,
        unitType: customForm.unit
    }]);
    setCustomForm({ name: '', price: '', cost: '', unit: 'piece' });
    setShowCustomInput(false);
  };

  const updateQty = (id: string, delta: number) => {
    setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: Math.max(0.1, parseFloat((i.quantity + delta * (i.unitType === 'kg' ? 0.1 : 1)).toFixed(2))) } : i));
  };

  const handleStartEditPrice = (item: any) => {
    setEditingPriceId(item.tempId);
    setTempPrice(item.price.toString());
    setEditingQtyId(null);
  };

  const handleSavePrice = (tempId: string) => {
    const newPrice = parseFloat(tempPrice);
    if (!isNaN(newPrice) && newPrice >= 0) {
      setCart(prev => prev.map(i => i.tempId === tempId ? { ...i, price: newPrice } : i));
    }
    setEditingPriceId(null);
  };

  const handleStartEditQty = (item: any) => {
    setEditingQtyId(item.tempId);
    setTempQty(item.quantity.toString());
    setEditingPriceId(null);
  };

  const handleSaveQty = (tempId: string) => {
    const newQty = parseFloat(tempQty);
    if (!isNaN(newQty) && newQty > 0) {
      setCart(prev => prev.map(i => i.tempId === tempId ? { ...i, quantity: newQty } : i));
    }
    setEditingQtyId(null);
  };

  const updateByPrice = (id: string, totalAmount: string) => {
    const amount = parseFloat(totalAmount);
    if (isNaN(amount) || amount <= 0) return;

    setCart(prev => prev.map(i => {
      if (i.tempId === id && i.unitType === 'kg') {
        const newQty = parseFloat((amount / i.price).toFixed(3));
        return { ...i, quantity: newQty };
      }
      return i;
    }));
  };

  const isCheckoutDisabled = cart.length === 0 || (saleType === 'wholesale' && !selectedCustomerId);

  const handleCheckout = () => {
    if (isCheckoutDisabled) return;

    const items = cart.map(({ name, price, costPrice, quantity, unitType }) => ({ name, price, costPrice, quantity, unitType }));
    const name = saleType === 'wholesale' ? customers.find(c => c.id === selectedCustomerId)?.name : manualCustomerName;

    onCompleteOrder(items, name, selectedCustomerId || undefined, saleType);

    setCart([]); 
    setManualCustomerName(''); 
    setSelectedCustomerId(''); 
    setSaleType('retail');
  };

  const total = cart.reduce((s, i) => s + (i.price * i.quantity), 0);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">
      <div className="lg:col-span-2 space-y-4">
        <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
             <h2 className="font-bold text-white flex items-center gap-2"><Settings className="text-[#FA8072]" size={20} /> قائمة المنتجات</h2>
             <button onClick={onOpenProductManager} className="text-xs bg-gray-700 hover:bg-gray-600 text-gray-300 px-3 py-1.5 rounded-lg transition-colors">تعديل الأصناف</button>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
            {products.map(p => (
                <button key={p.id} onClick={() => addToCart(p)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-gray-700 hover:bg-gray-700 hover:border-[#FA8072] text-white rounded-2xl transition-all shadow-sm active:scale-95 h-32 relative group">
                    <div className={`absolute top-2 right-2 px-1.5 py-0.5 rounded text-[10px] font-bold ${p.unitType === 'kg' ? 'bg-yellow-400 text-black' : 'bg-blue-300 text-black'}`}>{p.unitType === 'kg' ? 'كغ' : 'قطعة'}</div>
                    <span className="font-bold text-sm text-center mb-1 group-hover:text-[#FA8072]">{p.name}</span>
                    <span className="text-xs text-gray-400 bg-gray-900/50 px-2 py-1 rounded-md">
                      {(saleType === 'wholesale' ? (p.wholesalePrice || p.price) : p.price).toLocaleString()} ل.س
                    </span>
                </button>
            ))}
            <button onClick={() => setShowCustomInput(true)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-dashed border-gray-600 hover:bg-gray-700 text-gray-400 rounded-2xl h-32"><Edit3 size={20} className="mb-2" /><span className="text-xs">مادة حرة</span></button>
        </div>

        {showCustomInput && (
            <div className="bg-gray-800 p-4 rounded-xl border border-[#FA8072] animate-fade-up relative">
                <button onClick={() => setShowCustomInput(false)} className="absolute left-3 top-3 text-gray-500 hover:text-white"><X size={18} /></button>
                <h4 className="text-sm font-bold text-white mb-3">إضافة مادة حرة</h4>
                <div className="grid grid-cols-1 md:grid-cols-12 gap-2">
                    <input type="text" value={customForm.name} onChange={e => setCustomForm({...customForm, name: e.target.value})} placeholder="المادة" className="md:col-span-4 bg-gray-900 border border-gray-600 text-white px-3 py-2 rounded-lg text-sm" autoFocus />
                    <input type="number" value={customForm.cost} onChange={e => setCustomForm({...customForm, cost: e.target.value})} placeholder="التكلفة" className="md:col-span-2 bg-gray-900 border border-gray-600 text-red-400 px-3 py-2 rounded-lg text-sm" />
                    <input type="number" value={customForm.price} onChange={e => setCustomForm({...customForm, price: e.target.value})} placeholder="البيع" className="md:col-span-2 bg-gray-900 border border-gray-600 text-green-400 px-3 py-2 rounded-lg text-sm" />
                    <select value={customForm.unit} onChange={e => setCustomForm({...customForm, unit: e.target.value as UnitType})} className="md:col-span-2 bg-gray-900 border border-gray-600 text-white px-2 py-2 rounded-lg text-sm"><option value="piece">قطعة</option><option value="kg">كغ</option></select>
                    <button onClick={addCustomToCart} className="md:col-span-2 bg-[#FA8072] text-white rounded-lg font-bold">إضافة</button>
                </div>
            </div>
        )}
      </div>

      <div className="lg:col-span-1">
        <div className="bg-gray-800 rounded-2xl border border-gray-700 shadow-xl overflow-hidden flex flex-col h-full min-h-[500px]">
            <div className="bg-gray-900/80 p-4 border-b border-gray-700 space-y-3">
                <div className="flex justify-between items-center">
                    <h3 className="font-bold text-white flex items-center gap-2"><ShoppingCart size={20} className="text-[#FA8072]" /> سلة المبيعات</h3>
                    {cart.length > 0 && <button onClick={() => setCart([])} className="text-xs text-red-400 underline">إلغاء السلة</button>}
                </div>
                <div className="grid grid-cols-2 bg-gray-700 p-1 rounded-lg">
                    <button onClick={() => setSaleType('retail')} className={`py-1.5 text-xs font-bold rounded-md transition-colors ${saleType === 'retail' ? 'bg-white text-black' : 'text-gray-400'}`}>مفرق</button>
                    <button onClick={() => setSaleType('wholesale')} className={`py-1.5 text-xs font-bold rounded-md transition-colors ${saleType === 'wholesale' ? 'bg-[#FA8072] text-white' : 'text-gray-400'}`}>جملة</button>
