import React, { useMemo, useState } from 'react';
import { X, BarChart3, ArrowUpRight, TrendingUp, Info } from 'lucide-react';
import { ArchivedDay, SaleItem, PurchaseInvoice } from '../types';

interface AnalyticsModalProps {
  history: ArchivedDay[];
  currentSales: SaleItem[];
  currentPurchases: PurchaseInvoice[];
  onClose: () => void;
}

export const AnalyticsModal: React.FC<AnalyticsModalProps> = ({ history, currentSales, currentPurchases, onClose }) => {
  const [daysCount, setDaysCount] = useState<7 | 15 | 30>(7);

  const processedData = useMemo(() => {
    const todayRevenue = currentSales.reduce((s, i) => s + (i.price * i.quantity), 0);
    const todayPurchases = currentPurchases.reduce((s, i) => s + i.totalAmount, 0);

    const combined = [
      ...history.map(day => ({
        date: day.date,
        revenue: day.totalRevenue,
        purchases: (day.purchaseInvoices || []).reduce((s, i) => s + i.totalAmount, 0),
        profit: day.totalRevenue - (day.purchaseInvoices || []).reduce((s, i) => s + i.totalAmount, 0),
        timestamp: day.timestamp
      })),
      {
        date: 'اليوم',
        revenue: todayRevenue,
        purchases: todayPurchases,
        profit: todayRevenue - todayPurchases,
        timestamp: Date.now()
      }
    ].sort((a, b) => a.timestamp - b.timestamp);

    return combined.slice(-daysCount);
  }, [history, currentSales, currentPurchases, daysCount]);

  const stats = useMemo(() => {
    return {
      totalRevenue: processedData.reduce((s, d) => s + d.revenue, 0),
      totalPurchases: processedData.reduce((s, d) => s + d.purchases, 0),
      totalProfit: processedData.reduce((s, d) => s + d.profit, 0)
    };
  }, [processedData]);

  // SVG Chart Logic
  const chartHeight = 300;
  const chartWidth = 900;
  const padding = 60;
  const maxVal = Math.max(...processedData.flatMap(d => [d.revenue, d.purchases, 10000]));
  const getX = (index: number) => padding + (index * (chartWidth - 2 * padding) / (processedData.length - 1 || 1));
  const getY = (value: number) => chartHeight - padding - ((value / (maxVal || 1)) * (chartHeight - 2 * padding));

  return (
    <div className="fixed inset-0 bg-black/95 backdrop-blur-md z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-[3rem] w-full max-w-5xl shadow-2xl border border-gray-700 animate-fade-up overflow-hidden flex flex-col max-h-[95vh]">
        <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-900/50">
          <div className="flex items-center gap-4">
             <div className="bg-[#FA8072]/20 p-3 rounded-2xl"><BarChart3 className="text-[#FA8072]" size={28} /></div>
             <h3 className="font-black text-2xl text-white">التحليلات المالية المباشرة</h3>
          </div>
          <button onClick={onClose} className="p-3 hover:bg-gray-700 rounded-2xl transition-all text-gray-400"><X size={24} /></button>
        </div>

        <div className="p-8 overflow-y-auto flex-1 space-y-10">
          <div className="flex justify-center">
             <div className="flex gap-2 bg-gray-900/80 p-1.5 rounded-2xl border border-gray-700">
                {[7, 15, 30].map(n => (
                   <button key={n} onClick={() => setDaysCount(n as any)} className={`px-6 py-2 rounded-xl text-xs font-black transition-all ${daysCount === n ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}>آخر {n} يوم</button>
                ))}
             </div>
          </div>

          <div className="bg-gray-950/50 rounded-[2.5rem] border border-gray-700 p-8 shadow-inner relative overflow-hidden">
             {/* Legend */}
             <div className="absolute top-4 right-10 flex gap-6 text-[10px] font-black uppercase">
                 <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-blue-500"></div><span className="text-gray-400">المبيعات</span></div>
                 <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-red-500"></div><span className="text-gray-400">المشتريات</span></div>
             </div>

             <div className="overflow-x-auto pb-6 custom-scrollbar">
                <svg viewBox={`0 0 ${chartWidth} ${chartHeight}`} className="w-full h-auto min-w-[800px]">
                    {/* Grid Lines */}
                    {[0, 0.25, 0.5, 0.75, 1].map((v, i) => (
                        <line key={i} x1={padding} y1={getY(maxVal * v)} x2={chartWidth - padding} y2={getY(maxVal * v)} stroke="#374151" strokeWidth="1" strokeDasharray="5,5" />
                    ))}

                    {/* Data Lines */}
                    <polyline points={processedData.map((d, i) => `${getX(i)},${getY(d.revenue)}`).join(' ')} fill="none" stroke="#3B82F6" strokeWidth="5" strokeLinecap="round" strokeLinejoin="round" />
                    <polyline points={processedData.map((d, i) => `${getX(i)},${getY(d.purchases)}`).join(' ')} fill="none" stroke="#EF4444" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" />

                    {/* Points & Labels */}
                    {processedData.map((d, i) => (
                        <g key={i}>
                            <circle cx={getX(i)} cy={getY(d.revenue)} r="7" fill="#1F2937" stroke="#3B82F6" strokeWidth="3" />
                            <circle cx={getX(i)} cy={getY(d.purchases)} r="6" fill="#1F2937" stroke="#EF4444" strokeWidth="2" />
                            <text x={getX(i)} y={chartHeight - 20} textAnchor="middle" className="text-[12px] fill-gray-500 font-bold">{d.date.split('/')[0]}</text>
                        </g>
                    ))}
                </svg>
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
             <div className="bg-blue-600/10 p-6 rounded-[2rem] border border-blue-500/20 text-center">
                <span className="text-[10px] font-black text-blue-400 uppercase tracking-widest block mb-2">إجمالي المبيعات</span>
                <span className="text-3xl font-black text-white">{stats.totalRevenue.toLocaleString()}</span>
             </div>
             <div className="bg-red-600/10 p-6 rounded-[2rem] border border-red-500/20 text-center">
                <span className="text-[10px] font-black text-red-400 uppercase tracking-widest block mb-2">إجمالي المشتريات</span>
                <span className="text-3xl font-black text-white">{stats.totalPurchases.toLocaleString()}</span>
             </div>
             <div className="bg-green-600/10 p-6 rounded-[2rem] border border-green-500/20 text-center relative overflow-hidden group">
                <TrendingUp size={60} className="absolute -bottom-4 -right-4 text-green-500/10 group-hover:scale-110 transition-transform" />
                <span className="text-[10px] font-black text-green-400 uppercase tracking-widest block mb-2">صافي الربح</span>
                <span className="text-3xl font-black text-white">{stats.totalProfit.toLocaleString()}</span>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Trash2, ShoppingBag, Search, User, Download, Store, Edit3 } from 'lucide-react';
import { SaleItem } from '../types';

interface SalesTableProps {
  items: SaleItem[];
  onDeleteItem: (id: string) => void;
  onDeleteOrder?: (orderId: string) => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateItemPrice?: (itemId: string, newPrice: number) => void; 
}

export const SalesTable: React.FC<SalesTableProps> = ({ items, onDeleteItem, onDeleteOrder, onPreviewInvoice, onUpdateItemPrice }) => {
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [confirmOrderId, setConfirmOrderId] = useState<string | null>(null);
  const [editingPriceId, setEditingPriceId] = useState<string | null>(null);
  const [tempPrice, setTempPrice] = useState<string>('');

  const groupedOrders = useMemo(() => {
    const groups: { [key: string]: SaleItem[] } = {};
    items.forEach(item => {
        const key = item.orderId;
        if (!groups[key]) groups[key] = [];
        groups[key].push(item);
    });
    return Object.values(groups).sort((a, b) => b[0].orderId.localeCompare(a[0].orderId));
  }, [items]);

  const filteredOrders = useMemo(() => {
      if (!searchTerm) return groupedOrders;
      const term = searchTerm.toLowerCase();
      return groupedOrders.filter(g => (g[0].customerName?.toLowerCase() || '').includes(term));
  }, [groupedOrders, searchTerm]);

  const savePrice = (itemId: string) => {
    const price = parseFloat(tempPrice);
    if (!isNaN(price) && onUpdateItemPrice) onUpdateItemPrice(itemId, price);
    setEditingPriceId(null);
  };

  if (items.length === 0) return <div className="p-20 text-center text-gray-500 font-bold bg-gray-800 rounded-3xl border border-gray-700">لا توجد مبيعات مسجلة لهذا اليوم.</div>;

  return (
    <div className="space-y-5">
        <div className="relative max-w-md mx-auto no-print">
            <Search className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
            <input type="text" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="بحث باسم العميل..." className="w-full bg-gray-800 border border-gray-700 text-white rounded-2xl pr-12 pl-4 py-3 outline-none focus:border-[#FA8072] transition-all" />
        </div>

        <div className="space-y-4">
            {filteredOrders.map(group => {
                const total = group.reduce((s, i) => s + (i.price * i.quantity), 0);
                const first = group[0];
                return (
                    <div key={first.orderId} className="bg-gray-800 rounded-2xl border border-gray-700 overflow-hidden shadow-lg animate-fade-up">
                        <div className="p-4 bg-gray-900/50 flex justify-between items-center border-b border-gray-700">
                            <div className="flex items-center gap-3">
                                {first.saleType === 'wholesale' ? <Store size={16} className="text-orange-400" /> : <User size={16} className="text-blue-400" />}
                                <span className="font-bold text-white">{first.customerName || 'زبون عام'}</span>
                                <span className="text-[10px] text-gray-500 font-mono">{first.time}</span>
                            </div>
                            <div className="flex items-center gap-4">
                                <span className="font-black text-[#FA8072]">{total.toLocaleString()} <small className="text-[9px] text-gray-600 font-normal">ل.س</small></span>
                                <button onClick={() => onPreviewInvoice(group)} className="text-gray-400 hover:text-white transition-colors"><Download size={18} /></button>
                                <button onClick={() => onDeleteOrder && onDeleteOrder(first.orderId)} className="text-gray-600 hover:text-red-400 transition-colors"><Trash2 size={18} /></button>
                            </div>
                        </div>
                        <table className="w-full text-right text-xs">
                            <tbody className="divide-y divide-gray-700/50">
                                {group.map(item => (
                                    <tr key={item.id} className="hover:bg-gray-700/20">
                                        <td className="p-3 text-white font-medium">{item.name}</td>
                                        <td className="p-3 text-gray-400">الكمية: {item.quantity}</td>
                                        <td className="p-3">
                                            {editingPriceId === item.id ? (
                                                <input type="number" value={tempPrice} onChange={e => setTempPrice(e.target.value)} onBlur={() => savePrice(item.id)} className="w-20 bg-gray-950 border border-[#FA8072] text-white rounded px-2" autoFocus />
                                            ) : (
                                                <div className="flex items-center gap-2 cursor-pointer group/item" onClick={() => { setEditingPriceId(item.id); setTempPrice(item.price.toString()); }}>
                                                    <span className="text-gray-300">{item.price.toLocaleString()}</span>
                                                    <Edit3 size={12} className="text-gray-500 group-hover/item:text-[#FA8072] transition-colors" />
                                                </div>
                                            )}
                                        </td>
                                        <td className="p-3 text-white font-black">{(item.price * item.quantity).toLocaleString()}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                );
            })}
        </div>
    </div>
  );
};

import React, { useState } from 'react';
import { X, Copy, Check, Download, FileSpreadsheet } from 'lucide-react';
import { SaleItem } from '../types';
import { utils, writeFile } from 'xlsx';

interface InvoiceModalProps {
  items: SaleItem[];
  onClose: () => void;
}

export const InvoiceModal: React.FC<InvoiceModalProps> = ({ items, onClose }) => {
  const [copied, setCopied] = useState(false);
  const total = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const date = new Date().toLocaleDateString('ar-SY');

  const handleDownloadExcel = () => {
    const data = items.map(i => ({ "المادة": i.name, "الكمية": i.quantity, "السعر": i.price, "الإجمالي": i.price * i.quantity }));
    data.push({ "المادة": "المجموع الكلي", "الكمية": 0, "السعر": 0, "الإجمالي": total });
    const ws = utils.json_to_sheet(data);
    const wb = utils.book_new();
    utils.book_append_sheet(wb, ws, "Invoice");
    writeFile(wb, `Cookies-Invoice-${Date.now()}.xlsx`);
  };

  const handleCopy = () => {
    const text = `فاتورة مخبز كوكيز\nالتاريخ: ${date}\nالعميل: ${items[0]?.customerName || 'زبون عام'}\nالمجموع: ${total} ل.س`;
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-[2.5rem] w-full max-w-md shadow-2xl border border-gray-700 animate-fade-up overflow-hidden">
        <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-900/50">
          <h3 className="font-black text-xl text-white">تحميل الفاتورة</h3>
          <button onClick={onClose} className="p-2 text-gray-400 hover:text-white transition-colors"><X size={24} /></button>
        </div>

        <div className="p-10 space-y-6">
            <div className="text-center space-y-2">
                <div className="w-16 h-16 bg-blue-500/10 rounded-2xl flex items-center justify-center mx-auto mb-4 text-blue-400 border border-blue-500/20">
                    <Download size={32} />
                </div>
                <h4 className="text-white font-bold text-lg">جاهز للتحميل</h4>
                <p className="text-gray-500 text-sm">تم إنشاء ملف الفاتورة لطلب: <span className="text-gray-300">{items[0]?.customerName || 'زبون عام'}</span></p>
            </div>

            <div className="space-y-3">
                <button 
                  onClick={handleDownloadExcel} 
                  className="w-full bg-green-600 hover:bg-green-500 text-white py-4 rounded-2xl font-black text-sm flex items-center justify-center gap-3 transition-all shadow-xl active:scale-95"
                >
                    <FileSpreadsheet size={20} />
                    تحميل ملف Excel
                </button>
                <button 
                  onClick={handleCopy} 
                  className={`w-full py-4 rounded-2xl font-black text-sm flex items-center justify-center gap-3 transition-all border border-gray-700 ${copied ? 'bg-blue-600 text-white' : 'bg-gray-900/50 text-gray-400 hover:text-white'}`}
                >
                    {copied ? <Check size={20} /> : <Copy size={20} />}
                    {copied ? 'تم النسخ' : 'نسخ نص الفاتورة'}
                </button>
            </div>

            <div className="bg-orange-500/5 border border-orange-500/10 p-4 rounded-2xl text-[11px] text-orange-400 text-center font-bold">
                ملاحظة: يتم حفظ الملفات تلقائياً في مجلد "Downloads" على جهازك.
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, Suspense, useCallback } from 'react';
import { Header } from './components/Header';
import { POSInterface } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { Login } from './components/Login';
import { SaleItem, Product, ArchivedDay, SaleType, Customer, PurchaseInvoice, Supplier } from './types';
import { Loader2, X } from 'lucide-react';

const InvoiceModal = React.lazy(() => import('./components/InvoiceModal').then(m => ({ default: m.InvoiceModal })));
const ProductManager = React.lazy(() => import('./components/ProductManager').then(m => ({ default: m.ProductManager })));
const HistoryModal = React.lazy(() => import('./components/HistoryModal').then(m => ({ default: m.HistoryModal })));
const DataManagementModal = React.lazy(() => import('./components/DataManagementModal').then(m => ({ default: m.DataManagementModal })));
const CustomerManager = React.lazy(() => import('./components/CustomerManager').then(m => ({ default: m.CustomerManager })));
const ExpensesModal = React.lazy(() => import('./components/ExpensesModal').then(m => ({ default: m.ExpensesModal })));
const AnalyticsModal = React.lazy(() => import('./components/AnalyticsModal').then(m => ({ default: m.AnalyticsModal })));

const ModalLoader = () => <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center"><div className="bg-gray-800 p-4 rounded-full border border-gray-700"><Loader2 className="animate-spin text-[#FA8072]" size={32} /></div></div>;

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => sessionStorage.getItem('isAuth') === 'true');
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date>(() => new Date());
  const [showLock, setShowLock] = useState<{ target: string } | null>(null);
  const [lockPass, setLockPass] = useState('');
  const [lockError, setLockError] = useState(false);

  // Core Data States
  const [sales, setSales] = useState<SaleItem[]>(() => JSON.parse(localStorage.getItem('dailySales') || '[]'));
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'));
  const [history, setHistory] = useState<ArchivedDay[]>(() => JSON.parse(localStorage.getItem('salesHistory') || '[]'));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('products') || '[]'));
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('customers') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('suppliers') || '[]'));

  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [modals, setModals] = useState({ products: false, customers: false, history: false, data: false, expenses: false, analytics: false });

  // Persistence logic - Sync state to localStorage immediately
  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
    localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
    localStorage.setItem('salesHistory', JSON.stringify(history));
    localStorage.setItem('products', JSON.stringify(products));
    localStorage.setItem('customers', JSON.stringify(customers));
    localStorage.setItem('suppliers', JSON.stringify(suppliers));
    setLastSyncTime(new Date());
  }, [sales, purchaseInvoices, history, products, customers, suppliers]);

  const handleOpenProtected = (target: string) => setShowLock({ target });

  const verifyLock = () => {
    if (lockPass === '1997') {
      if (showLock?.target === 'full_reset') {
          localStorage.clear();
          window.location.reload();
      } else if (showLock) {
          setModals(m => ({ ...m, [showLock.target]: true }));
      }
      setShowLock(null);
      setLockPass('');
      setLockError(false);
    } else {
      setLockError(true);
    }
  };

  const completeOrder = useCallback((items: any[], name?: string, id?: string, type: SaleType = 'retail') => {
      const orderId = Date.now().toString();
      const now = new Date();
      const time = now.toLocaleTimeString('ar-SY', { hour: '2-digit', minute: '2-digit' });
      const nextNum = sales.length > 0 ? Math.max(...sales.map(s => s.customerNumber || 0)) + 1 : 1;

      const finalItems: SaleItem[] = items.map(i => ({ 
        ...i, 
        id: Math.random().toString(36).substring(2, 11), 
        orderId, 
        customerNumber: nextNum, 
        customerName: name || '', 
        customerId: id || '', 
        saleType: type, 
        time 
      }));

      // In the new system, sales are synced immediately to the main sales list
      setSales(prev => [...prev, ...finalItems]);
  }, [sales]);

  const handleExportData = () => {
    const backup = {
      dailySales: sales,
      dailyPurchaseInvoices: purchaseInvoices,
      salesHistory: history,
      products: products,
      customers: customers,
      suppliers: suppliers,
      exportDate: new Date().toISOString(),
      version: "2.5"
    };
    const blob = new Blob([JSON.stringify(backup, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `cookies-backup-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportData = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = JSON.parse(e.target?.result as string);
        if (data.dailySales) setSales(data.dailySales);
        if (data.dailyPurchaseInvoices) setPurchaseInvoices(data.dailyPurchaseInvoices);
        if (data.salesHistory) setHistory(data.salesHistory);
        if (data.products) setProducts(data.products);
        if (data.customers) setCustomers(data.customers);
        if (data.suppliers) setSuppliers(data.suppliers);

        alert('تمت استعادة كافة البيانات بنجاح.');
      } catch (err) {
        alert('خطأ في قراءة ملف النسخة الاحتياطية. يرجى التأكد من صحة الملف.');
      }
    };
    reader.readAsText(file);
  };

  if (!isAuthenticated) return <Login onLogin={() => { sessionStorage.setItem('isAuth', 'true'); setIsAuthenticated(true); }} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => handleOpenProtected('history')} 
        onOpenDataManagement={() => handleOpenProtected('data')} 
        onOpenExpenses={() => handleOpenProtected('expenses')}
        onOpenAnalytics={() => handleOpenProtected('analytics')}
        isOnline={navigator.onLine} 
        lastSyncTime={lastSyncTime} 
        onManualSync={() => {
            setIsSyncing(true);
            setTimeout(() => setIsSyncing(false), 800);
        }} 
        onQuickBackup={handleExportData} 
        isSyncing={isSyncing}
      />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />

        <POSInterface 
            onCompleteOrder={completeOrder} 
            products={products} 
            customers={customers} 
            onOpenProductManager={() => setModals(m => ({...m, products: true}))} 
            onOpenCustomerManager={() => setModals(m => ({...m, customers: true}))} 
        />

        <div className="mt-8">
            <SalesTable 
                items={sales} 
                onDeleteItem={id => setSales(s => s.filter(i => i.id !== id))} 
                onDeleteOrder={oid => setSales(s => s.filter(i => i.orderId !== oid))} 
                onPreviewInvoice={setInvoiceItems}
                onUpdateItemPrice={(id, p) => setSales(s => s.map(i => i.id === id ? {...i, price: p} : i))}
            />
        </div>
      </main>

      <footer className="mt-12 py-8 border-t border-gray-800/50 text-center no-print">
         <button onClick={() => handleOpenProtected('full_reset')} className="text-gray-700 text-[10px] font-bold tracking-widest uppercase">نظام مبيعات كوكيز v2.5 • 2026</button>
      </footer>

      <Suspense fallback={<ModalLoader />}>
        {modals.analytics && <AnalyticsModal history={history} currentSales={sales} currentPurchases={purchaseInvoices} onClose={() => setModals(m => ({ ...m, analytics: false }))} />}
        {modals.expenses && (
            <ExpensesModal 
                isOpen={modals.expenses} 
                onClose={() => setModals(m => ({...m, expenses: false}))} 
                currentPurchases={purchaseInvoices} 
                archivedHistory={history} 
                onAddInvoice={v => setPurchaseInvoices(p => [...p, v])} 
                onDeleteInvoice={id => setPurchaseInvoices(p => p.filter(v => v.id !== id))} 
                suppliers={suppliers} 
                onAddSupplier={s => setSuppliers(p => [...p, {...s, id: Date.now().toString()}])} 
                onDeleteSupplier={id => setSuppliers(p => p.filter(s => s.id !== id))} 
            />
        )}
        {modals.history && (
            <HistoryModal 
                history={history} 
                currentSales={sales} 
                onClose={() => setModals(m => ({...m, history: false}))} 
                onClearHistory={() => setHistory([])} 
                onPreviewInvoice={setInvoiceItems} 
                onUpdateOrder={(d, o, i) => setHistory(h => h.map(day => day.date === d ? {...day, items: day.items.map(item => item.orderId === o ? i.find(x => x.id === item.id) || item : item)} : day))} 
            />
        )}
        {modals.products && <ProductManager isOpen={modals.products} onClose={() => setModals(m => ({...m, products: false}))} products={products} onAddProduct={p => setProducts(s => [...s, {...p, id: Date.now().toString()}])} onUpdateProduct={(id, u) => setProducts(s => s.map(p => p.id === id ? {...p, ...u} : p))} onDeleteProduct={id => setProducts(s => s.filter(p => p.id !== id))} />}
        {modals.customers && <CustomerManager isOpen={modals.customers} onClose={() => setModals(m => ({...m, customers: false}))} customers={customers} onAddCustomer={c => setCustomers(s => [...s, {...c, id: Date.now().toString()}])} onDeleteCustomer={id => setCustomers(s => s.filter(c => c.id !== id))} />}
        {modals.data && <DataManagementModal onClose={() => setModals(m => ({...m, data: false}))} onExport={handleExportData} onImport={handleImportData} />}
        {invoiceItems && <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />}
      </Suspense>

      {showLock && (
        <div className="fixed inset-0 bg-black/90 z-[200] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-gray-800 border border-gray-700 p-6 rounded-3xl w-full max-w-xs shadow-2xl animate-fade-up relative">
            <button onClick={() => { setShowLock(null); setLockPass(''); setLockError(false); }} className="absolute top-4 left-4 text-gray-500 hover:text-white transition-colors"><X size={20} /></button>
            <div className="text-center mb-6">
                <div className="w-12 h-12 bg-[#FA8072]/20 rounded-full flex items-center justify-center mx-auto mb-3"><Loader2 className="text-[#FA8072] animate-pulse" size={24} /></div>
                <h3 className="text-white font-black text-lg">تأكيد الإجراء</h3>
                <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest mt-1">يرجى إدخال رمز التحقق (1997)</p>
            </div>
            <input type="password" value={lockPass} onChange={e => setLockPass(e.target.value)} placeholder="رمز الدخول" className={`w-full bg-gray-900 border ${lockError ? 'border-red-500' : 'border-gray-700'} text-white p-4 rounded-2xl mb-4 text-center outline-none focus:border-[#FA8072] text-xl tracking-widest`} autoFocus onKeyDown={e => e.key === 'Enter' && verifyLock()} />
            {lockError && <p className="text-red-500 text-[10px] text-center mb-4 font-bold animate-pulse">رمز الدخول غير صحيح!</p>}
            <button onClick={verifyLock} className="w-full bg-gradient-to-r from-[#FA8072] to-orange-600 text-white py-4 rounded-2xl font-black text-sm shadow-lg shadow-orange-900/20 active:scale-95 transition-all">تأكيد الإجراء</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ShoppingCart, Settings, Edit3, Trash2, CheckCircle, Plus, Minus, UserPlus, X, Check } from 'lucide-react';
import { Product, UnitType, SaleType, Customer } from '../types';

interface POSInterfaceProps {
  onCompleteOrder: (items: any[], customerName?: string, customerId?: string, saleType?: SaleType) => void;
  products: Product[];
  customers: Customer[];
  onOpenProductManager: () => void;
  onOpenCustomerManager: () => void;
}

export const POSInterface: React.FC<POSInterfaceProps> = ({ 
    onCompleteOrder, products, customers, onOpenProductManager, onOpenCustomerManager 
}) => {
  const [cart, setCart] = useState<any[]>([]);
  const [saleType, setSaleType] = useState<SaleType>('retail');
  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [manualCustomerName, setManualCustomerName] = useState(''); 
  const [showCustomInput, setShowCustomInput] = useState(false);
  const [customForm, setCustomForm] = useState({ name: '', price: '', cost: '', unit: 'piece' as UnitType });

  const [editingPriceId, setEditingPriceId] = useState<string | null>(null);
  const [tempPrice, setTempPrice] = useState<string>('');
  const [editingQtyId, setEditingQtyId] = useState<string | null>(null);
  const [tempQty, setTempQty] = useState<string>('');

  useEffect(() => {
    setCart(prev => prev.map(item => {
      const productDef = products.find(p => p.name === item.name && p.unitType === item.unitType);
      if (productDef) {
        return {
          ...item,
          price: saleType === 'wholesale' ? (productDef.wholesalePrice || productDef.price) : productDef.price
        };
      }
      return item;
    }));
  }, [saleType, products]);

  const addToCart = (p: Product) => {
    setCart(prev => {
      const idx = prev.findIndex(i => i.name === p.name && i.unitType === p.unitType);
      const activePrice = saleType === 'wholesale' ? (p.wholesalePrice || p.price) : p.price;

      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], quantity: next[idx].quantity + 1, price: activePrice };
        return next;
      }
      return [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: p.name, 
        price: activePrice, 
        costPrice: p.costPrice || 0, 
        quantity: 1, 
        unitType: p.unitType 
      }];
    });
  };

  const addCustomToCart = () => {
    if (!customForm.name || !customForm.price) return;
    setCart(prev => [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: customForm.name, 
        price: parseFloat(customForm.price) || 0, 
        costPrice: parseFloat(customForm.cost) || 0,
        quantity: 1,
        unitType: customForm.unit
    }]);
    setCustomForm({ name: '', price: '', cost: '', unit: 'piece' });
    setShowCustomInput(false);
  };

  const updateQty = (id: string, delta: number) => {
    setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: Math.max(0.1, parseFloat((i.quantity + delta * (i.unitType === 'kg' ? 0.1 : 1)).toFixed(2))) } : i));
  };

  const handleStartEditPrice = (item: any) => {
    setEditingPriceId(item.tempId);
    setTempPrice(item.price.toString());
  };

  const handleSavePrice = (tempId: string) => {
    const newPrice = parseFloat(tempPrice);
    if (!isNaN(newPrice) && newPrice >= 0) {
      setCart(prev => prev.map(i => i.tempId === tempId ? { ...i, price: newPrice } : i));
    }
    setEditingPriceId(null);
  };

  const handleStartEditQty = (item: any) => {
    setEditingQtyId(item.tempId);
    setTempQty(item.quantity.toString());
  };

  const handleSaveQty = (tempId: string) => {
    const newQty = parseFloat(tempQty);
    if (!isNaN(newQty) && newQty > 0) {
      setCart(prev => prev.map(i => i.tempId === tempId ? { ...i, quantity: newQty } : i));
    }
    setEditingQtyId(null);
  };

  const isCheckoutDisabled = cart.length === 0 || (saleType === 'wholesale' && !selectedCustomerId);

  const handleCheckout = () => {
    if (isCheckoutDisabled) return;
    const items = cart.map(({ name, price, costPrice, quantity, unitType }) => ({ name, price, costPrice, quantity, unitType }));
    const name = saleType === 'wholesale' ? customers.find(c => c.id === selectedCustomerId)?.name : manualCustomerName;
    onCompleteOrder(items, name, selectedCustomerId || undefined, saleType);
    setCart([]); setManualCustomerName(''); setSelectedCustomerId(''); setSaleType('retail');
  };

  const total = cart.reduce((s, i) => s + (i.price * i.quantity), 0);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">
      <div className="lg:col-span-2 space-y-4">
        <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
             <h2 className="font-bold text-white flex items-center gap-2"><ShoppingCart size={20} className="text-[#FA8072]" /> قائمة المنتجات</h2>
             <button onClick={onOpenProductManager} className="text-xs bg-gray-700 hover:bg-gray-600 text-gray-300 px-3 py-1.5 rounded-lg transition-colors">تعديل الأصناف</button>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
            {products.map(p => (
                <button key={p.id} onClick={() => addToCart(p)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-gray-700 hover:bg-gray-700 hover:border-[#FA8072] text-white rounded-2xl transition-all shadow-sm active:scale-95 h-32 relative group">
                    <div className={`absolute top-2 right-2 px-1.5 py-0.5 rounded text-[10px] font-bold ${p.unitType === 'kg' ? 'bg-yellow-400 text-black' : 'bg-blue-300 text-black'}`}>{p.unitType === 'kg' ? 'كغ' : 'قطعة'}</div>
                    <span className="font-bold text-sm text-center mb-1 group-hover:text-[#FA8072]">{p.name}</span>
                    <span className="text-xs text-gray-400 bg-gray-900/50 px-2 py-1 rounded-md">
                      {(saleType === 'wholesale' ? (p.wholesalePrice || p.price) : p.price).toLocaleString()} ل.س
                    </span>
                </button>
            ))}
            <button onClick={() => setShowCustomInput(true)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-dashed border-gray-600 hover:bg-gray-700 text-gray-400 rounded-2xl h-32"><Plus size={24} className="mb-2" /><span className="text-xs">مادة حرة</span></button>
        </div>

        {showCustomInput && (
            <div className="bg-gray-800 p-4 rounded-xl border border-[#FA8072] animate-fade-up relative">
                <button onClick={() => setShowCustomInput(false)} className="absolute left-3 top-3 text-gray-500 hover:text-white"><X size={18} /></button>
                <h4 className="text-sm font-bold text-white mb-3">إضافة مادة حرة</h4>
                <div className="grid grid-cols-1 md:grid-cols-12 gap-2">
                    <input type="text" value={customForm.name} onChange={e => setCustomForm({...customForm, name: e.target.value})} placeholder="المادة" className="md:col-span-4 bg-gray-900 border border-gray-600 text-white px-3 py-2 rounded-lg text-sm" autoFocus />
                    <input type="number" value={customForm.cost} onChange={e => setCustomForm({...customForm, cost: e.target.value})} placeholder="التكلفة" className="md:col-span-2 bg-gray-900 border border-gray-600 text-red-400 px-3 py-2 rounded-lg text-sm" />
                    <input type="number" value={customForm.price} onChange={e => setCustomForm({...customForm, price: e.target.value})} placeholder="البيع" className="md:col-span-2 bg-gray-900 border border-gray-600 text-green-400 px-3 py-2 rounded-lg text-sm" />
                    <select value={customForm.unit} onChange={e => setCustomForm({...customForm, unit: e.target.value as UnitType})} className="md:col-span-2 bg-gray-900 border border-gray-600 text-white px-2 py-2 rounded-lg text-sm"><option value="piece">قطعة</option><option value="kg">كغ</option></select>
                    <button onClick={addCustomToCart} className="md:col-span-2 bg-[#FA8072] text-white rounded-lg font-bold">إضافة</button>
                </div>
            </div>
        )}
      </div>

      <div className="lg:col-span-1">
        <div className="bg-gray-800 rounded-2xl border border-gray-700 shadow-xl overflow-hidden flex flex-col h-full min-h-[500px]">
            <div className="bg-gray-900/80 p-4 border-b border-gray-700 space-y-3">
                <div className="flex justify-between items-center">
                    <h3 className="font-bold text-white flex items-center gap-2"><ShoppingCart size={20} className="text-[#FA8072]" /> سلة المبيعات</h3>
                    {cart.length > 0 && <button onClick={() => setCart([])} className="text-xs text-red-400 underline">إلغاء السلة</button>}
                </div>
                <div className="grid grid-cols-2 bg-gray-700 p-1 rounded-lg">
                    <button onClick={() => setSaleType('retail')} className={`py-1.5 text-xs font-bold rounded-md transition-colors ${saleType === 'retail' ? 'bg-white text-black' : 'text-gray-400'}`}>مفرق</button>
                    <button onClick={() => setSaleType('wholesale')} className={`py-1.5 text-xs font-bold rounded-md transition-colors ${saleType === 'wholesale' ? 'bg-[#FA8072] text-white' : 'text-gray-400'}`}>جملة</button>
                </div>
                {saleType === 'retail' ? (
                     <input type="text" value={manualCustomerName} onChange={e => setManualCustomerName(e.target.value)} placeholder="الاسم (اختياري)..." className="w-full bg-gray-800 border border-gray-600 text-white text-sm rounded-lg px-3 py-2 outline-none focus:border-[#FA8072]" />
                ) : (
                    <div className="flex gap-2">
                         <select value={selectedCustomerId} onChange={e => setSelectedCustomerId(e.target.value)} className={`w-full bg-gray-800 border text-white text-sm rounded-lg px-3 py-2 outline-none transition-all ${!selectedCustomerId && cart.length > 0 ? 'border-orange-500 animate-pulse' : 'border-gray-600 focus:border-[#FA8072]'}`}>
                            <option value="">اختر العميل...</option>
                            {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                         </select>
                        <button onClick={onOpenCustomerManager} className="bg-blue-600 text-white px-3 rounded-lg hover:bg-blue-500 transition-colors"><UserPlus size={18} /></button>
                    </div>
                )}
            </div>

            <div className="flex-grow p-3 overflow-y-auto space-y-2">
                {!cart.length ? (
                    <div className="h-full flex flex-col items-center justify-center text-gray-500 opacity-50 py-10"><ShoppingCart size={48} className="mb-2" /><p>سلة المبيعات فارغة</p></div>
                ) : (
                    cart.map(i => (
                        <div key={i.tempId} className="bg-gray-700/50 p-3 rounded-xl flex flex-col gap-2 border border-gray-700 relative group/item hover:border-gray-500 transition-colors">
                            <div className="flex justify-between items-start">
                                <div className="flex flex-col flex-1">
                                    <span className="text-white font-bold text-sm">{i.name}</span>
                                    {editingPriceId === i.tempId ? (
                                        <div className="flex items-center gap-1 mt-1">
                                            <input type="number" value={tempPrice} onChange={e => setTempPrice(e.target.value)} onBlur={() => handleSavePrice(i.tempId)} onKeyDown={e => e.key === 'Enter' && handleSavePrice(i.tempId)} className="w-20 bg-gray-900 border border-[#FA8072] text-white text-xs px-1 rounded" autoFocus />
                                        </div>
                                    ) : (
                                        <div className="mt-1 flex items-center gap-1.5 cursor-pointer group/price" onClick={() => handleStartEditPrice(i)}>
                                            <span className="text-[10px] text-gray-400">السعر: <span className="text-gray-300 font-bold">{i.price.toLocaleString()}</span></span>
                                            <Edit3 size={11} className="text-[#FA8072] opacity-30 group-hover/price:opacity-100" />
                                        </div>
                                    )}
                                </div>
                                <button onClick={() => setCart(p => p.filter(it => it.tempId !== i.tempId))} className="text-gray-500 hover:text-red-500 transition-colors p-1"><Trash2 size={16} /></button>
                            </div>
                            <div className="flex items-center justify-between mt-1">
                                <div className="flex items-center gap-1 bg-gray-900 rounded-lg px-2 py-1 border border-gray-700">
                                    <button onClick={() => updateQty(i.tempId, -1)} className="text-gray-400 hover:text-white transition-colors p-0.5"><Minus size={12} /></button>
                                    <span onClick={() => handleStartEditQty(i)} className="text-white text-sm font-bold min-w-[35px] text-center cursor-pointer">{i.quantity}</span>
                                    <button onClick={() => updateQty(i.tempId, 1)} className="text-gray-400 hover:text-white transition-colors p-0.5"><Plus size={12} /></button>
                                </div>
                                <span className="text-[#FA8072] font-bold text-base">{(i.price * i.quantity).toLocaleString()} <span className="text-[10px] opacity-70">ل.س</span></span>
                            </div>
                        </div>
                    ))
                )}
            </div>

            <div className="p-4 bg-gray-900 border-t border-gray-700 shrink-0">
                <div className="flex justify-between items-center mb-4">
                    <span className="text-gray-400 font-bold">المجموع:</span>
                    <span className="text-2xl font-bold text-white tracking-tight">{total.toLocaleString()} <span className="text-xs text-gray-500 font-normal">ل.س</span></span>
                </div>
                <button 
                  onClick={handleCheckout} 
                  disabled={isCheckoutDisabled} 
                  className={`w-full py-4 rounded-xl font-bold text-lg flex items-center justify-center gap-2 transition-all active:scale-[0.98] ${!isCheckoutDisabled ? 'bg-green-600 text-white hover:bg-green-500 shadow-lg' : 'bg-gray-700 text-gray-500 cursor-not-allowed'}`}
                >
                  <CheckCircle size={22} /> تأكيد الطلب
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { X, ChevronDown, ChevronUp, ArrowRight, Folder, CalendarDays, ShoppingBag, Zap, Store, User } from 'lucide-react';
import { ArchivedDay, SaleItem } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  currentSales?: SaleItem[];
  onClose: () => void;
  onClearHistory: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateOrder: (date: string, orderId: string, updatedItems: SaleItem[]) => void;
}

type NavStep = 'years' | 'months' | 'days';

export const HistoryModal: React.FC<HistoryModalProps> = ({ 
  history, currentSales = [], onClose, onClearHistory, onPreviewInvoice, onUpdateOrder 
}) => {
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);

  const fullHistory = useMemo(() => {
      const merged = [...history];
      if (currentSales.length > 0) {
          const today = new Date();
          const todayStr = today.toLocaleDateString('ar-SY');
          const existingTodayIdx = merged.findIndex(d => d.date.includes(todayStr));

          const todayEntry: ArchivedDay = {
              id: 'today-active',
              date: `${todayStr} (مبيعات حية)`,
              timestamp: Date.now(),
              totalRevenue: currentSales.reduce((s, i) => s + (i.price * i.quantity), 0),
              totalExpenses: 0,
              totalItems: currentSales.length,
              items: currentSales,
              purchaseInvoices: []
          };

          if (existingTodayIdx > -1) merged[existingTodayIdx] = todayEntry;
          else merged.push(todayEntry);
      }
      return merged;
  }, [history, currentSales]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(fullHistory.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [fullHistory]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      fullHistory
        .filter(day => new Date(day.timestamp).getFullYear().toString() === selectedYear)
        .map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [fullHistory, selectedYear]);

  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return fullHistory.filter(day => {
      const d = new Date(day.timestamp);
      return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    }).sort((a,b) => b.timestamp - a.timestamp);
  }, [fullHistory, selectedYear, selectedMonth]);

  const getMonthName = (monthIndex: number) => {
    return new Date(2000, monthIndex).toLocaleString('ar-SY', { month: 'long' });
  };

  const renderContent = () => {
    if (step === 'years') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {years.length > 0 ? years.map(year => (
                <button key={year} onClick={() => { setSelectedYear(year); setStep('months'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <Folder size={48} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-black text-white">{year}</span>
                </button>
            )) : (
              <div className="col-span-full py-20 text-center flex flex-col items-center gap-4">
                  <div className="bg-gray-700/30 p-6 rounded-full"><Zap size={48} className="text-gray-600" /></div>
                  <p className="text-gray-500 font-bold">لا توجد عمليات بيع مؤرشفة بعد</p>
              </div>
            )}
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => { setSelectedMonth(monthIdx); setStep('days'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <CalendarDays size={48} className="text-blue-400 group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-4 animate-fade-up h-full">
            <div className="flex-1 overflow-y-auto space-y-3 pr-1 custom-scrollbar">
                {currentDaysData.map(day => {
                    const isToday = day.id === 'today-active';
                    return (
                        <div key={day.id} className={`rounded-xl border overflow-hidden shadow-sm transition-all ${isToday ? 'border-orange-500/50 bg-orange-500/5' : 'border-gray-700 bg-gray-800'}`}>
                            <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className={`p-4 flex justify-between items-center cursor-pointer ${isToday ? 'bg-orange-500/10' : 'bg-gray-900/50 hover:bg-gray-900'}`}>
                                <div className="flex items-center gap-3">
                                    <div className="text-gray-500">{expandedDayId === day.id ? <ChevronUp size={18} /> : <ChevronDown size={18} />}</div>
                                    <span className={`font-bold ${isToday ? 'text-orange-400' : 'text-white'}`}>{day.date}</span>
                                </div>
                                <div className="flex items-center gap-3">
                                    <span className="font-black text-lg text-green-400">{day.totalRevenue.toLocaleString()} <small className="text-[10px] text-gray-500 font-normal">ل.س</small></span>
                                </div>
                            </div>

                            {expandedDayId === day.id && (
                                <div className="p-4 bg-gray-900/30 border-t border-gray-700 animate-fade-up space-y-2">
                                    {day.items.map((item, idx) => (
                                        <div key={idx} className="flex justify-between items-center text-xs p-3 bg-gray-800 rounded-lg border border-gray-700/50">
                                            <div className="flex items-center gap-3">
                                                {item.saleType === 'wholesale' ? <Store size={14} className="text-orange-400" /> : <User size={14} className="text-blue-400" />}
                                                <div className="flex flex-col">
                                                    <span className="text-white font-medium">{item.name}</span>
                                                    <span className="text-[9px] text-gray-500">{item.saleType === 'wholesale' ? 'جملة' : 'مفرق'} • الكمية: {item.quantity}</span>
                                                </div>
                                            </div>
                                            <span className="text-white font-bold">{(item.price * item.quantity).toLocaleString()}</span>
                                        </div>
                                    ))}
                                    <button onClick={() => onPreviewInvoice(day.items)} className="w-full mt-2 py-2 bg-gray-700 hover:bg-[#FA8072] text-white rounded-lg text-xs font-bold transition-all">معاينة الفواتير</button>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
  };

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-md z-50 flex items-center justify-center p-4">
