import React, { useMemo, useState } from 'react';
import { X, BarChart3, TrendingUp } from 'lucide-react';
import { ArchivedDay, SaleItem, PurchaseInvoice } from '../types';

interface AnalyticsModalProps {
  history: ArchivedDay[];
  currentSales: SaleItem[];
  currentPurchases: PurchaseInvoice[];
  onClose: () => void;
}

export const AnalyticsModal: React.FC<AnalyticsModalProps> = ({ history, currentSales, currentPurchases, onClose }) => {
  const [daysCount, setDaysCount] = useState<7 | 15 | 30>(7);

  const processedData = useMemo(() => {
    // Current day stats
    const todayRevenue = currentSales.reduce((s, i) => s + (i.price * i.quantity), 0);
    const todayPurchases = currentPurchases.reduce((s, i) => s + i.totalAmount, 0);
    const todayProfit = currentSales.reduce((s, i) => s + ((i.price - i.costPrice) * i.quantity), 0);

    const combined = [
      ...history.map(day => ({
        date: day.date,
        revenue: day.totalRevenue,
        purchases: (day.purchaseInvoices || []).reduce((s, i) => s + i.totalAmount, 0),
        profit: day.items.reduce((s, i) => s + ((i.price - (i.costPrice || 0)) * i.quantity), 0),
        timestamp: day.timestamp
      })),
      {
        date: 'اليوم',
        revenue: todayRevenue,
        purchases: todayPurchases,
        profit: todayProfit,
        timestamp: Date.now()
      }
    ].sort((a, b) => a.timestamp - b.timestamp);

    return combined.slice(-daysCount);
  }, [history, currentSales, currentPurchases, daysCount]);

  const stats = useMemo(() => {
    return {
      totalRevenue: processedData.reduce((s, d) => s + d.revenue, 0),
      totalPurchases: processedData.reduce((s, d) => s + d.purchases, 0),
      totalProfit: processedData.reduce((s, d) => s + d.profit, 0)
    };
  }, [processedData]);

  // Chart configuration
  const chartHeight = 300;
  const chartWidth = 900;
  const padding = 60;
  const maxVal = Math.max(...processedData.flatMap(d => [d.revenue, d.profit, 10000]));
  const getX = (index: number) => padding + (index * (chartWidth - 2 * padding) / (processedData.length - 1 || 1));
  const getY = (value: number) => chartHeight - padding - ((value / (maxVal || 1)) * (chartHeight - 2 * padding));

  return (
    <div className="fixed inset-0 bg-black/95 backdrop-blur-md z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-[3rem] w-full max-w-5xl shadow-2xl border border-gray-700 animate-fade-up overflow-hidden flex flex-col max-h-[95vh]">
        <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-900/50">
          <div className="flex items-center gap-4">
             <div className="bg-[#FA8072]/20 p-3 rounded-2xl"><BarChart3 className="text-[#FA8072]" size={28} /></div>
             <h3 className="font-black text-2xl text-white">التحليلات المالية المباشرة</h3>
          </div>
          <button onClick={onClose} className="p-3 hover:bg-gray-700 rounded-2xl transition-all text-gray-400"><X size={24} /></button>
        </div>

        <div className="p-8 overflow-y-auto flex-1 space-y-10">
          <div className="flex justify-center">
             <div className="flex gap-2 bg-gray-900/80 p-1.5 rounded-2xl border border-gray-700">
                {[7, 15, 30].map(n => (
                   <button key={n} onClick={() => setDaysCount(n as any)} className={`px-6 py-2 rounded-xl text-xs font-black transition-all ${daysCount === n ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}>آخر {n} يوم</button>
                ))}
             </div>
          </div>

          <div className="bg-gray-950/50 rounded-[2.5rem] border border-gray-700 p-8 shadow-inner relative">
             <div className="absolute top-4 right-10 flex gap-6 text-[10px] font-black uppercase">
                 <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-blue-500"></div><span className="text-gray-400">المبيعات</span></div>
                 <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-green-500"></div><span className="text-gray-400">صافي الربح الفعلي</span></div>
             </div>

             <div className="overflow-x-auto pb-6 custom-scrollbar">
                <svg viewBox={`0 0 ${chartWidth} ${chartHeight}`} className="w-full h-auto min-w-[800px]">
                    {[0, 0.25, 0.5, 0.75, 1].map((v, i) => (
                        <line key={i} x1={padding} y1={getY(maxVal * v)} x2={chartWidth - padding} y2={getY(maxVal * v)} stroke="#374151" strokeWidth="1" strokeDasharray="5,5" />
                    ))}

                    <polyline points={processedData.map((d, i) => `${getX(i)},${getY(d.revenue)}`).join(' ')} fill="none" stroke="#3B82F6" strokeWidth="5" strokeLinecap="round" strokeLinejoin="round" />
                    <polyline points={processedData.map((d, i) => `${getX(i)},${getY(d.profit)}`).join(' ')} fill="none" stroke="#10B981" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" />

                    {processedData.map((d, i) => (
                        <g key={i}>
                            <circle cx={getX(i)} cy={getY(d.revenue)} r="7" fill="#1F2937" stroke="#3B82F6" strokeWidth="3" />
                            <circle cx={getX(i)} cy={getY(d.profit)} r="6" fill="#1F2937" stroke="#10B981" strokeWidth="2" />
                            <text x={getX(i)} y={chartHeight - 20} textAnchor="middle" className="text-[12px] fill-gray-500 font-bold">{d.date.split('/')[0]}</text>
                        </g>
                    ))}
                </svg>
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
             <div className="bg-blue-600/10 p-6 rounded-[2rem] border border-blue-500/20 text-center">
                <span className="text-[10px] font-black text-blue-400 uppercase tracking-widest block mb-2">إجمالي المبيعات</span>
                <span className="text-3xl font-black text-white">{stats.totalRevenue.toLocaleString()}</span>
             </div>
             <div className="bg-red-600/10 p-6 rounded-[2rem] border border-red-500/20 text-center">
                <span className="text-[10px] font-black text-red-400 uppercase tracking-widest block mb-2">إجمالي المشتريات</span>
                <span className="text-3xl font-black text-white">{stats.totalPurchases.toLocaleString()}</span>
             </div>
             <div className="bg-green-600/10 p-6 rounded-[2rem] border border-green-500/20 text-center relative overflow-hidden group">
                <TrendingUp size={60} className="absolute -bottom-4 -right-4 text-green-500/10" />
                <span className="text-[10px] font-black text-green-400 uppercase tracking-widest block mb-2">صافي الربح الفعلي</span>
                <span className="text-3xl font-black text-white">{stats.totalProfit.toLocaleString()}</span>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Trash2, Search, User, Download, Store, Edit3 } from 'lucide-react';
import { SaleItem } from '../types';

interface SalesTableProps {
  items: SaleItem[];
  onDeleteItem: (id: string) => void;
  onDeleteOrder?: (orderId: string) => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateItemPrice?: (itemId: string, newPrice: number) => void; 
}

export const SalesTable: React.FC<SalesTableProps> = ({ items, onDeleteItem, onDeleteOrder, onPreviewInvoice, onUpdateItemPrice }) => {
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [editingPriceId, setEditingPriceId] = useState<string | null>(null);
  const [tempPrice, setTempPrice] = useState<string>('');

  const groupedOrders = useMemo(() => {
    const groups: { [key: string]: SaleItem[] } = {};
    items.forEach(item => {
        const key = item.orderId;
        if (!groups[key]) groups[key] = [];
        groups[key].push(item);
    });
    return Object.values(groups).sort((a, b) => b[0].orderId.localeCompare(a[0].orderId));
  }, [items]);

  const filteredOrders = useMemo(() => {
      if (!searchTerm) return groupedOrders;
      const term = searchTerm.toLowerCase();
      return groupedOrders.filter(g => (g[0].customerName?.toLowerCase() || '').includes(term));
  }, [groupedOrders, searchTerm]);

  const savePrice = (itemId: string) => {
    const price = parseFloat(tempPrice);
    if (!isNaN(price) && onUpdateItemPrice) onUpdateItemPrice(itemId, price);
    setEditingPriceId(null);
  };

  if (items.length === 0) return <div className="p-20 text-center text-gray-500 font-bold bg-gray-800 rounded-3xl border border-gray-700">لا توجد مبيعات مسجلة لهذا اليوم.</div>;

  return (
    <div className="space-y-5">
        <div className="relative max-w-md mx-auto no-print">
            <Search className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
            <input type="text" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="بحث باسم العميل..." className="w-full bg-gray-800 border border-gray-700 text-white rounded-2xl pr-12 pl-4 py-3 outline-none focus:border-[#FA8072] transition-all" />
        </div>

        <div className="space-y-4">
            {filteredOrders.map(group => {
                const total = group.reduce((s, i) => s + (i.price * i.quantity), 0);
                const first = group[0];
                return (
                    <div key={first.orderId} className="bg-gray-800 rounded-2xl border border-gray-700 overflow-hidden shadow-lg animate-fade-up">
                        <div className="p-4 bg-gray-900/50 flex justify-between items-center border-b border-gray-700">
                            <div className="flex items-center gap-3">
                                {first.saleType === 'wholesale' ? <Store size={16} className="text-orange-400" /> : <User size={16} className="text-blue-400" />}
                                <span className="font-bold text-white">{first.customerName || 'زبون عام'}</span>
                                <span className="text-[10px] text-gray-500 font-mono">{first.time}</span>
                            </div>
                            <div className="flex items-center gap-4">
                                <span className="font-black text-[#FA8072]">{total.toLocaleString()} <small className="text-[9px] text-gray-600 font-normal">ل.س</small></span>
                                <button onClick={() => onPreviewInvoice(group)} className="text-gray-400 hover:text-white transition-colors"><Download size={18} /></button>
                                <button onClick={() => onDeleteOrder && onDeleteOrder(first.orderId)} className="text-gray-600 hover:text-red-400 transition-colors"><Trash2 size={18} /></button>
                            </div>
                        </div>
                        <table className="w-full text-right text-xs">
                            <tbody className="divide-y divide-gray-700/50">
                                {group.map(item => (
                                    <tr key={item.id} className="hover:bg-gray-700/20">
                                        <td className="p-3 text-white font-medium">{item.name}</td>
                                        <td className="p-3 text-gray-400">الكمية: {item.quantity}</td>
                                        <td className="p-3">
                                            {editingPriceId === item.id ? (
                                                <input type="number" value={tempPrice} onChange={e => setTempPrice(e.target.value)} onBlur={() => savePrice(item.id)} className="w-20 bg-gray-950 border border-[#FA8072] text-white rounded px-2" autoFocus />
                                            ) : (
                                                <div className="flex items-center gap-2 cursor-pointer group/item" onClick={() => { setEditingPriceId(item.id); setTempPrice(item.price.toString()); }}>
                                                    <span className="text-gray-300">{item.price.toLocaleString()}</span>
                                                    <Edit3 size={12} className="text-[#FA8072] opacity-0 group-hover/item:opacity-100 transition-opacity" />
                                                </div>
                                            )}
                                        </td>
                                        <td className="p-3 text-white font-black">{(item.price * item.quantity).toLocaleString()}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                );
            })}
        </div>
    </div>
  );
};

import React, { useState } from 'react';
import { X, Copy, Check, Download, FileSpreadsheet } from 'lucide-react';
import { SaleItem } from '../types';
import { utils, writeFile } from 'xlsx';

interface InvoiceModalProps {
  items: SaleItem[];
  onClose: () => void;
}

export const InvoiceModal: React.FC<InvoiceModalProps> = ({ items, onClose }) => {
  const [copied, setCopied] = useState(false);
  const total = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const date = new Date().toLocaleDateString('ar-SY');

  const handleDownloadExcel = () => {
    const data = items.map(i => ({ "المادة": i.name, "الكمية": i.quantity, "السعر": i.price, "الإجمالي": i.price * i.quantity }));
    data.push({ "المادة": "المجموع الكلي", "الكمية": 0, "السعر": 0, "الإجمالي": total });
    const ws = utils.json_to_sheet(data);
    const wb = utils.book_new();
    utils.book_append_sheet(wb, ws, "Invoice");
    writeFile(wb, `Cookies-Invoice-${Date.now()}.xlsx`);
  };

  const handleCopy = () => {
    const text = `فاتورة مخبز كوكيز\nالتاريخ: ${date}\nالعميل: ${items[0]?.customerName || 'زبون عام'}\nالمجموع: ${total} ل.س`;
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-[2.5rem] w-full max-w-md shadow-2xl border border-gray-700 animate-fade-up overflow-hidden">
        <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-900/50">
          <h3 className="font-black text-xl text-white">تحميل الفاتورة</h3>
          <button onClick={onClose} className="p-2 text-gray-400 hover:text-white transition-colors"><X size={24} /></button>
        </div>

        <div className="p-10 space-y-6">
            <div className="text-center space-y-2">
                <div className="w-16 h-16 bg-blue-500/10 rounded-2xl flex items-center justify-center mx-auto mb-4 text-blue-400 border border-blue-500/20">
                    <Download size={32} />
                </div>
                <h4 className="text-white font-bold text-lg">جاهز للتحميل</h4>
                <p className="text-gray-500 text-sm">سيتم تحميل الفاتورة كملف Excel لطلب: <span className="text-gray-300 font-bold">{items[0]?.customerName || 'زبون عام'}</span></p>
            </div>

            <div className="space-y-3">
                <button 
                  onClick={handleDownloadExcel} 
                  className="w-full bg-green-600 hover:bg-green-500 text-white py-4 rounded-2xl font-black text-sm flex items-center justify-center gap-3 transition-all shadow-xl active:scale-95"
                >
                    <FileSpreadsheet size={20} />
                    تحميل ملف Excel
                </button>
                <button 
                  onClick={handleCopy} 
                  className={`w-full py-4 rounded-2xl font-black text-sm flex items-center justify-center gap-3 transition-all border border-gray-700 ${copied ? 'bg-blue-600 text-white' : 'bg-gray-900/50 text-gray-400 hover:text-white'}`}
                >
                    {copied ? <Check size={20} /> : <Copy size={20} />}
                    {copied ? 'تم النسخ' : 'نسخ نص الفاتورة'}
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

