import React, { useState, useMemo } from 'react';
import { X, ChevronDown, ChevronUp, ArrowRight, Folder, CalendarDays, ShoppingBag, Zap, Store, User, Filter, TrendingUp, PieChart, Info, LogOut } from 'lucide-react';
import { ArchivedDay, SaleItem, SaleType } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  currentSales?: SaleItem[];
  onClose: () => void;
  onClearHistory: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateOrder: (date: string, orderId: string, updatedItems: SaleItem[]) => void;
}

type NavStep = 'years' | 'months' | 'days';
type FilterType = 'all' | SaleType;
type TabMode = 'archive' | 'profit-report';

export const HistoryModal: React.FC<HistoryModalProps> = ({ 
  history, currentSales = [], onClose, onClearHistory, onPreviewInvoice, onUpdateOrder 
}) => {
  const [tab, setTab] = useState<TabMode>('archive');
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);
  const [filterType, setFilterType] = useState<FilterType>('all');

  const fullHistory = useMemo(() => {
      const merged = [...history];
      if (currentSales.length > 0) {
          const today = new Date();
          const todayStr = today.toLocaleDateString('ar-SY');
          const existingTodayIdx = merged.findIndex(d => d.date.includes(todayStr));

          const todayEntry: ArchivedDay = {
              id: 'today-active',
              date: `${todayStr} (مبيعات حية)`,
              timestamp: Date.now(),
              totalRevenue: currentSales.reduce((s, i) => s + (i.price * i.quantity), 0),
              totalExpenses: 0,
              totalItems: currentSales.length,
              items: currentSales,
              purchaseInvoices: []
          };

          if (existingTodayIdx > -1) merged[existingTodayIdx] = todayEntry;
          else merged.push(todayEntry);
      }
      return merged;
  }, [history, currentSales]);

  const profitReport = useMemo(() => {
    const report: Record<string, { today: number, month: number, year: number, total: number }> = {};
    const now = new Date();
    const currentYear = now.getFullYear();
    const currentMonth = now.getMonth();
    const todayStr = now.toLocaleDateString('ar-SY');

    fullHistory.forEach(day => {
        const d = new Date(day.timestamp);
        const isYear = d.getFullYear() === currentYear;
        const isMonth = isYear && d.getMonth() === currentMonth;
        const isToday = day.date.includes(todayStr);

        day.items.forEach(item => {
            const profitPerUnit = item.price - (item.costPrice || 0);
            const totalProfit = profitPerUnit * item.quantity;

            if (!report[item.name]) {
                report[item.name] = { today: 0, month: 0, year: 0, total: 0 };
            }

            report[item.name].total += totalProfit;
            if (isYear) report[item.name].year += totalProfit;
            if (isMonth) report[item.name].month += totalProfit;
            if (isToday) report[item.name].today += totalProfit;
        });
    });

    return Object.entries(report).sort((a, b) => b[1].total - a[1].total);
  }, [fullHistory]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(fullHistory.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [fullHistory]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      fullHistory
        .filter(day => new Date(day.timestamp).getFullYear().toString() === selectedYear)
        .map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [fullHistory, selectedYear]);

  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return fullHistory.filter(day => {
      const d = new Date(day.timestamp);
      return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    }).sort((a,b) => b.timestamp - a.timestamp);
  }, [fullHistory, selectedYear, selectedMonth]);

  const getMonthName = (monthIndex: number) => {
    return new Date(2000, monthIndex).toLocaleString('ar-SY', { month: 'long' });
  };

  const renderArchive = () => {
    if (step === 'years') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {years.length > 0 ? years.map(year => (
                <button key={year} onClick={() => { setSelectedYear(year); setStep('months'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <Folder size={48} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-black text-white">{year}</span>
                </button>
            )) : (
              <div className="col-span-full py-20 text-center flex flex-col items-center gap-4">
                  <div className="bg-gray-700/30 p-6 rounded-full"><Zap size={48} className="text-gray-600" /></div>
                  <p className="text-gray-500 font-bold">لا توجد عمليات بيع مؤرشفة بعد</p>
              </div>
            )}
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => { setSelectedMonth(monthIdx); setStep('days'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <CalendarDays size={48} className="text-blue-400 group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-4 animate-fade-up h-full">
            <div className="flex items-center gap-2 bg-gray-900 p-1.5 rounded-xl border border-gray-700 shrink-0">
                <button onClick={() => setFilterType('all')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${filterType === 'all' ? 'bg-white text-black shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>الكل</button>
                <button onClick={() => setFilterType('retail')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${filterType === 'retail' ? 'bg-blue-500 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>مفرق</button>
                <button onClick={() => setFilterType('wholesale')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${filterType === 'wholesale' ? 'bg-orange-500 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>جملة</button>
            </div>

            <div className="flex-1 overflow-y-auto space-y-3 pr-1 custom-scrollbar">
                {currentDaysData.map(day => {
                    const filteredItems = day.items.filter(item => filterType === 'all' || item.saleType === filterType);
                    if (filteredItems.length === 0 && filterType !== 'all') return null;
                    const dayTotal = filteredItems.reduce((s, i) => s + (i.price * i.quantity), 0);
                    const isToday = day.id === 'today-active';

                    return (
                        <div key={day.id} className={`rounded-xl border overflow-hidden shadow-sm transition-all ${isToday ? 'border-orange-500/50 bg-orange-500/5' : 'border-gray-700 bg-gray-800'}`}>
                            <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className={`p-4 flex justify-between items-center cursor-pointer ${isToday ? 'bg-orange-500/10' : 'bg-gray-900/50 hover:bg-gray-900'}`}>
                                <div className="flex items-center gap-3">
                                    <div className="text-gray-500">{expandedDayId === day.id ? <ChevronUp size={18} /> : <ChevronDown size={18} />}</div>
                                    <span className={`font-bold ${isToday ? 'text-orange-400' : 'text-white'}`}>{day.date}</span>
                                </div>
                                <span className="font-black text-lg text-green-400">{dayTotal.toLocaleString()} <small className="text-[10px] text-gray-500 font-normal">ل.س</small></span>
                            </div>
                            {expandedDayId === day.id && (
                                <div className="p-4 bg-gray-900/30 border-t border-gray-700 animate-fade-up space-y-2">
                                    {filteredItems.map((item, idx) => (
                                        <div key={idx} className="flex justify-between items-center text-xs p-3 bg-gray-800 rounded-lg border border-gray-700/50">
                                            <div className="flex items-center gap-3">
                                                {item.saleType === 'wholesale' ? <Store size={14} className="text-orange-400" /> : <User size={14} className="text-blue-400" />}
                                                <div className="flex flex-col">
                                                    <span className="text-white font-medium">{item.name}</span>
                                                    <span className="text-[9px] text-gray-500">{item.saleType === 'wholesale' ? 'جملة' : 'مفرق'} • الكمية: {item.quantity}</span>
                                                </div>
                                            </div>
                                            <span className="text-white font-bold">{(item.price * item.quantity).toLocaleString()}</span>
                                        </div>
                                    ))}
                                    <button onClick={() => onPreviewInvoice(filteredItems)} className="w-full mt-2 py-2 bg-gray-700 hover:bg-[#FA8072] text-white rounded-lg text-xs font-bold transition-all">معاينة الفواتير</button>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
  };

  const renderProfitReport = () => (
    <div className="flex flex-col h-full animate-fade-up">
        <div className="bg-blue-500/10 border border-blue-500/20 p-4 rounded-2xl mb-4 flex items-start gap-3">
            <Info size={20} className="text-blue-400 shrink-0 mt-0.5" />
            <p className="text-xs text-gray-400 leading-relaxed font-bold">
                هذا التقرير يحلل صافي أرباح كل منتج بشكل منفصل بناءً على الفرق بين (سعر البيع) و (سعر التكلفة) المسجل عند وقت البيع.
            </p>
        </div>

        <div className="bg-gray-900 rounded-2xl border border-gray-700 overflow-hidden flex-1 flex flex-col">
            <div className="overflow-x-auto custom-scrollbar">
                <table className="w-full text-right text-xs">
                    <thead className="bg-gray-800 text-gray-400 font-black uppercase text-[9px] tracking-widest sticky top-0 z-10">
                        <tr>
                            <th className="p-4 border-b border-gray-700">اسم المنتج</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح اليوم</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح الشهر</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح السنة</th>
                            <th className="p-4 border-b border-gray-700 text-center bg-[#FA8072]/10 text-[#FA8072]">إجمالي الربح</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-800">
                        {profitReport.map(([name, data], idx) => (
                            <tr key={idx} className="hover:bg-gray-800/50 transition-colors">
                                <td className="p-4 font-black text-white">{name}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.today.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.month.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.year.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums font-black text-green-400 bg-green-400/5">{data.total.toLocaleString()}</td>
                            </tr>
                        ))}
                        {profitReport.length === 0 && (
                            <tr><td colSpan={5} className="p-20 text-center text-gray-600 font-bold">لا توجد بيانات بيع مسجلة بعد</td></tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-md z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-3xl w-full max-w-5xl shadow-2xl border border-gray-700 flex flex-col h-[85vh] overflow-hidden animate-fade-up">
        {/* Header Tabs */}
        <div className="p-5 border-b border-gray-700 flex flex-col md:flex-row justify-between items-center bg-gray-900/50 gap-4 shrink-0">
            <div className="flex items-center gap-3 w-full md:w-auto">
                {tab === 'archive' && step !== 'years' && (
                    <button onClick={() => {
                        if (step === 'days') { setStep('months'); setSelectedMonth(-1); } 
                        else if (step === 'months') { setStep('years'); setSelectedYear(''); }
                    }} className="bg-gray-700 hover:bg-[#FA8072] p-2 rounded-full text-white transition-colors shrink-0"><ArrowRight size={20} /></button>
                )}
                <h3 className="font-black text-xl text-white">أرشيف المبيعات</h3>
            </div>

            <div className="flex items-center gap-1 bg-gray-950 p-1 rounded-xl border border-gray-700 w-full md:w-auto">
                <button 
                  onClick={() => setTab('archive')} 
                  className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all ${tab === 'archive' ? 'bg-[#FA8072] text-white shadow-lg shadow-orange-900/20' : 'text-gray-500 hover:text-white'}`}
                >
                    <Folder size={14} /> تصفح الأرشيف
                </button>
                <button 
                  onClick={() => setTab('profit-report')} 
                  className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all ${tab === 'profit-report' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-gray-500 hover:text-white'}`}
                >
                    <PieChart size={14} /> تقرير الأرباح
                </button>
            </div>

            <div className="flex items-center gap-2">
                <button onClick={onClose} className="hidden md:flex items-center gap-2 bg-gray-700 hover:bg-red-600 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all">
                    <span>إغلاق</span>
                    <X size={18} />
                </button>
                <button onClick={onClose} className="p-2 text-gray-400 hover:text-white no-print md:hidden"><X size={24} /></button>
            </div>
        </div>

        <div className="p-6 flex-1 overflow-y-auto custom-scrollbar">
            {tab === 'archive' ? renderArchive() : renderProfitReport()}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, Suspense } from 'react';
import { Plus, Trash2, X, ShoppingCart, UserPlus, Printer, FileText, Store, Folder, CalendarDays, ArrowRight, Zap, ChevronDown, ChevronUp } from 'lucide-react';
import { PurchaseInvoice, PurchaseItem, ArchivedDay, PaymentStatus, Supplier } from '../types';

const PurchasePrintModal = React.lazy(() => import('./PurchasePrintModal').then(module => ({ default: module.PurchasePrintModal })));

interface ExpensesModalProps {
  currentPurchases: PurchaseInvoice[];
  archivedHistory: ArchivedDay[]; 
  onAddInvoice: (invoice: PurchaseInvoice) => void;
  onDeleteInvoice: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
  suppliers: Supplier[];
  onAddSupplier: (supplier: Omit<Supplier, 'id'>) => void;
  onDeleteSupplier: (id: string) => void;
}

type NavStep = 'years' | 'months' | 'days';

export const ExpensesModal: React.FC<ExpensesModalProps> = ({ 
  currentPurchases, archivedHistory, onAddInvoice, onDeleteInvoice, isOpen, onClose, suppliers = [], onAddSupplier, onDeleteSupplier
}) => {
  const [activeTab, setActiveTab] = useState<'new' | 'history' | 'suppliers'>('new');
  const [selectedSupplierId, setSelectedSupplierId] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('paid'); 
  const [itemInputs, setItemInputs] = useState({ name: '', quantity: '', unitPrice: '' });
  const [currentInvoiceItems, setCurrentInvoiceItems] = useState<PurchaseItem[]>([]);
  const [invoiceToPrint, setInvoiceToPrint] = useState<PurchaseInvoice | null>(null);
  const [newSup, setNewSup] = useState({ name: '', phone: '' });

  // Navigation state for History Tab
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);

  const fullHistory = useMemo(() => {
    const merged = [...archivedHistory];
    if (currentPurchases.length > 0) {
        const today = new Date();
        const todayStr = today.toLocaleDateString('ar-SY');
        const existingTodayIdx = merged.findIndex(d => d.date.includes(todayStr));

        const todayEntry: ArchivedDay = {
            id: 'today-active-purchases',
            date: `${todayStr} (مباشر)`,
            timestamp: Date.now(),
            totalRevenue: 0,
            totalExpenses: currentPurchases.reduce((s, i) => s + i.totalAmount, 0),
            totalItems: 0,
            items: [],
            purchaseInvoices: currentPurchases
        };

        if (existingTodayIdx > -1) merged[existingTodayIdx] = { ...merged[existingTodayIdx], purchaseInvoices: [...(merged[existingTodayIdx].purchaseInvoices || []), ...currentPurchases] };
        else merged.push(todayEntry);
    }
    return merged;
  }, [archivedHistory, currentPurchases]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(fullHistory.filter(d => (d.purchaseInvoices || []).length > 0).map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [fullHistory]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      fullHistory
        .filter(day => (day.purchaseInvoices || []).length > 0 && new Date(day.timestamp).getFullYear().toString() === selectedYear)
        .map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [fullHistory, selectedYear]);

  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return fullHistory.filter(day => {
      const d = new Date(day.timestamp);
      return (day.purchaseInvoices || []).length > 0 && d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    }).sort((a,b) => b.timestamp - a.timestamp);
  }, [fullHistory, selectedYear, selectedMonth]);

  const getMonthName = (monthIndex: number) => {
    return new Date(2000, monthIndex).toLocaleString('ar-SY', { month: 'long' });
  };

  const addItem = () => {
      if (!itemInputs.name || !itemInputs.quantity || !itemInputs.unitPrice) return;
      const q = parseFloat(itemInputs.quantity); 
      const price = parseFloat(itemInputs.unitPrice);
      setCurrentInvoiceItems(prev => [...prev, { id: Date.now().toString(), name: itemInputs.name, quantity: q, cost: price, total: q * price }]);
      setItemInputs({ name: '', quantity: '', unitPrice: '' });
  };

  const handleSaveInvoice = () => {
      const supplier = suppliers.find(s => s.id === selectedSupplierId);
      if (!supplier || currentInvoiceItems.length === 0) return alert('يرجى تحديد مورد وإضافة مواد للفاتورة');

      const totalAmount = currentInvoiceItems.reduce((sum, item) => sum + item.total, 0);
      onAddInvoice({ 
          id: Date.now().toString(), 
          supplierName: supplier.name, 
          date: new Date().toLocaleDateString('ar-SY'), 
          timestamp: Date.now(), 
          items: currentInvoiceItems, 
          totalAmount, 
          paymentStatus 
      });
      setSelectedSupplierId(''); 
      setCurrentInvoiceItems([]); 
      setActiveTab('history');
      setStep('years');
  };

  const renderHistoryContent = () => {
    if (step === 'years') return (
        <div className="grid grid-cols-2 gap-4 animate-fade-up">
            {years.length > 0 ? years.map(year => (
                <button key={year} onClick={() => { setSelectedYear(year); setStep('months'); }} className="bg-gray-900/40 hover:bg-gray-700/50 border border-gray-700 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <Folder size={40} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                    <span className="text-lg font-black text-white">{year}</span>
                </button>
            )) : (
              <div className="col-span-full py-20 text-center flex flex-col items-center gap-4">
                  <div className="bg-gray-900/30 p-6 rounded-full"><Zap size={48} className="text-gray-700" /></div>
                  <p className="text-gray-500 font-bold">لا توجد مشتريات مؤرشفة</p>
              </div>
            )}
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => { setSelectedMonth(monthIdx); setStep('days'); }} className="bg-gray-900/40 hover:bg-gray-700/50 border border-gray-700 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <CalendarDays size={40} className="text-blue-400 group-hover:scale-110 transition-transform" />
                    <span className="text-lg font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-3 animate-fade-up h-full">
            <div className="flex-1 overflow-y-auto space-y-2 pr-1 custom-scrollbar">
                {currentDaysData.map(day => {
                    const isToday = day.id === 'today-active-purchases';
                    return (
                        <div key={day.id} className={`rounded-xl border overflow-hidden transition-all ${isToday ? 'border-orange-500/30 bg-orange-500/5' : 'border-gray-700 bg-gray-900/20'}`}>
                            <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className={`p-4 flex justify-between items-center cursor-pointer ${isToday ? 'bg-orange-500/10' : 'bg-gray-900/50 hover:bg-gray-900'}`}>
                                <div className="flex items-center gap-3">
                                    <div className="text-gray-500">{expandedDayId === day.id ? <ChevronUp size={16} /> : <ChevronDown size={16} />}</div>
                                    <span className={`font-bold text-sm ${isToday ? 'text-orange-400' : 'text-white'}`}>{day.date}</span>
                                </div>
                                <span className="font-black text-red-400">{(day.purchaseInvoices || []).reduce((s,i) => s + i.totalAmount, 0).toLocaleString()} <small className="text-[9px] text-gray-600 font-normal">ل.س</small></span>
                            </div>

                            {expandedDayId === day.id && (
                                <div className="p-3 bg-black/20 border-t border-gray-700 animate-fade-up space-y-2">
                                    {(day.purchaseInvoices || []).map((inv) => (
                                        <div key={inv.id} className="bg-gray-800 p-3 rounded-xl border border-gray-700 flex justify-between items-center group">
                                            <div className="flex items-center gap-3">
                                                <div className="bg-gray-900 p-1.5 rounded text-red-400"><Store size={14} /></div>
                                                <div className="flex flex-col">
                                                    <span className="text-white text-xs font-bold">{inv.supplierName}</span>
                                                    <span className="text-[9px] text-gray-500">{inv.paymentStatus === 'paid' ? 'نقدي' : 'آجل'} • {inv.items.length} مواد</span>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                <span className="text-white font-bold text-xs">{inv.totalAmount.toLocaleString()}</span>
                                                <button onClick={() => setInvoiceToPrint(inv)} className="p-1.5 bg-gray-700 rounded hover:bg-blue-600 text-white transition-colors"><Printer size={12}/></button>
                                                <button onClick={() => onDeleteInvoice(inv.id)} className="p-1.5 text-gray-500 hover:text-red-500 transition-colors"><Trash2 size={12}/></button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
  };

  if (!isOpen) return null;

  return (
    <>
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-[2rem] w-full max-w-2xl shadow-2xl border border-gray-700 flex flex-col h-[85vh] overflow-hidden">

        <div className="p-5 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 shrink-0">
          <div className="flex items-center gap-3">
            {activeTab === 'history' && step !== 'years' && (
                <button onClick={() => {
                    if (step === 'days') { setStep('months'); setSelectedMonth(-1); } 
                    else if (step === 'months') { setStep('years'); setSelectedYear(''); }
                }} className="bg-gray-700 hover:bg-[#FA8072] p-1.5 rounded-full text-white transition-colors"><ArrowRight size={18} /></button>
            )}
            <div className="flex items-center gap-2 text-white">
                <ShoppingCart size={22} className="text-[#FA8072]" />
                <h3 className="font-black text-xl">إدارة المشتريات</h3>
            </div>
          </div>
          <div className="flex items-center gap-2">
              <button onClick={onClose} className="hidden md:flex items-center gap-2 bg-gray-700 hover:bg-red-600 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all">
                  <span>خروج</span>
                  <X size={18} />
              </button>
              <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full text-gray-400 md:hidden"><X size={24} /></button>
          </div>
        </div>

        <div className="flex border-b border-gray-700 bg-gray-900/30">
            <button onClick={() => setActiveTab('new')} className={`flex-1 py-4 text-xs font-black transition-all ${activeTab === 'new' ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500 hover:bg-gray-800'}`}>فاتورة جديدة</button>
            <button onClick={() => { setActiveTab('history'); setStep('years'); }} className={`flex-1 py-4 text-xs font-black transition-all ${activeTab === 'history' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-800'}`}>سجل المشتريات</button>
            <button onClick={() => setActiveTab('suppliers')} className={`flex-1 py-4 text-xs font-black transition-all ${activeTab === 'suppliers' ? 'bg-gray-700 text-white' : 'text-gray-500 hover:bg-gray-800'}`}>قائمة الموردين</button>
        </div>

        <div className="p-6 overflow-y-auto flex-1 custom-scrollbar">
          {activeTab === 'new' ? (
              <div className="space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 font-black uppercase pr-1">تحديد المورد:</label>
                        <select value={selectedSupplierId} onChange={e => setSelectedSupplierId(e.target.value)} className={`w-full bg-gray-900 border rounded-xl px-4 py-3 text-white text-sm outline-none transition-all ${!selectedSupplierId && suppliers.length > 0 ? 'border-orange-500' : 'border-gray-700 focus:border-[#FA8072]'}`}>
                            <option value="">اختر مورد...</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                    <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 font-black uppercase pr-1">حالة الدفع:</label>
                        <div className="flex bg-gray-900 p-1 rounded-xl border border-gray-700">
                            <button onClick={() => setPaymentStatus('paid')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${paymentStatus === 'paid' ? 'bg-green-600 text-white shadow-md' : 'text-gray-500'}`}>نقدي</button>
                            <button onClick={() => setPaymentStatus('credit')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${paymentStatus === 'credit' ? 'bg-orange-600 text-white shadow-md' : 'text-gray-500'}`}>آجل</button>
                        </div>
                    </div>
                  </div>

                  <div className="bg-gray-900/40 p-5 rounded-2xl border border-gray-700 space-y-4">
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                          <input type="text" value={itemInputs.name} onChange={e => setItemInputs({...itemInputs, name: e.target.value})} placeholder="المادة المشتراة" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-sm" />
                          <input type="number" value={itemInputs.quantity} onChange={e => setItemInputs({...itemInputs, quantity: e.target.value})} placeholder="الكمية" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-sm text-center font-bold" />
                          <input type="number" value={itemInputs.unitPrice} onChange={e => setItemInputs({...itemInputs, unitPrice: e.target.value})} placeholder="سعر التكلفة" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-[#FA8072] text-sm text-center font-bold" />
                      </div>
                      <button onClick={addItem} className="w-full bg-gray-700 hover:bg-[#FA8072] text-white py-3 rounded-xl font-black text-xs flex items-center justify-center gap-2 transition-all active:scale-95"><Plus size={18}/> إضافة بند للفاتورة</button>
                  </div>

                  <div className="bg-gray-950/30 border border-gray-700 rounded-2xl overflow-hidden shadow-inner">
                      <table className="w-full text-xs text-right">
                          <thead className="bg-gray-900 text-gray-500">
                              <tr><th className="p-3">الصنف</th><th className="p-3 text-center">الكمية</th><th className="p-3">الإجمالي</th><th className="p-3 w-8"></th></tr>
                          </thead>
                          <tbody className="divide-y divide-gray-800">
                              {currentInvoiceItems.map(item => (
                                  <tr key={item.id} className="hover:bg-gray-800/50"><td className="p-3 text-white font-medium">{item.name}</td><td className="p-3 text-center text-gray-400 font-bold">{item.quantity}</td><td className="p-3 text-[#FA8072] font-black">{item.total.toLocaleString()}</td><td className="p-3"><button onClick={() => setCurrentInvoiceItems(s => s.filter(i => i.id !== item.id))} className="text-gray-600 hover:text-red-500 transition-colors"><Trash2 size={16}/></button></td></tr>
                              ))}
                              {currentInvoiceItems.length === 0 && <tr><td colSpan={4} className="p-10 text-center text-gray-600 italic">لا توجد مواد في هذه الفاتورة</td></tr>}
                          </tbody>
                      </table>
                  </div>

                  <div className="flex items-center justify-between pt-6 border-t border-gray-700">
                      <div className="flex flex-col">
                        <span className="text-[10px] text-gray-500 font-black uppercase tracking-widest mb-1">إجمالي الفاتورة</span>
                        <div className="text-3xl font-black text-red-500">{currentInvoiceItems.reduce((s,i) => s + i.total, 0).toLocaleString()} <span className="text-xs text-gray-500 font-normal">ل.س</span></div>
                      </div>
                      <button onClick={handleSaveInvoice} className="bg-green-600 hover:bg-green-500 text-white px-8 py-4 rounded-2xl font-black text-sm flex items-center gap-3 shadow-xl shadow-green-900/20 active:scale-95 transition-all"><FileText size={20} /> حفظ الفاتورة</button>
                  </div>
              </div>
          ) : activeTab === 'suppliers' ? (
              <div className="space-y-8">
                  <div className="bg-gray-900/40 p-6 rounded-2xl border border-gray-700 space-y-4">
                      <h4 className="text-white font-black text-sm">إضافة مورد جديد للنظام</h4>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                          <input type="text" value={newSup.name} onChange={e => setNewSup({...newSup, name: e.target.value})} placeholder="اسم المورد أو الشركة" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-sm" />
                          <input type="text" value={newSup.phone} onChange={e => setNewSup({...newSup, phone: e.target.value})} placeholder="رقم الهاتف" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-sm dir-ltr text-right" />
                      </div>
                      <button onClick={() => { if(!newSup.name) return; onAddSupplier(newSup); setNewSup({name:'', phone:''}); }} className="w-full bg-[#FA8072] text-white py-3.5 rounded-xl font-black text-xs flex items-center justify-center gap-2 shadow-lg active:scale-95 transition-all"><UserPlus size={18}/> إضافة مورد</button>
                  </div>

                  <div className="space-y-3">
                      <h4 className="text-gray-500 font-black text-[10px] uppercase tracking-widest pl-2">الموردين المسجلين ({suppliers.length})</h4>
                      <div className="grid gap-3">
                        {suppliers.map(s => (
                            <div key={s.id} className="bg-gray-900/40 p-4 rounded-[1.5rem] border border-gray-700 flex justify-between items-center group hover:border-[#FA8072]/50 transition-all">
                                <div className="flex items-center gap-4">
                                    <div className="bg-gray-800 p-3 rounded-2xl text-[#FA8072] group-hover:scale-110 transition-transform"><Store size={20} /></div>
                                    <div className="flex flex-col"><span className="text-white font-black text-sm">{s.name}</span><span className="text-[10px] text-gray-500 font-bold">{s.phone || 'بدون رقم هاتف'}</span></div>
                                </div>
                                <button onClick={() => onDeleteSupplier(s.id)} className="text-gray-600 hover:text-red-400 p-2 transition-colors"><Trash2 size={20}/></button>
                            </div>
                        ))}
                      </div>
                      {suppliers.length === 0 && <p className="text-center py-10 text-gray-700 text-sm italic">لا يوجد موردين مضافين حالياً</p>}
                  </div>
              </div>
          ) : (
              <div className="h-full">
                  {renderHistoryContent()}
              </div>
          )}
        </div>
      </div>
    </div>
    {invoiceToPrint && <Suspense fallback={null}><PurchasePrintModal invoice={invoiceToPrint} onClose={() => setInvoiceToPrint(null)} /></Suspense>}
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { FileText, History, Database, Wifi, WifiOff, RefreshCw, Clock, Calendar, DownloadCloud, BarChart3, Wallet, LogOut } from 'lucide-react';

interface HeaderProps {
  onOpenHistory: () => void;
  onOpenDataManagement: () => void;
  onOpenExpenses: () => void;
  onOpenAnalytics: () => void;
  onLogout: () => void;
  isOnline: boolean;
  lastSyncTime: Date;
  onManualSync: () => void;
  onQuickBackup: () => void;
  isSyncing: boolean;
  installPrompt?: any;
  onInstall?: () => void;
}

export const Header: React.FC<HeaderProps> = ({ 
  onOpenHistory, 
  onOpenDataManagement, 
  onOpenExpenses,
  onOpenAnalytics,
  onLogout,
  isOnline,
  lastSyncTime,
  onManualSync,
  onQuickBackup,
  isSyncing,
  installPrompt,
  onInstall
}) => {
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentTime(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const formatLastSync = (date: Date) => {
    return date.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <header className="bg-[#1F2937] border-b border-gray-700 shadow-xl sticky top-0 z-40 no-print">
      <div className="container mx-auto px-4 py-1.5">
        <div className="flex flex-col md:flex-row items-center justify-between gap-2">

            {/* Right: Brand */}
            <div className="flex items-center justify-between w-full md:w-auto">
                 <div className="flex items-center gap-2">
                     <div className="bg-gradient-to-br from-[#FA8072] to-orange-600 p-1.5 rounded-lg shadow-lg">
                       <FileText className="text-white" size={16} />
                     </div>
                     <h1 className="font-bold text-sm text-white leading-tight">نظام المبيعات</h1>
                 </div>

                 {/* Mobile Status Bar */}
                 <div className="md:hidden flex items-center gap-2.5 bg-black/30 px-3.5 py-1.5 rounded-full border border-gray-700 shadow-inner">
                    <div className="flex items-center gap-2 border-l border-gray-700/50 pl-2">
                        <div className={`flex items-center gap-1.5 ${isOnline ? 'text-green-500' : 'text-red-500 animate-pulse'}`}>
                             {isOnline ? <Wifi size={12} /> : <WifiOff size={12} />}
                             <button 
                                onClick={onManualSync} 
                                disabled={isSyncing} 
                                className={`text-blue-400 ${isSyncing ? 'animate-spin' : ''}`}
                            >
                                <RefreshCw size={12} />
                            </button>
                        </div>
                        <button onClick={onLogout} className="text-red-400/80 hover:text-red-300 mr-1">
                            <LogOut size={12} />
                        </button>
                    </div>
                    <span className="text-[11px] font-black text-white tabular-nums">
                        {currentTime.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })}
                    </span>
                 </div>
            </div>

            {/* Center: Navigation */}
            <div className="flex items-center gap-0.5 bg-gray-900/40 p-1 rounded-xl border border-gray-800/50">
                <button onClick={onOpenAnalytics} className="flex flex-col items-center justify-center w-12 h-10 rounded-lg text-gray-400 hover:text-white hover:bg-gray-800 transition-all group">
                    <BarChart3 size={16} className="group-hover:text-green-400" />
                    <span className="text-[8px] font-bold mt-0.5">التحليلات</span>
                </button>
                <button onClick={onOpenExpenses} className="flex flex-col items-center justify-center w-12 h-10 rounded-lg text-gray-400 hover:text-white hover:bg-gray-800 transition-all group">
