                     <div className="bg-gradient-to-br from-[#FA8072] to-orange-600 p-1.5 rounded-lg shadow-lg">
                       <FileText className="text-white" size={16} />
                     </div>
                     <h1 className="font-bold text-sm text-white leading-tight">نظام المبيعات</h1>
