        <p className="text-gray-400 text-sm font-bold mb-8 h-10">
          {progress < 40 && "جاري الاتصال بقاعدة البيانات المحلية..."}
          {progress >= 40 && progress < 80 && "تأمين الملفات للعمل بوضعية الأوفلاين..."}
