import React, { useState, useEffect } from 'react';
import { ShoppingCart, Settings, Edit3, Trash2, CheckCircle, Plus, Minus, UserPlus, X, Check } from 'lucide-react';
import { Product, UnitType, SaleType, Customer } from '../types';

interface POSInterfaceProps {
  onCompleteOrder: (items: any[], customerName?: string, customerId?: string, saleType?: SaleType) => void;
  products: Product[];
  customers: Customer[];
  onOpenProductManager: () => void;
  onOpenCustomerManager: () => void;
}

export const POSInterface: React.FC<POSInterfaceProps> = ({ 
    onCompleteOrder, products, customers, onOpenProductManager, onOpenCustomerManager 
}) => {
  const [cart, setCart] = useState<any[]>([]);
  const [saleType, setSaleType] = useState<SaleType>('retail');
  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [manualCustomerName, setManualCustomerName] = useState(''); 
  const [showCustomInput, setShowCustomInput] = useState(false);
  const [customForm, setCustomForm] = useState({ name: '', price: '', cost: '', unit: 'piece' as UnitType });

  const [editingPriceId, setEditingPriceId] = useState<string | null>(null);
  const [tempPrice, setTempPrice] = useState<string>('');

  useEffect(() => {
    setCart(prev => prev.map(item => {
      const productDef = products.find(p => p.name === item.name && p.unitType === item.unitType);
      if (productDef) {
        return {
          ...item,
          price: saleType === 'wholesale' ? (productDef.wholesalePrice || productDef.price) : productDef.price
        };
      }
      return item;
    }));
  }, [saleType, products]);

  const addToCart = (p: Product) => {
    setCart(prev => {
      const idx = prev.findIndex(i => i.name === p.name && i.unitType === p.unitType);
      const activePrice = saleType === 'wholesale' ? (p.wholesalePrice || p.price) : p.price;

      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], quantity: next[idx].quantity + 1, price: activePrice };
        return next;
      }
      return [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: p.name, 
        price: activePrice, 
        costPrice: p.costPrice || 0, 
        quantity: 1, 
        unitType: p.unitType 
      }];
    });
  };

  const addCustomToCart = () => {
    if (!customForm.name || !customForm.price) return;
    setCart(prev => [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: customForm.name, 
        price: parseFloat(customForm.price) || 0, 
        costPrice: parseFloat(customForm.cost) || 0,
        quantity: 1,
        unitType: customForm.unit
    }]);
    setCustomForm({ name: '', price: '', cost: '', unit: 'piece' });
    setShowCustomInput(false);
  };

  const updateQty = (id: string, delta: number) => {
    setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: Math.max(0.1, parseFloat((i.quantity + delta * (i.unitType === 'kg' ? 0.1 : 1)).toFixed(2))) } : i));
  };

  const handleManualQtyChange = (id: string, value: string) => {
    const newQty = parseFloat(value);
    if (!isNaN(newQty)) {
        setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: newQty } : i));
    } else if (value === '') {
        setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: 0 } : i));
    }
  };

  const handleStartEditPrice = (item: any) => {
    setEditingPriceId(item.tempId);
    setTempPrice(item.price.toString());
  };

  const handleSavePrice = (tempId: string) => {
    const newPrice = parseFloat(tempPrice);
    if (!isNaN(newPrice) && newPrice >= 0) {
      setCart(prev => prev.map(i => i.tempId === tempId ? { ...i, price: newPrice } : i));
    }
    setEditingPriceId(null);
  };

  const isCheckoutDisabled = cart.length === 0 || (saleType === 'wholesale' && !selectedCustomerId);

  const handleCheckout = () => {
    if (isCheckoutDisabled) return;
    const items = cart.map(({ name, price, costPrice, quantity, unitType }) => ({ name, price, costPrice, quantity, unitType }));
    const name = saleType === 'wholesale' ? customers.find(c => c.id === selectedCustomerId)?.name : manualCustomerName;
    onCompleteOrder(items, name, selectedCustomerId || undefined, saleType);
    setCart([]); setManualCustomerName(''); setSelectedCustomerId(''); setSaleType('retail');
  };

  const total = cart.reduce((s, i) => s + (i.price * i.quantity), 0);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">
      <div className="lg:col-span-2 space-y-4">
        <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
             <h2 className="font-bold text-white flex items-center gap-2"><ShoppingCart size={20} className="text-[#FA8072]" /> قائمة المنتجات</h2>
             <button onClick={onOpenProductManager} className="text-xs bg-gray-700 hover:bg-gray-600 text-gray-300 px-3 py-1.5 rounded-lg transition-colors">تعديل الأصناف</button>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
            {products.map(p => (
                <button key={p.id} onClick={() => addToCart(p)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-gray-700 hover:bg-gray-700 hover:border-[#FA8072] text-white rounded-2xl transition-all shadow-sm active:scale-95 h-32 relative group">
                    <div className={`absolute top-2 right-2 px-1.5 py-0.5 rounded text-[10px] font-bold ${p.unitType === 'kg' ? 'bg-yellow-400 text-black' : 'bg-blue-300 text-black'}`}>{p.unitType === 'kg' ? 'كغ' : 'قطعة'}</div>
                    <span className="font-bold text-sm text-center mb-1 group-hover:text-[#FA8072]">{p.name}</span>
                    <span className="text-xs text-gray-400 bg-gray-900/50 px-2 py-1 rounded-md">
                      {(saleType === 'wholesale' ? (p.wholesalePrice || p.price) : p.price).toLocaleString()} ل.س
                    </span>
                </button>
            ))}
            <button onClick={() => setShowCustomInput(true)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-dashed border-gray-600 hover:bg-gray-700 text-gray-400 rounded-2xl h-32"><Plus size={24} className="mb-2" /><span className="text-xs">مادة حرة</span></button>
        </div>

        {showCustomInput && (
            <div className="bg-gray-800 p-4 rounded-xl border border-[#FA8072] animate-fade-up relative">
                <button onClick={() => setShowCustomInput(false)} className="absolute left-3 top-3 text-gray-500 hover:text-white"><X size={18} /></button>
                <h4 className="text-sm font-bold text-white mb-3">إضافة مادة حرة</h4>
                <div className="grid grid-cols-1 md:grid-cols-12 gap-2">
                    <input type="text" value={customForm.name} onChange={e => setCustomForm({...customForm, name: e.target.value})} placeholder="المادة" className="md:col-span-4 bg-gray-900 border border-gray-600 text-white px-3 py-2 rounded-lg text-sm" autoFocus />
                    <input type="number" value={customForm.cost} onChange={e => setCustomForm({...customForm, cost: e.target.value})} placeholder="التكلفة" className="md:col-span-2 bg-gray-900 border border-gray-600 text-red-400 px-3 py-2 rounded-lg text-sm" />
                    <input type="number" value={customForm.price} onChange={e => setCustomForm({...customForm, price: e.target.value})} placeholder="البيع" className="md:col-span-2 bg-gray-900 border border-gray-600 text-green-400 px-3 py-2 rounded-lg text-sm" />
                    <select value={customForm.unit} onChange={e => setCustomForm({...customForm, unit: e.target.value as UnitType})} className="md:col-span-2 bg-gray-900 border border-gray-600 text-white px-2 py-2 rounded-lg text-sm"><option value="piece">قطعة</option><option value="kg">كغ</option></select>
                    <button onClick={addCustomToCart} className="md:col-span-2 bg-[#FA8072] text-white rounded-lg font-bold">إضافة</button>
                </div>
            </div>
        )}
      </div>

      <div className="lg:col-span-1">
        <div className="bg-gray-800 rounded-[2rem] border border-gray-700 shadow-2xl overflow-hidden flex flex-col h-full min-h-[550px]">
            <div className="bg-gray-900/80 p-5 border-b border-gray-700 space-y-4">
                <div className="flex justify-between items-center">
                    <h3 className="font-black text-white flex items-center gap-2"><ShoppingCart size={22} className="text-[#FA8072]" /> سلة المبيعات</h3>
                    {cart.length > 0 && <button onClick={() => setCart([])} className="text-[10px] font-black text-red-400 hover:underline">تفريغ السلة</button>}
                </div>
                <div className="grid grid-cols-2 bg-gray-700 p-1 rounded-xl">
                    <button onClick={() => setSaleType('retail')} className={`py-2 text-xs font-black rounded-lg transition-all ${saleType === 'retail' ? 'bg-white text-black shadow-sm' : 'text-gray-400'}`}>مفرق</button>
                    <button onClick={() => setSaleType('wholesale')} className={`py-2 text-xs font-black rounded-lg transition-all ${saleType === 'wholesale' ? 'bg-[#FA8072] text-white shadow-sm' : 'text-gray-400'}`}>جملة</button>
                </div>
                {saleType === 'retail' ? (
                     <input type="text" value={manualCustomerName} onChange={e => setManualCustomerName(e.target.value)} placeholder="اسم الزبون (اختياري)..." className="w-full bg-gray-800 border border-gray-700 text-white text-sm rounded-xl px-4 py-2.5 outline-none focus:border-[#FA8072]" />
                ) : (
                    <div className="flex gap-2">
                         <select value={selectedCustomerId} onChange={e => setSelectedCustomerId(e.target.value)} className={`w-full bg-gray-800 border text-white text-sm rounded-xl px-4 py-2.5 outline-none transition-all ${!selectedCustomerId && cart.length > 0 ? 'border-orange-500 animate-pulse' : 'border-gray-700 focus:border-[#FA8072]'}`}>
                            <option value="">اختر عميل الجملة...</option>
                            {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                         </select>
                        <button onClick={onOpenCustomerManager} className="bg-blue-600 text-white px-4 rounded-xl hover:bg-blue-500 transition-colors shadow-lg shadow-blue-900/20"><UserPlus size={18} /></button>
                    </div>
                )}
            </div>

            <div className="flex-grow p-4 overflow-y-auto space-y-3 custom-scrollbar">
                {!cart.length ? (
                    <div className="h-full flex flex-col items-center justify-center text-gray-700 py-10">
                        <div className="bg-gray-700/20 p-6 rounded-full mb-4">
                            <ShoppingCart size={48} className="opacity-20" />
                        </div>
                        <p className="font-bold">السلة فارغة</p>
                    </div>
                ) : (
                    cart.map(i => (
                        <div key={i.tempId} className="bg-gray-700/30 p-4 rounded-2xl flex flex-col gap-3 border border-gray-700/50 hover:border-[#FA8072]/30 transition-all">
                            <div className="flex justify-between items-start">
                                <div className="flex flex-col flex-1">
                                    <span className="text-white font-black text-sm">{i.name}</span>
                                    {editingPriceId === i.tempId ? (
                                        <div className="flex items-center gap-1 mt-1">
                                            <input 
                                                type="number" 
                                                value={tempPrice} 
                                                onChange={e => setTempPrice(e.target.value)} 
                                                onBlur={() => handleSavePrice(i.tempId)} 
                                                onKeyDown={e => e.key === 'Enter' && handleSavePrice(i.tempId)} 
                                                className="w-20 bg-gray-900 border border-[#FA8072] text-white text-xs px-2 py-1 rounded-lg" 
                                                autoFocus 
                                            />
                                        </div>
                                    ) : (
                                        <div className="mt-1 flex items-center gap-1.5 cursor-pointer group/price" onClick={() => handleStartEditPrice(i)}>
                                            <span className="text-[10px] text-gray-500">السعر: <span className="text-gray-300 font-bold tabular-nums">{i.price.toLocaleString()}</span></span>
                                            <Edit3 size={10} className="text-[#FA8072] opacity-30 group-hover/price:opacity-100" />
                                        </div>
                                    )}
                                </div>
                                <button onClick={() => setCart(p => p.filter(it => it.tempId !== i.tempId))} className="text-gray-600 hover:text-red-500 transition-colors p-1"><Trash2 size={16} /></button>
                            </div>

                            <div className="flex items-center justify-between">
                                {/* Enhanced Quantity Control with Input Field */}
                                <div className="flex items-center gap-1 bg-gray-900/50 rounded-xl px-2 py-1.5 border border-gray-700">
                                    <button onClick={() => updateQty(i.tempId, -1)} className="text-gray-500 hover:text-white transition-colors p-1"><Minus size={14} /></button>
                                    <input 
                                        type="number" 
                                        value={i.quantity} 
                                        onChange={(e) => handleManualQtyChange(i.tempId, e.target.value)}
                                        className="w-14 bg-transparent text-white text-sm font-black text-center outline-none border-none [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
                                        step={i.unitType === 'kg' ? '0.1' : '1'}
                                    />
                                    <button onClick={() => updateQty(i.tempId, 1)} className="text-gray-500 hover:text-white transition-colors p-1"><Plus size={14} /></button>
                                </div>

                                <div className="flex flex-col items-end">
                                    <span className="text-[#FA8072] font-black text-lg tabular-nums">{(i.price * i.quantity).toLocaleString()}</span>
                                    <span className="text-[8px] text-gray-600 font-bold uppercase">المجموع</span>
                                </div>
                            </div>
                        </div>
                    ))
                )}
            </div>

            <div className="p-6 bg-gray-900/90 border-t border-gray-700 shrink-0">
                <div className="flex justify-between items-center mb-5">
                    <span className="text-gray-500 font-black text-xs uppercase tracking-widest">إجمالي السلة</span>
                    <div className="text-right">
                        <span className="text-3xl font-black text-white tabular-nums">{total.toLocaleString()}</span>
                        <span className="text-[10px] text-gray-500 font-bold mr-1">ل.س</span>
                    </div>
                </div>
                <button 
                  onClick={handleCheckout} 
                  disabled={isCheckoutDisabled} 
                  className={`w-full py-4 rounded-[1.5rem] font-black text-lg flex items-center justify-center gap-3 transition-all active:scale-[0.98] shadow-2xl ${!isCheckoutDisabled ? 'bg-green-600 text-white hover:bg-green-500 shadow-green-900/20' : 'bg-gray-700 text-gray-500 cursor-not-allowed opacity-50'}`}
                >
                  <CheckCircle size={24} /> تأكيد وحفظ الفاتورة
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ShoppingCart, Settings, Edit3, Trash2, CheckCircle, Plus, Minus, UserPlus, X, Check } from 'lucide-react';
import { Product, UnitType, SaleType, Customer } from '../types';

interface POSInterfaceProps {
  onCompleteOrder: (items: any[], customerName?: string, customerId?: string, saleType?: SaleType) => void;
  products: Product[];
  customers: Customer[];
  onOpenProductManager: () => void;
  onOpenCustomerManager: () => void;
}

export const POSInterface: React.FC<POSInterfaceProps> = ({ 
    onCompleteOrder, products, customers, onOpenProductManager, onOpenCustomerManager 
}) => {
  const [cart, setCart] = useState<any[]>([]);
  const [saleType, setSaleType] = useState<SaleType>('retail');
  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [manualCustomerName, setManualCustomerName] = useState(''); 
  const [showCustomInput, setShowCustomInput] = useState(false);
  const [customForm, setCustomForm] = useState({ name: '', price: '', cost: '', unit: 'piece' as UnitType });

  const [editingPriceId, setEditingPriceId] = useState<string | null>(null);
  const [tempPrice, setTempPrice] = useState<string>('');

  useEffect(() => {
    setCart(prev => prev.map(item => {
      const productDef = products.find(p => p.name === item.name && p.unitType === item.unitType);
      if (productDef) {
        return {
          ...item,
          price: saleType === 'wholesale' ? (productDef.wholesalePrice || productDef.price) : productDef.price
        };
      }
      return item;
    }));
  }, [saleType, products]);

  const addToCart = (p: Product) => {
    setCart(prev => {
      const idx = prev.findIndex(i => i.name === p.name && i.unitType === p.unitType);
      const activePrice = saleType === 'wholesale' ? (p.wholesalePrice || p.price) : p.price;

      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], quantity: next[idx].quantity + 1, price: activePrice };
        return next;
      }
      return [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: p.name, 
        price: activePrice, 
        costPrice: p.costPrice || 0, 
        quantity: 1, 
        unitType: p.unitType 
      }];
    });
  };

  const addCustomToCart = () => {
    if (!customForm.name || !customForm.price) return;
    setCart(prev => [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: customForm.name, 
        price: parseFloat(customForm.price) || 0, 
        costPrice: parseFloat(customForm.cost) || 0,
        quantity: 1,
        unitType: customForm.unit
    }]);
    setCustomForm({ name: '', price: '', cost: '', unit: 'piece' });
    setShowCustomInput(false);
  };

  const updateQty = (id: string, delta: number) => {
    setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: Math.max(0.1, parseFloat((i.quantity + delta * (i.unitType === 'kg' ? 0.1 : 1)).toFixed(2))) } : i));
  };

  const handleManualQtyChange = (id: string, value: string) => {
    const newQty = parseFloat(value);
    if (!isNaN(newQty)) {
        setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: newQty } : i));
    } else if (value === '') {
        setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: 0 } : i));
    }
  };

  const handleStartEditPrice = (item: any) => {
    setEditingPriceId(item.tempId);
    // إذا كان وزن، نظهر الإجمالي الحالي لتسهيل التعديل
    if (item.unitType === 'kg') {
      setTempPrice((item.price * item.quantity).toString());
    } else {
      setTempPrice(item.price.toString());
    }
  };

  const handleSavePrice = (tempId: string) => {
    const enteredValue = parseFloat(tempPrice);
    if (!isNaN(enteredValue) && enteredValue >= 0) {
      setCart(prev => prev.map(i => {
        if (i.tempId === tempId) {
          if (i.unitType === 'kg') {
            // الميزة المطلوبة: تعديل الوزن بناءً على المبلغ المدخل
            // الكمية = المبلغ الإجمالي / سعر الكيلو
            const newQty = parseFloat((enteredValue / i.price).toFixed(3));
            return { ...i, quantity: newQty };
          } else {
            // المواد بالقطعة: تعديل سعر القطعة بشكل مباشر
            return { ...i, price: enteredValue };
          }
        }
        return i;
      }));
    }
    setEditingPriceId(null);
  };

  const isCheckoutDisabled = cart.length === 0 || (saleType === 'wholesale' && !selectedCustomerId);

  const handleCheckout = () => {
    if (isCheckoutDisabled) return;
    const items = cart.map(({ name, price, costPrice, quantity, unitType }) => ({ name, price, costPrice, quantity, unitType }));
    const name = saleType === 'wholesale' ? customers.find(c => c.id === selectedCustomerId)?.name : manualCustomerName;
    onCompleteOrder(items, name, selectedCustomerId || undefined, saleType);
    setCart([]); setManualCustomerName(''); setSelectedCustomerId(''); setSaleType('retail');
  };

  const total = cart.reduce((s, i) => s + (i.price * i.quantity), 0);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">
      <div className="lg:col-span-2 space-y-4">
        <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
             <h2 className="font-bold text-white flex items-center gap-2"><ShoppingCart size={20} className="text-[#FA8072]" /> قائمة المنتجات</h2>
             <button onClick={onOpenProductManager} className="text-xs bg-gray-700 hover:bg-gray-600 text-gray-300 px-3 py-1.5 rounded-lg transition-colors">تعديل الأصناف</button>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
            {products.map(p => (
                <button key={p.id} onClick={() => addToCart(p)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-gray-700 hover:bg-gray-700 hover:border-[#FA8072] text-white rounded-2xl transition-all shadow-sm active:scale-95 h-32 relative group">
                    <div className={`absolute top-2 right-2 px-1.5 py-0.5 rounded text-[10px] font-bold ${p.unitType === 'kg' ? 'bg-yellow-400 text-black' : 'bg-blue-300 text-black'}`}>{p.unitType === 'kg' ? 'كغ' : 'قطعة'}</div>
                    <span className="font-bold text-sm text-center mb-1 group-hover:text-[#FA8072]">{p.name}</span>
                    <span className="text-xs text-gray-400 bg-gray-900/50 px-2 py-1 rounded-md">
                      {(saleType === 'wholesale' ? (p.wholesalePrice || p.price) : p.price).toLocaleString()} ل.س
                    </span>
                </button>
            ))}
            <button onClick={() => setShowCustomInput(true)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-dashed border-gray-600 hover:bg-gray-700 text-gray-400 rounded-2xl h-32"><Plus size={24} className="mb-2" /><span className="text-xs">مادة حرة</span></button>
        </div>

        {showCustomInput && (
            <div className="bg-gray-800 p-4 rounded-xl border border-[#FA8072] animate-fade-up relative">
                <button onClick={() => setShowCustomInput(false)} className="absolute left-3 top-3 text-gray-500 hover:text-white"><X size={18} /></button>
                <h4 className="text-sm font-bold text-white mb-3">إضافة مادة حرة</h4>
                <div className="grid grid-cols-1 md:grid-cols-12 gap-2">
                    <input type="text" value={customForm.name} onChange={e => setCustomForm({...customForm, name: e.target.value})} placeholder="المادة" className="md:col-span-4 bg-gray-900 border border-gray-600 text-white px-3 py-2 rounded-lg text-sm" autoFocus />
                    <input type="number" value={customForm.cost} onChange={e => setCustomForm({...customForm, cost: e.target.value})} placeholder="التكلفة" className="md:col-span-2 bg-gray-900 border border-gray-600 text-red-400 px-3 py-2 rounded-lg text-sm" />
                    <input type="number" value={customForm.price} onChange={e => setCustomForm({...customForm, price: e.target.value})} placeholder="البيع" className="md:col-span-2 bg-gray-900 border border-gray-600 text-green-400 px-3 py-2 rounded-lg text-sm" />
                    <select value={customForm.unit} onChange={e => setCustomForm({...customForm, unit: e.target.value as UnitType})} className="md:col-span-2 bg-gray-900 border border-gray-600 text-white px-2 py-2 rounded-lg text-sm"><option value="piece">قطعة</option><option value="kg">كغ</option></select>
                    <button onClick={addCustomToCart} className="md:col-span-2 bg-[#FA8072] text-white rounded-lg font-bold">إضافة</button>
                </div>
            </div>
        )}
      </div>

      <div className="lg:col-span-1">
        <div className="bg-gray-800 rounded-[2rem] border border-gray-700 shadow-2xl overflow-hidden flex flex-col h-full min-h-[550px]">
            <div className="bg-gray-900/80 p-5 border-b border-gray-700 space-y-4">
                <div className="flex justify-between items-center">
                    <h3 className="font-black text-white flex items-center gap-2"><ShoppingCart size={22} className="text-[#FA8072]" /> سلة المبيعات</h3>
                    {cart.length > 0 && <button onClick={() => setCart([])} className="text-[10px] font-black text-red-400 hover:underline">تفريغ السلة</button>}
                </div>
                <div className="grid grid-cols-2 bg-gray-700 p-1 rounded-xl">
                    <button onClick={() => setSaleType('retail')} className={`py-2 text-xs font-black rounded-lg transition-all ${saleType === 'retail' ? 'bg-white text-black shadow-sm' : 'text-gray-400'}`}>مفرق</button>
                    <button onClick={() => setSaleType('wholesale')} className={`py-2 text-xs font-black rounded-lg transition-all ${saleType === 'wholesale' ? 'bg-[#FA8072] text-white shadow-sm' : 'text-gray-400'}`}>جملة</button>
                </div>
                {saleType === 'retail' ? (
                     <input type="text" value={manualCustomerName} onChange={e => setManualCustomerName(e.target.value)} placeholder="اسم الزبون (اختياري)..." className="w-full bg-gray-800 border border-gray-700 text-white text-sm rounded-xl px-4 py-2.5 outline-none focus:border-[#FA8072]" />
                ) : (
                    <div className="flex gap-2">
                         <select value={selectedCustomerId} onChange={e => setSelectedCustomerId(e.target.value)} className={`w-full bg-gray-800 border text-white text-sm rounded-xl px-4 py-2.5 outline-none transition-all ${!selectedCustomerId && cart.length > 0 ? 'border-orange-500 animate-pulse' : 'border-gray-700 focus:border-[#FA8072]'}`}>
                            <option value="">اختر عميل الجملة...</option>
                            {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                         </select>
                        <button onClick={onOpenCustomerManager} className="bg-blue-600 text-white px-4 rounded-xl hover:bg-blue-500 transition-colors shadow-lg shadow-blue-900/20"><UserPlus size={18} /></button>
                    </div>
                )}
            </div>

            <div className="flex-grow p-4 overflow-y-auto space-y-3 custom-scrollbar">
                {!cart.length ? (
                    <div className="h-full flex flex-col items-center justify-center text-gray-700 py-10">
                        <div className="bg-gray-700/20 p-6 rounded-full mb-4">
                            <ShoppingCart size={48} className="opacity-20" />
                        </div>
                        <p className="font-bold">السلة فارغة</p>
                    </div>
                ) : (
                    cart.map(i => (
                        <div key={i.tempId} className="bg-gray-700/30 p-4 rounded-2xl flex flex-col gap-3 border border-gray-700/50 hover:border-[#FA8072]/30 transition-all">
                            <div className="flex justify-between items-start">
                                <div className="flex flex-col flex-1">
                                    <span className="text-white font-black text-sm">{i.name}</span>
                                    {editingPriceId === i.tempId ? (
                                        <div className="flex items-center gap-1 mt-1">
                                            <input 
                                                type="number" 
                                                value={tempPrice} 
                                                onChange={e => setTempPrice(e.target.value)} 
                                                onBlur={() => handleSavePrice(i.tempId)} 
                                                onKeyDown={e => e.key === 'Enter' && handleSavePrice(i.tempId)} 
                                                className="w-24 bg-gray-900 border border-[#FA8072] text-white text-xs px-2 py-1 rounded-lg" 
                                                autoFocus 
                                            />
                                            <span className="text-[10px] text-gray-500">{i.unitType === 'kg' ? '(المبلغ الكلي)' : '(سعر القطعة)'}</span>
                                        </div>
                                    ) : (
                                        <div className="mt-1 flex items-center gap-1.5 cursor-pointer group/price" onClick={() => handleStartEditPrice(i)}>
                                            <span className="text-[10px] text-gray-500">
                                              {i.unitType === 'kg' ? 'سعر الكيلو: ' : 'السعر: '}
                                              <span className="text-gray-300 font-bold tabular-nums">{i.price.toLocaleString()}</span>
                                            </span>
                                            <Edit3 size={10} className="text-[#FA8072] opacity-30 group-hover/price:opacity-100" />
                                        </div>
                                    )}
                                </div>
                                <button onClick={() => setCart(p => p.filter(it => it.tempId !== i.tempId))} className="text-gray-600 hover:text-red-500 transition-colors p-1"><Trash2 size={16} /></button>
                            </div>

                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-1 bg-gray-900/50 rounded-xl px-2 py-1.5 border border-gray-700">
                                    <button onClick={() => updateQty(i.tempId, -1)} className="text-gray-500 hover:text-white transition-colors p-1"><Minus size={14} /></button>
                                    <input 
                                        type="number" 
                                        value={i.quantity} 
                                        onChange={(e) => handleManualQtyChange(i.tempId, e.target.value)}
                                        className="w-14 bg-transparent text-white text-sm font-black text-center outline-none border-none [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
                                        step={i.unitType === 'kg' ? '0.1' : '1'}
                                    />
                                    <button onClick={() => updateQty(i.tempId, 1)} className="text-gray-500 hover:text-white transition-colors p-1"><Plus size={14} /></button>
                                </div>

                                <div className="flex flex-col items-end">
                                    <span className="text-[#FA8072] font-black text-lg tabular-nums">{(i.price * i.quantity).toLocaleString()}</span>
                                    <span className="text-[8px] text-gray-600 font-bold uppercase">إجمالي المادة</span>
                                </div>
                            </div>
                        </div>
                    ))
                )}
            </div>

            <div className="p-6 bg-gray-900/90 border-t border-gray-700 shrink-0">
                <div className="flex justify-between items-center mb-5">
                    <span className="text-gray-500 font-black text-xs uppercase tracking-widest">إجمالي السلة</span>
                    <div className="text-right">
                        <span className="text-3xl font-black text-white tabular-nums">{total.toLocaleString()}</span>
                        <span className="text-[10px] text-gray-500 font-bold mr-1">ل.س</span>
                    </div>
                </div>
                <button 
                  onClick={handleCheckout} 
                  disabled={isCheckoutDisabled} 
                  className={`w-full py-4 rounded-[1.5rem] font-black text-lg flex items-center justify-center gap-3 transition-all active:scale-[0.98] shadow-2xl ${!isCheckoutDisabled ? 'bg-green-600 text-white hover:bg-green-500 shadow-green-900/20' : 'bg-gray-700 text-gray-500 cursor-not-allowed opacity-50'}`}
                >
                  <CheckCircle size={24} /> تأكيد وحفظ الفاتورة
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, Suspense, useCallback } from 'react';
import { Header } from './components/Header';
import { POSInterface } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { Login } from './components/Login';
import { SaleItem, Product, ArchivedDay, SaleType, Customer, PurchaseInvoice, Supplier } from './types';
import { Loader2, X, ShieldCheck, Wifi, CloudDownload, CheckCircle2 } from 'lucide-react';

const InvoiceModal = React.lazy(() => import('./components/InvoiceModal').then(m => ({ default: m.InvoiceModal })));
const ProductManager = React.lazy(() => import('./components/ProductManager').then(m => ({ default: m.ProductManager })));
const HistoryModal = React.lazy(() => import('./components/HistoryModal').then(m => ({ default: m.HistoryModal })));
const DataManagementModal = React.lazy(() => import('./components/DataManagementModal').then(m => ({ default: m.DataManagementModal })));
const CustomerManager = React.lazy(() => import('./components/CustomerManager').then(m => ({ default: m.CustomerManager })));
const ExpensesModal = React.lazy(() => import('./components/ExpensesModal').then(m => ({ default: m.ExpensesModal })));
const AnalyticsModal = React.lazy(() => import('./components/AnalyticsModal').then(m => ({ default: m.AnalyticsModal })));

const ModalLoader = () => <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center"><div className="bg-gray-800 p-4 rounded-full border border-gray-700"><Loader2 className="animate-spin text-[#FA8072]" size={32} /></div></div>;

const WelcomeLoader: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(timer);
          setTimeout(onComplete, 500);
          return 100;
        }
        return prev + 5;
      });
    }, 100);
    return () => clearInterval(timer);
  }, [onComplete]);

  return (
    <div className="fixed inset-0 bg-gray-900 z-[300] flex flex-col items-center justify-center p-6 text-center overflow-hidden">
      {/* Background Decor */}
      <div className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-[#FA8072]/10 rounded-full blur-[100px] animate-pulse"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-96 h-96 bg-blue-500/10 rounded-full blur-[100px] animate-pulse"></div>

      <div className="relative z-10 max-w-sm w-full">
        <div className="mb-8 relative">
           <div className="w-24 h-24 bg-gradient-to-tr from-[#FA8072] to-orange-600 rounded-[2rem] flex items-center justify-center mx-auto shadow-2xl shadow-orange-500/20 animate-bounce">
              <ShieldCheck className="text-white" size={48} />
           </div>
           {progress === 100 && (
             <div className="absolute -right-2 -bottom-2 bg-green-500 text-white p-1 rounded-full animate-fade-up">
                <CheckCircle2 size={24} />
             </div>
           )}
        </div>

        <h2 className="text-2xl font-black text-white mb-2 animate-fade-up">أهلاً بك في مخبز كوكيز</h2>
        <p className="text-gray-400 text-sm font-bold mb-8 h-10">
          {progress < 40 && "جاري الاتصال بقاعدة البيانات المحلية..."}
          {progress >= 40 && progress < 80 && "تأمين الملفات للعمل بوضعية الأوفلاين..."}
          {progress >= 80 && progress < 100 && "مزامنة البيانات السحابية..."}
          {progress === 100 && "النظام جاهز للعمل الآن"}
        </p>

        <div className="w-full bg-gray-800 h-3 rounded-full overflow-hidden border border-gray-700 mb-4 p-0.5">
          <div 
            className="h-full bg-gradient-to-r from-[#FA8072] to-orange-500 rounded-full transition-all duration-300 ease-out shadow-lg shadow-orange-500/30"
            style={{ width: `${progress}%` }}
          ></div>
        </div>

        <div className="flex justify-between items-center px-1">
          <div className="flex items-center gap-2 text-gray-500">
             <Wifi size={14} className={progress < 100 ? "animate-pulse" : "text-green-500"} />
             <span className="text-[10px] font-black uppercase tracking-widest">OFFLINE READY</span>
          </div>
          <span className="text-[#FA8072] font-black tabular-nums">{progress}%</span>
        </div>
      </div>

      <div className="absolute bottom-10 flex items-center gap-2 text-gray-600">
          <CloudDownload size={14} />
          <span className="text-[8px] font-black uppercase tracking-[0.3em]">Downloading System Assets</span>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => sessionStorage.getItem('isAuth') === 'true');
  const [isInitializing, setIsInitializing] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date>(() => new Date());
  const [showLock, setShowLock] = useState<{ target: string } | null>(null);
  const [lockPass, setLockPass] = useState('');
  const [lockError, setLockError] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  // Core Data States
  const [sales, setSales] = useState<SaleItem[]>(() => JSON.parse(localStorage.getItem('dailySales') || '[]'));
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'));
  const [history, setHistory] = useState<ArchivedDay[]>(() => JSON.parse(localStorage.getItem('salesHistory') || '[]'));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('products') || '[]'));
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('customers') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('suppliers') || '[]'));

  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [modals, setModals] = useState({ products: false, customers: false, history: false, data: false, expenses: false, analytics: false });

  // Handle successful login transition
  const handleLoginSuccess = () => {
    sessionStorage.setItem('isAuth', 'true');
    setIsInitializing(true);
  };

  const finalizeLogin = () => {
    setIsInitializing(false);
    setIsAuthenticated(true);
  };

  // Monitor Online Status
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Persistence logic - Immediate sync to localStorage
  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
    localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
    localStorage.setItem('salesHistory', JSON.stringify(history));
    localStorage.setItem('products', JSON.stringify(products));
    localStorage.setItem('customers', JSON.stringify(customers));
    localStorage.setItem('suppliers', JSON.stringify(suppliers));
    setLastSyncTime(new Date());
  }, [sales, purchaseInvoices, history, products, customers, suppliers]);

  const handleOpenProtected = (target: string) => setShowLock({ target });

  const handleLogout = () => {
    sessionStorage.removeItem('isAuth');
    setIsAuthenticated(false);
  };

  const verifyLock = () => {
    if (lockPass === '1997') {
      if (showLock?.target === 'full_reset') {
          localStorage.clear();
          window.location.reload();
      } else if (showLock) {
          setModals(m => ({ ...m, [showLock.target]: true }));
      }
      setShowLock(null);
      setLockPass('');
      setLockError(false);
    } else {
      setLockError(true);
    }
  };

  const completeOrder = useCallback((items: any[], name?: string, id?: string, type: SaleType = 'retail') => {
      const orderId = Date.now().toString();
      const now = new Date();
      const time = now.toLocaleTimeString('ar-SY', { hour: '2-digit', minute: '2-digit' });
      const nextNum = sales.length > 0 ? Math.max(...sales.map(s => s.customerNumber || 0)) + 1 : 1;

      const finalItems: SaleItem[] = items.map(i => ({ 
        ...i, 
        id: Math.random().toString(36).substring(2, 11), 
        orderId, 
        customerNumber: nextNum, 
        customerName: name || '', 
        customerId: id || '', 
        saleType: type, 
        time 
      }));

      setSales(prev => [...prev, ...finalItems]);
  }, [sales]);

  const handleExportData = () => {
    const backup = {
      dailySales: sales,
      dailyPurchaseInvoices: purchaseInvoices,
      salesHistory: history,
      products: products,
      customers: customers,
      suppliers: suppliers,
      exportDate: new Date().toISOString()
    };
    const blob = new Blob([JSON.stringify(backup, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `cookies-backup-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportData = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = JSON.parse(e.target?.result as string);
        if (data.dailySales) setSales(data.dailySales);
        if (data.dailyPurchaseInvoices) setPurchaseInvoices(data.dailyPurchaseInvoices);
        if (data.salesHistory) setHistory(data.salesHistory);
        if (data.products) setProducts(data.products);
        if (data.customers) setCustomers(data.customers);
        if (data.suppliers) setSuppliers(data.suppliers);

        alert('تمت استعادة البيانات بنجاح.');
      } catch (err) {
        alert('خطأ في قراءة ملف النسخة الاحتياطية.');
      }
    };
    reader.readAsText(file);
  };

  if (isInitializing) return <WelcomeLoader onComplete={finalizeLogin} />;
  if (!isAuthenticated) return <Login onLogin={handleLoginSuccess} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => handleOpenProtected('history')} 
        onOpenDataManagement={() => handleOpenProtected('data')} 
        onOpenExpenses={() => handleOpenProtected('expenses')}
        onOpenAnalytics={() => handleOpenProtected('analytics')}
        onLogout={handleLogout}
        isOnline={isOnline} 
        lastSyncTime={lastSyncTime} 
        onManualSync={() => {
            setIsSyncing(true);
            setTimeout(() => setIsSyncing(false), 800);
        }} 
        onQuickBackup={handleExportData} 
        isSyncing={isSyncing}
      />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />

        <POSInterface 
            onCompleteOrder={completeOrder} 
            products={products} 
            customers={customers} 
            onOpenProductManager={() => setModals(m => ({...m, products: true}))} 
            onOpenCustomerManager={() => setModals(m => ({...m, customers: true}))} 
        />

        <div className="mt-8">
            <SalesTable 
                items={sales} 
                onDeleteItem={id => setSales(s => s.filter(i => i.id !== id))} 
                onDeleteOrder={oid => setSales(s => s.filter(i => i.orderId !== oid))} 
                onPreviewInvoice={setInvoiceItems}
                onUpdateItemPrice={(id, p) => setSales(s => s.map(i => i.id === id ? {...i, price: p} : i))}
            />
        </div>
      </main>

      <footer className="mt-12 py-8 border-t border-gray-800/50 text-center no-print">
         <button onClick={() => handleOpenProtected('full_reset')} className="text-gray-700 text-[10px] font-bold tracking-widest uppercase">نظام مبيعات كوكيز v2.5 • 2026</button>
      </footer>

      <Suspense fallback={<ModalLoader />}>
        {modals.analytics && <AnalyticsModal history={history} currentSales={sales} currentPurchases={purchaseInvoices} onClose={() => setModals(m => ({ ...m, analytics: false }))} />}
        {modals.expenses && (
            <ExpensesModal 
                isOpen={modals.expenses} 
                onClose={() => setModals(m => ({...m, expenses: false}))} 
                currentPurchases={purchaseInvoices} 
                archivedHistory={history} 
                onAddInvoice={v => setPurchaseInvoices(p => [...p, v])} 
                onUpdateInvoice={v => setPurchaseInvoices(p => p.map(inv => inv.id === v.id ? v : inv))}
                onDeleteInvoice={id => setPurchaseInvoices(p => p.filter(v => v.id !== id))} 
                suppliers={suppliers} 
                onAddSupplier={s => setSuppliers(p => [...p, {...s, id: Date.now().toString()}])} 
                onDeleteSupplier={id => setSuppliers(p => p.filter(s => s.id !== id))} 
            />
        )}
        {modals.history && (
            <HistoryModal 
                history={history} 
                currentSales={sales} 
                onClose={() => setModals(m => ({...m, history: false}))} 
                onClearHistory={() => setHistory([])} 
                onPreviewInvoice={setInvoiceItems} 
                onUpdateOrder={(d, o, i) => setHistory(h => h.map(day => day.date === d ? {...day, items: day.items.map(item => item.orderId === o ? i.find(x => x.id === item.id) || item : item)} : day))} 
            />
        )}
        {modals.products && <ProductManager isOpen={modals.products} onClose={() => setModals(m => ({...m, products: false}))} products={products} onAddProduct={p => setProducts(s => [...s, {...p, id: Date.now().toString()}])} onUpdateProduct={(id, u) => setProducts(s => s.map(p => p.id === id ? {...p, ...u} : p))} onDeleteProduct={id => setProducts(s => s.filter(p => p.id !== id))} />}
        {modals.customers && <CustomerManager isOpen={modals.customers} onClose={() => setModals(m => ({...m, customers: false}))} customers={customers} onAddCustomer={c => setCustomers(s => [...s, {...c, id: Date.now().toString()}])} onDeleteCustomer={id => setCustomers(s => s.filter(c => c.id !== id))} />}
        {modals.data && <DataManagementModal onClose={() => setModals(m => ({...m, data: false}))} onExport={handleExportData} onImport={handleImportData} />}
        {invoiceItems && <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />}
      </Suspense>

      {showLock && (
        <div className="fixed inset-0 bg-black/90 z-[200] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-gray-800 border border-gray-700 p-6 rounded-3xl w-full max-w-xs shadow-2xl animate-fade-up relative">
            <button onClick={() => { setShowLock(null); setLockPass(''); setLockError(false); }} className="absolute top-4 left-4 text-gray-500 hover:text-white transition-colors"><X size={20} /></button>
            <div className="text-center mb-6">
                <div className="w-12 h-12 bg-[#FA8072]/20 rounded-full flex items-center justify-center mx-auto mb-3"><Loader2 className="text-[#FA8072] animate-pulse" size={24} /></div>
                <h3 className="text-white font-black text-lg">تأكيد الإجراء</h3>
                <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest mt-1">يرجى إدخال رمز التحقق (1997)</p>
            </div>
            <input type="password" value={lockPass} onChange={e => setLockPass(e.target.value)} placeholder="رمز الدخول" className={`w-full bg-gray-900 border ${lockError ? 'border-red-500' : 'border-gray-700'} text-white p-4 rounded-2xl mb-4 text-center outline-none focus:border-[#FA8072] text-xl tracking-widest`} autoFocus onKeyDown={e => e.key === 'Enter' && verifyLock()} />
            {lockError && <p className="text-red-500 text-[10px] text-center mb-4 font-bold animate-pulse">رمز الدخول غير صحيح!</p>}
            <button onClick={verifyLock} className="w-full bg-gradient-to-r from-[#FA8072] to-orange-600 text-white py-4 rounded-2xl font-black text-sm shadow-lg shadow-orange-900/20 active:scale-95 transition-all">تأكيد الإجراء</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo, Suspense } from 'react';
import { Plus, Trash2, X, ShoppingCart, UserPlus, Printer, FileText, Store, Folder, CalendarDays, ArrowRight, Zap, ChevronDown, ChevronUp, Edit3, RotateCcw } from 'lucide-react';
import { PurchaseInvoice, PurchaseItem, ArchivedDay, PaymentStatus, Supplier } from '../types';

const PurchasePrintModal = React.lazy(() => import('./PurchasePrintModal').then(module => ({ default: module.PurchasePrintModal })));

interface ExpensesModalProps {
  currentPurchases: PurchaseInvoice[];
  archivedHistory: ArchivedDay[]; 
  onAddInvoice: (invoice: PurchaseInvoice) => void;
  onUpdateInvoice: (invoice: PurchaseInvoice) => void;
  onDeleteInvoice: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
  suppliers: Supplier[];
  onAddSupplier: (supplier: Omit<Supplier, 'id'>) => void;
  onDeleteSupplier: (id: string) => void;
}

type NavStep = 'years' | 'months' | 'days';

export const ExpensesModal: React.FC<ExpensesModalProps> = ({ 
  currentPurchases, archivedHistory, onAddInvoice, onUpdateInvoice, onDeleteInvoice, isOpen, onClose, suppliers = [], onAddSupplier, onDeleteSupplier
}) => {
  const [activeTab, setActiveTab] = useState<'new' | 'history' | 'suppliers'>('new');
  const [selectedSupplierId, setSelectedSupplierId] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('paid'); 
  const [itemInputs, setItemInputs] = useState({ name: '', quantity: '', unitPrice: '' });
  const [currentInvoiceItems, setCurrentInvoiceItems] = useState<PurchaseItem[]>([]);
  const [invoiceToPrint, setInvoiceToPrint] = useState<PurchaseInvoice | null>(null);
  const [newSup, setNewSup] = useState({ name: '', phone: '' });
  const [editingInvoiceId, setEditingInvoiceId] = useState<string | null>(null);

  // Navigation state for History Tab
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);

  const fullHistory = useMemo(() => {
    const merged = [...archivedHistory];
    if (currentPurchases.length > 0) {
        const today = new Date();
        const todayStr = today.toLocaleDateString('ar-SY');
        const existingTodayIdx = merged.findIndex(d => d.date.includes(todayStr));

        const todayEntry: ArchivedDay = {
            id: 'today-active-purchases',
            date: `${todayStr} (مباشر)`,
            timestamp: Date.now(),
            totalRevenue: 0,
            totalExpenses: currentPurchases.reduce((s, i) => s + i.totalAmount, 0),
            totalItems: 0,
            items: [],
            purchaseInvoices: currentPurchases
        };

        if (existingTodayIdx > -1) merged[existingTodayIdx] = { ...merged[existingTodayIdx], purchaseInvoices: [...(merged[existingTodayIdx].purchaseInvoices || []), ...currentPurchases] };
        else merged.push(todayEntry);
    }
    return merged;
  }, [archivedHistory, currentPurchases]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(fullHistory.filter(d => (d.purchaseInvoices || []).length > 0).map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [fullHistory]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      fullHistory
        .filter(day => (day.purchaseInvoices || []).length > 0 && new Date(day.timestamp).getFullYear().toString() === selectedYear)
        .map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [fullHistory, selectedYear]);

  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return fullHistory.filter(day => {
      const d = new Date(day.timestamp);
      return (day.purchaseInvoices || []).length > 0 && d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    }).sort((a,b) => b.timestamp - a.timestamp);
  }, [fullHistory, selectedYear, selectedMonth]);

  const getMonthName = (monthIndex: number) => {
    return new Date(2000, monthIndex).toLocaleString('ar-SY', { month: 'long' });
  };

  const addItem = () => {
      if (!itemInputs.name || !itemInputs.quantity || !itemInputs.unitPrice) return;
      const q = parseFloat(itemInputs.quantity); 
      const price = parseFloat(itemInputs.unitPrice);
      setCurrentInvoiceItems(prev => [...prev, { id: Date.now().toString(), name: itemInputs.name, quantity: q, cost: price, total: q * price }]);
      setItemInputs({ name: '', quantity: '', unitPrice: '' });
  };

  const handleSaveInvoice = () => {
      const supplier = suppliers.find(s => s.id === selectedSupplierId || s.name === selectedSupplierId);
      if (!supplier || currentInvoiceItems.length === 0) return alert('يرجى تحديد مورد وإضافة مواد للفاتورة');

      const totalAmount = currentInvoiceItems.reduce((sum, item) => sum + item.total, 0);

      const invoiceData: PurchaseInvoice = { 
          id: editingInvoiceId || Date.now().toString(), 
          supplierName: supplier.name, 
          date: new Date().toLocaleDateString('ar-SY'), 
          timestamp: Date.now(), 
          items: currentInvoiceItems, 
          totalAmount, 
          paymentStatus 
      };

      if (editingInvoiceId) {
          onUpdateInvoice(invoiceData);
          setEditingInvoiceId(null);
      } else {
          onAddInvoice(invoiceData);
      }

      setSelectedSupplierId(''); 
      setCurrentInvoiceItems([]); 
      setActiveTab('history');
      setStep('years');
  };

  const startEditInvoice = (inv: PurchaseInvoice) => {
      const supplier = suppliers.find(s => s.name === inv.supplierName);
      setEditingInvoiceId(inv.id);
      setSelectedSupplierId(supplier?.id || inv.supplierName);
      setPaymentStatus(inv.paymentStatus);
      setCurrentInvoiceItems(inv.items);
      setActiveTab('new');
  };

  const cancelEdit = () => {
      setEditingInvoiceId(null);
      setSelectedSupplierId('');
      setCurrentInvoiceItems([]);
      setPaymentStatus('paid');
  };

  const renderHistoryContent = () => {
    if (step === 'years') return (
        <div className="grid grid-cols-2 gap-4 animate-fade-up">
            {years.length > 0 ? years.map(year => (
                <button key={year} onClick={() => { setSelectedYear(year); setStep('months'); }} className="bg-gray-900/40 hover:bg-gray-700/50 border border-gray-700 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <Folder size={40} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                    <span className="text-lg font-black text-white">{year}</span>
                </button>
            )) : (
              <div className="col-span-full py-20 text-center flex flex-col items-center gap-4">
                  <div className="bg-gray-900/30 p-6 rounded-full"><Zap size={48} className="text-gray-700" /></div>
                  <p className="text-gray-500 font-bold">لا توجد مشتريات مؤرشفة</p>
              </div>
            )}
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => { setSelectedMonth(monthIdx); setStep('days'); }} className="bg-gray-900/40 hover:bg-gray-700/50 border border-gray-700 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <CalendarDays size={40} className="text-blue-400 group-hover:scale-110 transition-transform" />
                    <span className="text-lg font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-3 animate-fade-up h-full">
            <div className="flex-1 overflow-y-auto space-y-2 pr-1 custom-scrollbar">
                {currentDaysData.map(day => {
                    const isToday = day.id === 'today-active-purchases';
                    return (
                        <div key={day.id} className={`rounded-xl border overflow-hidden transition-all ${isToday ? 'border-orange-500/30 bg-orange-500/5' : 'border-gray-700 bg-gray-900/20'}`}>
                            <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className={`p-4 flex justify-between items-center cursor-pointer ${isToday ? 'bg-orange-500/10' : 'bg-gray-900/50 hover:bg-gray-900'}`}>
                                <div className="flex items-center gap-3">
                                    <div className="text-gray-500">{expandedDayId === day.id ? <ChevronUp size={16} /> : <ChevronDown size={16} />}</div>
                                    <span className={`font-bold text-sm ${isToday ? 'text-orange-400' : 'text-white'}`}>{day.date}</span>
                                </div>
                                <span className="font-black text-red-400">{(day.purchaseInvoices || []).reduce((s,i) => s + i.totalAmount, 0).toLocaleString()} <small className="text-[9px] text-gray-600 font-normal">ل.س</small></span>
                            </div>

                            {expandedDayId === day.id && (
                                <div className="p-3 bg-black/20 border-t border-gray-700 animate-fade-up space-y-2">
                                    {(day.purchaseInvoices || []).map((inv) => (
                                        <div key={inv.id} className="bg-gray-800 p-3 rounded-xl border border-gray-700 flex justify-between items-center group">
                                            <div className="flex items-center gap-3">
                                                <div className="bg-gray-900 p-1.5 rounded text-red-400"><Store size={14} /></div>
                                                <div className="flex flex-col">
                                                    <span className="text-white text-xs font-bold">{inv.supplierName}</span>
                                                    <span className="text-[9px] text-gray-500">{inv.paymentStatus === 'paid' ? 'نقدي' : 'آجل'} • {inv.items.length} مواد</span>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-1.5">
                                                <span className="text-white font-bold text-xs ml-2">{inv.totalAmount.toLocaleString()}</span>
                                                <button onClick={() => setInvoiceToPrint(inv)} className="p-1.5 bg-gray-700 rounded hover:bg-blue-600 text-white transition-colors" title="طباعة"><Printer size={12}/></button>
                                                <button onClick={() => startEditInvoice(inv)} className="p-1.5 bg-gray-700 rounded hover:bg-yellow-600 text-white transition-colors" title="تعديل"><Edit3 size={12}/></button>
                                                <button onClick={() => onDeleteInvoice(inv.id)} className="p-1.5 text-gray-500 hover:text-red-500 transition-colors" title="حذف"><Trash2 size={12}/></button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
  };

  if (!isOpen) return null;

  return (
    <>
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-[2rem] w-full max-w-2xl shadow-2xl border border-gray-700 flex flex-col h-[85vh] overflow-hidden">

        <div className="p-5 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 shrink-0">
          <div className="flex items-center gap-3">
            {activeTab === 'history' && step !== 'years' && (
                <button onClick={() => {
                    if (step === 'days') { setStep('months'); setSelectedMonth(-1); } 
                    else if (step === 'months') { setStep('years'); setSelectedYear(''); }
                }} className="bg-gray-700 hover:bg-[#FA8072] p-1.5 rounded-full text-white transition-colors"><ArrowRight size={18} /></button>
            )}
            <div className="flex items-center gap-2 text-white">
                <ShoppingCart size={22} className="text-[#FA8072]" />
                <h3 className="font-black text-xl">إدارة المشتريات</h3>
            </div>
          </div>
          <div className="flex items-center gap-2">
              <button onClick={onClose} className="hidden md:flex items-center gap-2 bg-gray-700 hover:bg-red-600 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all">
                  <span>خروج</span>
                  <X size={18} />
              </button>
              <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full text-gray-400 md:hidden"><X size={24} /></button>
          </div>
        </div>

        <div className="flex border-b border-gray-700 bg-gray-900/30">
            <button onClick={() => setActiveTab('new')} className={`flex-1 py-4 text-xs font-black transition-all ${activeTab === 'new' ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500 hover:bg-gray-800'}`}>
              {editingInvoiceId ? 'تعديل الفاتورة' : 'فاتورة جديدة'}
            </button>
            <button onClick={() => { setActiveTab('history'); setStep('years'); }} className={`flex-1 py-4 text-xs font-black transition-all ${activeTab === 'history' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-800'}`}>سجل المشتريات</button>
            <button onClick={() => setActiveTab('suppliers')} className={`flex-1 py-4 text-xs font-black transition-all ${activeTab === 'suppliers' ? 'bg-gray-700 text-white' : 'text-gray-500 hover:bg-gray-800'}`}>قائمة الموردين</button>
        </div>

        <div className="p-6 overflow-y-auto flex-1 custom-scrollbar">
          {activeTab === 'new' ? (
              <div className="space-y-6">
                  {editingInvoiceId && (
                    <div className="bg-yellow-500/10 border border-yellow-500/20 p-3 rounded-xl flex items-center justify-between">
                        <span className="text-yellow-500 text-xs font-bold flex items-center gap-2">
                           <Edit3 size={14} /> أنت الآن في وضع تعديل فاتورة قديمة
                        </span>
                        <button onClick={cancelEdit} className="text-[10px] bg-gray-700 text-white px-3 py-1 rounded-lg flex items-center gap-1">
                           <RotateCcw size={10} /> إلغاء التعديل
                        </button>
                    </div>
                  )}

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 font-black uppercase pr-1">تحديد المورد:</label>
                        <select value={selectedSupplierId} onChange={e => setSelectedSupplierId(e.target.value)} className={`w-full bg-gray-900 border rounded-xl px-4 py-3 text-white text-sm outline-none transition-all ${!selectedSupplierId && suppliers.length > 0 ? 'border-orange-500' : 'border-gray-700 focus:border-[#FA8072]'}`}>
                            <option value="">اختر مورد...</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                    <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 font-black uppercase pr-1">حالة الدفع:</label>
                        <div className="flex bg-gray-900 p-1 rounded-xl border border-gray-700">
                            <button onClick={() => setPaymentStatus('paid')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${paymentStatus === 'paid' ? 'bg-green-600 text-white shadow-md' : 'text-gray-500'}`}>نقدي</button>
                            <button onClick={() => setPaymentStatus('credit')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${paymentStatus === 'credit' ? 'bg-orange-600 text-white shadow-md' : 'text-gray-500'}`}>آجل</button>
                        </div>
                    </div>
                  </div>

                  <div className="bg-gray-900/40 p-5 rounded-2xl border border-gray-700 space-y-4">
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                          <input type="text" value={itemInputs.name} onChange={e => setItemInputs({...itemInputs, name: e.target.value})} placeholder="المادة المشتراة" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-sm" />
                          <input type="number" value={itemInputs.quantity} onChange={e => setItemInputs({...itemInputs, quantity: e.target.value})} placeholder="الكمية" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-sm text-center font-bold" />
                          <input type="number" value={itemInputs.unitPrice} onChange={e => setItemInputs({...itemInputs, unitPrice: e.target.value})} placeholder="سعر التكلفة" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-[#FA8072] text-sm text-center font-bold" />
                      </div>
                      <button onClick={addItem} className="w-full bg-gray-700 hover:bg-[#FA8072] text-white py-3 rounded-xl font-black text-xs flex items-center justify-center gap-2 transition-all active:scale-95"><Plus size={18}/> إضافة بند للفاتورة</button>
                  </div>

                  <div className="bg-gray-950/30 border border-gray-700 rounded-2xl overflow-hidden shadow-inner">
                      <table className="w-full text-xs text-right">
                          <thead className="bg-gray-900 text-gray-500">
                              <tr><th className="p-3">الصنف</th><th className="p-3 text-center">الكمية</th><th className="p-3">الإجمالي</th><th className="p-3 w-8"></th></tr>
                          </thead>
                          <tbody className="divide-y divide-gray-800">
                              {currentInvoiceItems.map(item => (
                                  <tr key={item.id} className="hover:bg-gray-800/50"><td className="p-3 text-white font-medium">{item.name}</td><td className="p-3 text-center text-gray-400 font-bold">{item.quantity}</td><td className="p-3 text-[#FA8072] font-black">{item.total.toLocaleString()}</td><td className="p-3"><button onClick={() => setCurrentInvoiceItems(s => s.filter(i => i.id !== item.id))} className="text-gray-600 hover:text-red-500 transition-colors"><Trash2 size={16}/></button></td></tr>
                              ))}
                              {currentInvoiceItems.length === 0 && <tr><td colSpan={4} className="p-10 text-center text-gray-600 italic">لا توجد مواد في هذه الفاتورة</td></tr>}
                          </tbody>
                      </table>
                  </div>

                  <div className="flex items-center justify-between pt-6 border-t border-gray-700">
                      <div className="flex flex-col">
                        <span className="text-[10px] text-gray-500 font-black uppercase tracking-widest mb-1">إجمالي الفاتورة</span>
                        <div className="text-3xl font-black text-red-500">{currentInvoiceItems.reduce((s,i) => s + i.total, 0).toLocaleString()} <span className="text-xs text-gray-500 font-normal">ل.س</span></div>
                      </div>
                      <div className="flex gap-2">
                        {editingInvoiceId && (
                           <button onClick={cancelEdit} className="bg-gray-700 hover:bg-gray-600 text-white px-6 py-4 rounded-2xl font-black text-sm active:scale-95 transition-all">إلغاء</button>
                        )}
                        <button onClick={handleSaveInvoice} className="bg-green-600 hover:bg-green-500 text-white px-8 py-4 rounded-2xl font-black text-sm flex items-center gap-3 shadow-xl shadow-green-900/20 active:scale-95 transition-all">
                          <FileText size={20} /> {editingInvoiceId ? 'تحديث الفاتورة' : 'حفظ الفاتورة'}
                        </button>
                      </div>
                  </div>
              </div>
          ) : activeTab === 'suppliers' ? (
              <div className="space-y-8">
                  <div className="bg-gray-900/40 p-6 rounded-2xl border border-gray-700 space-y-4">
                      <h4 className="text-white font-black text-sm">إضافة مورد جديد للنظام</h4>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                          <input type="text" value={newSup.name} onChange={e => setNewSup({...newSup, name: e.target.value})} placeholder="اسم المورد أو الشركة" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-sm" />
                          <input type="text" value={newSup.phone} onChange={e => setNewSup({...newSup, phone: e.target.value})} placeholder="رقم الهاتف" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-sm dir-ltr text-right" />
                      </div>
                      <button onClick={() => { if(!newSup.name) return; onAddSupplier(newSup); setNewSup({name:'', phone:''}); }} className="w-full bg-[#FA8072] text-white py-3.5 rounded-xl font-black text-xs flex items-center justify-center gap-2 shadow-lg active:scale-95 transition-all"><UserPlus size={18}/> إضافة مورد</button>
                  </div>

                  <div className="space-y-3">
                      <h4 className="text-gray-500 font-black text-[10px] uppercase tracking-widest pl-2">الموردين المسجلين ({suppliers.length})</h4>
                      <div className="grid gap-3">
                        {suppliers.map(s => (
                            <div key={s.id} className="bg-gray-900/40 p-4 rounded-[1.5rem] border border-gray-700 flex justify-between items-center group hover:border-[#FA8072]/50 transition-all">
                                <div className="flex items-center gap-4">
                                    <div className="bg-gray-800 p-3 rounded-2xl text-[#FA8072] group-hover:scale-110 transition-transform"><Store size={20} /></div>
                                    <div className="flex flex-col"><span className="text-white font-black text-sm">{s.name}</span><span className="text-[10px] text-gray-500 font-bold">{s.phone || 'بدون رقم هاتف'}</span></div>
                                </div>
                                <button onClick={() => onDeleteSupplier(s.id)} className="text-gray-600 hover:text-red-400 p-2 transition-colors"><Trash2 size={20}/></button>
                            </div>
                        ))}
                      </div>
                      {suppliers.length === 0 && <p className="text-center py-10 text-gray-700 text-sm italic">لا يوجد موردين مضافين حالياً</p>}
                  </div>
              </div>
          ) : (
              <div className="h-full">
                  {renderHistoryContent()}
              </div>
          )}
        </div>
      </div>
    </div>
    {invoiceToPrint && <Suspense fallback={null}><PurchasePrintModal invoice={invoiceToPrint} onClose={() => setInvoiceToPrint(null)} /></Suspense>}
    </>
  );
};

import React, { useState, useEffect, Suspense, useCallback } from 'react';
import { Header } from './components/Header';
