const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => sessionStorage.getItem('isAuth') === 'true');
  const [isInitializing, setIsInitializing] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date>(() => new Date());
  const [showLock, setShowLock] = useState<{ target: string } | null>(null);
  const [lockPass, setLockPass] = useState('');
  const [lockError, setLockError] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const [sales, setSales] = useState<SaleItem[]>(() => JSON.parse(localStorage.getItem('dailySales') || '[]'));
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'));
  const [history, setHistory] = useState<ArchivedDay[]>(() => JSON.parse(localStorage.getItem('salesHistory') || '[]'));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('products') || '[]'));
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('customers') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('suppliers') || '[]'));

  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [modals, setModals] = useState({ products: false, customers: false, history: false, data: false, expenses: false, analytics: false });

  const handleLoginSuccess = () => {
    sessionStorage.setItem('isAuth', 'true');
    setIsInitializing(true);
  };

  const finalizeLogin = () => {
    setIsInitializing(false);
    setIsAuthenticated(true);
  };

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
    localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
    localStorage.setItem('salesHistory', JSON.stringify(history));
    localStorage.setItem('products', JSON.stringify(products));
    localStorage.setItem('customers', JSON.stringify(customers));
    localStorage.setItem('suppliers', JSON.stringify(suppliers));
    setLastSyncTime(new Date());
  }, [sales, purchaseInvoices, history, products, customers, suppliers]);

  // منطق تحديث المنتج تلقائياً في كل مكان
  const handleUpdateProduct = (id: string, updatedFields: Partial<Product>) => {
    const oldProduct = products.find(p => p.id === id);
    if (!oldProduct) return;

    // تحديث قائمة المنتجات
    setProducts(prev => prev.map(p => p.id === id ? { ...p, ...updatedFields } : p));

    // إذا تغير الاسم، نقوم بتحديثه في كل الفواتير
    if (updatedFields.name && updatedFields.name !== oldProduct.name) {
      const oldName = oldProduct.name;
      const newName = updatedFields.name;

      // 1. المبيعات الحالية
      setSales(prev => prev.map(item => item.name === oldName ? { ...item, name: newName } : item));

      // 2. المشتريات الحالية
      setPurchaseInvoices(prev => prev.map(inv => ({
        ...inv,
        items: inv.items.map(item => item.name === oldName ? { ...item, name: newName } : item)
      })));

      // 3. الأرشيف
      setHistory(prev => prev.map(day => ({
        ...day,
        items: day.items.map(item => item.name === oldName ? { ...item, name: newName } : item),
        purchaseInvoices: (day.purchaseInvoices || []).map(inv => ({
          ...inv,
          items: inv.items.map(item => item.name === oldName ? { ...item, name: newName } : item)
        }))
      })));
    }
  };

  const handleOpenProtected = (target: string) => setShowLock({ target });

  const handleLogout = () => {
    sessionStorage.removeItem('isAuth');
    setIsAuthenticated(false);
  };

  const verifyLock = () => {
    if (lockPass === '1997') {
      if (showLock?.target === 'full_reset') {
          localStorage.clear();
          window.location.reload();
      } else if (showLock) {
          setModals(m => ({ ...m, [showLock.target]: true }));
      }
      setShowLock(null);
      setLockPass('');
      setLockError(false);
    } else {
      setLockError(true);
    }
  };

  const completeOrder = useCallback((items: any[], name?: string, id?: string, type: SaleType = 'retail') => {
      const orderId = Date.now().toString();
      const now = new Date();
      const time = now.toLocaleTimeString('ar-SY', { hour: '2-digit', minute: '2-digit' });
      const nextNum = sales.length > 0 ? Math.max(...sales.map(s => s.customerNumber || 0)) + 1 : 1;

      const finalItems: SaleItem[] = items.map(i => ({ 
        ...i, 
        id: Math.random().toString(36).substring(2, 11), 
        orderId, 
        customerNumber: nextNum, 
        customerName: name || '', 
        customerId: id || '', 
        saleType: type, 
        time 
      }));

      setSales(prev => [...prev, ...finalItems]);
  }, [sales]);

  const handleExportData = () => {
    const backup = { dailySales: sales, dailyPurchaseInvoices: purchaseInvoices, salesHistory: history, products, customers, suppliers, exportDate: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(backup, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `cookies-backup-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportData = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = JSON.parse(e.target?.result as string);
        if (data.dailySales) setSales(data.dailySales);
        if (data.dailyPurchaseInvoices) setPurchaseInvoices(data.dailyPurchaseInvoices);
        if (data.salesHistory) setHistory(data.salesHistory);
        if (data.products) setProducts(data.products);
        if (data.customers) setCustomers(data.customers);
        if (data.suppliers) setSuppliers(data.suppliers);
        alert('تمت استعادة البيانات بنجاح.');
      } catch (err) { alert('خطأ في قراءة ملف النسخة الاحتياطية.'); }
    };
    reader.readAsText(file);
  };

  if (isInitializing) return <WelcomeLoader onComplete={finalizeLogin} />;
  if (!isAuthenticated) return <Login onLogin={handleLoginSuccess} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => handleOpenProtected('history')} 
        onOpenDataManagement={() => handleOpenProtected('data')} 
        onOpenExpenses={() => handleOpenProtected('expenses')}
        onOpenAnalytics={() => handleOpenProtected('analytics')}
        onLogout={handleLogout}
        isOnline={isOnline} 
        lastSyncTime={lastSyncTime} 
        onManualSync={() => { setIsSyncing(true); setTimeout(() => setIsSyncing(false), 800); }} 
        onQuickBackup={handleExportData} 
        isSyncing={isSyncing}
      />
      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />
        <POSInterface products={products} customers={customers} onCompleteOrder={completeOrder} onOpenProductManager={() => setModals(m => ({...m, products: true}))} onOpenCustomerManager={() => setModals(m => ({...m, customers: true}))} />
        <div className="mt-8">
            <SalesTable items={sales} onDeleteItem={id => setSales(s => s.filter(i => i.id !== id))} onDeleteOrder={oid => setSales(s => s.filter(i => i.orderId !== oid))} onPreviewInvoice={setInvoiceItems} onUpdateItemPrice={(id, p) => setSales(s => s.map(i => i.id === id ? {...i, price: p} : i))} />
        </div>
      </main>
      <footer className="mt-12 py-8 border-t border-gray-800/50 text-center no-print">
         <button onClick={() => handleOpenProtected('full_reset')} className="text-gray-700 text-[10px] font-bold tracking-widest uppercase">نظام مبيعات كوكيز v2.5 • 2026</button>
      </footer>
      <Suspense fallback={<ModalLoader />}>
        {modals.analytics && <AnalyticsModal history={history} currentSales={sales} currentPurchases={purchaseInvoices} onClose={() => setModals(m => ({ ...m, analytics: false }))} />}
        {modals.expenses && <ExpensesModal isOpen={modals.expenses} onClose={() => setModals(m => ({...m, expenses: false}))} currentPurchases={purchaseInvoices} archivedHistory={history} onAddInvoice={v => setPurchaseInvoices(p => [...p, v])} onUpdateInvoice={v => setPurchaseInvoices(p => p.map(inv => inv.id === v.id ? v : inv))} onDeleteInvoice={id => setPurchaseInvoices(p => p.filter(v => v.id !== id))} suppliers={suppliers} onAddSupplier={s => setSuppliers(p => [...p, {...s, id: Date.now().toString()}])} onDeleteSupplier={id => setSuppliers(p => p.filter(s => s.id !== id))} />}
        {modals.history && <HistoryModal history={history} currentSales={sales} onClose={() => setModals(m => ({...m, history: false}))} onClearHistory={() => setHistory([])} onPreviewInvoice={setInvoiceItems} onUpdateOrder={(d, o, i) => setHistory(h => h.map(day => day.date === d ? {...day, items: day.items.map(item => item.orderId === o ? i.find(x => x.id === item.id) || item : item)} : day))} />}
        {modals.products && <ProductManager isOpen={modals.products} onClose={() => setModals(m => ({...m, products: false}))} products={products} onAddProduct={p => setProducts(s => [...s, {...p, id: Date.now().toString()}])} onUpdateProduct={handleUpdateProduct} onDeleteProduct={id => setProducts(s => s.filter(p => p.id !== id))} />}
        {modals.customers && <CustomerManager isOpen={modals.customers} onClose={() => setModals(m => ({...m, customers: false}))} customers={customers} onAddCustomer={c => setCustomers(s => [...s, {...c, id: Date.now().toString()}])} onDeleteCustomer={id => setCustomers(s => s.filter(c => c.id !== id))} />}
        {modals.data && <DataManagementModal onClose={() => setModals(m => ({...m, data: false}))} onExport={handleExportData} onImport={handleImportData} />}
        {invoiceItems && <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />}
      </Suspense>
      {showLock && (
        <div className="fixed inset-0 bg-black/90 z-[200] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-gray-800 border border-gray-700 p-6 rounded-3xl w-full max-w-xs shadow-2xl animate-fade-up relative">
            <button onClick={() => { setShowLock(null); setLockPass(''); setLockError(false); }} className="absolute top-4 left-4 text-gray-500 hover:text-white transition-colors"><X size={20} /></button>
            <div className="text-center mb-6">
                <div className="w-12 h-12 bg-[#FA8072]/20 rounded-full flex items-center justify-center mx-auto mb-3"><Loader2 className="text-[#FA8072] animate-pulse" size={24} /></div>
                <h3 className="text-white font-black text-lg">تأكيد الإجراء</h3>
                <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest mt-1">يرجى إدخال رمز التحقق (1997)</p>
            </div>
            <input type="password" value={lockPass} onChange={e => setLockPass(e.target.value)} placeholder="رمز الدخول" className={`w-full bg-gray-900 border ${lockError ? 'border-red-500' : 'border-gray-700'} text-white p-4 rounded-2xl mb-4 text-center outline-none focus:border-[#FA8072] text-xl tracking-widest`} autoFocus onKeyDown={e => e.key === 'Enter' && verifyLock()} />
            {lockError && <p className="text-red-500 text-[10px] text-center mb-4 font-bold animate-pulse">رمز الدخول غير صحيح!</p>}
            <button onClick={verifyLock} className="w-full bg-gradient-to-r from-[#FA8072] to-orange-600 text-white py-4 rounded-2xl font-black text-sm shadow-lg shadow-orange-900/20 active:scale-95 transition-all">تأكيد الإجراء</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { X, ChevronDown, ChevronUp, ArrowRight, Folder, CalendarDays, ShoppingBag, Zap, Store, User, Filter, TrendingUp, PieChart, Info, Clock, Download } from 'lucide-react';
import { ArchivedDay, SaleItem, SaleType } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  currentSales?: SaleItem[];
  onClose: () => void;
  onClearHistory: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateOrder: (date: string, orderId: string, updatedItems: SaleItem[]) => void;
}

type NavStep = 'years' | 'months' | 'days';
type FilterType = 'all' | SaleType;
type TabMode = 'archive' | 'profit-report';

export const HistoryModal: React.FC<HistoryModalProps> = ({ 
  history, currentSales = [], onClose, onClearHistory, onPreviewInvoice, onUpdateOrder 
}) => {
  const [tab, setTab] = useState<TabMode>('archive');
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);
  const [filterType, setFilterType] = useState<FilterType>('all');

  const fullHistory = useMemo(() => {
      const merged = [...history];
      if (currentSales.length > 0) {
          const today = new Date();
          const todayStr = today.toLocaleDateString('ar-SY');
          const existingTodayIdx = merged.findIndex(d => d.date.includes(todayStr));

          const todayEntry: ArchivedDay = {
              id: 'today-active',
              date: `${todayStr} (مبيعات حية)`,
              timestamp: Date.now(),
              totalRevenue: currentSales.reduce((s, i) => s + (i.price * i.quantity), 0),
              totalExpenses: 0,
              totalItems: currentSales.length,
              items: currentSales,
              purchaseInvoices: []
          };

          if (existingTodayIdx > -1) merged[existingTodayIdx] = todayEntry;
          else merged.push(todayEntry);
      }
      return merged;
  }, [history, currentSales]);

  const profitReport = useMemo(() => {
    const report: Record<string, { today: number, month: number, year: number, total: number }> = {};
    const now = new Date();
    const currentYear = now.getFullYear();
    const currentMonth = now.getMonth();
    const todayStr = now.toLocaleDateString('ar-SY');

    fullHistory.forEach(day => {
        const d = new Date(day.timestamp);
        const isYear = d.getFullYear() === currentYear;
        const isMonth = isYear && d.getMonth() === currentMonth;
        const isToday = day.date.includes(todayStr);

        day.items.forEach(item => {
            const profitPerUnit = item.price - (item.costPrice || 0);
            const totalProfit = profitPerUnit * item.quantity;
            if (!report[item.name]) report[item.name] = { today: 0, month: 0, year: 0, total: 0 };
            report[item.name].total += totalProfit;
            if (isYear) report[item.name].year += totalProfit;
            if (isMonth) report[item.name].month += totalProfit;
            if (isToday) report[item.name].today += totalProfit;
        });
    });
    return Object.entries(report).sort((a, b) => b[1].total - a[1].total);
  }, [fullHistory]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(fullHistory.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [fullHistory]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      fullHistory.filter(day => new Date(day.timestamp).getFullYear().toString() === selectedYear).map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [fullHistory, selectedYear]);

  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return fullHistory.filter(day => {
      const d = new Date(day.timestamp);
      return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    }).sort((a,b) => b.timestamp - a.timestamp);
  }, [fullHistory, selectedYear, selectedMonth]);

  const getMonthName = (monthIndex: number) => new Date(2000, monthIndex).toLocaleString('ar-SY', { month: 'long' });

  const groupItemsByOrder = (items: SaleItem[]) => {
      const orders: Record<string, SaleItem[]> = {};
      items.forEach(item => {
          if (!orders[item.orderId]) orders[item.orderId] = [];
          orders[item.orderId].push(item);
      });
      return Object.values(orders).sort((a, b) => b[0].orderId.localeCompare(a[0].orderId));
  };

  const renderArchive = () => {
    if (step === 'years') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {years.length > 0 ? years.map(year => (
                <button key={year} onClick={() => { setSelectedYear(year); setStep('months'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <Folder size={48} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-black text-white">{year}</span>
                </button>
            )) : (
              <div className="col-span-full py-20 text-center flex flex-col items-center gap-4">
                  <div className="bg-gray-700/30 p-6 rounded-full"><Zap size={48} className="text-gray-600" /></div>
                  <p className="text-gray-500 font-bold">لا توجد عمليات بيع مؤرشفة بعد</p>
              </div>
            )}
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => { setSelectedMonth(monthIdx); setStep('days'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <CalendarDays size={48} className="text-blue-400 group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-4 animate-fade-up h-full">
            <div className="flex items-center gap-2 bg-gray-900 p-1.5 rounded-xl border border-gray-700 shrink-0">
                <button onClick={() => setFilterType('all')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${filterType === 'all' ? 'bg-white text-black shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>الكل</button>
                <button onClick={() => setFilterType('retail')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${filterType === 'retail' ? 'bg-blue-500 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>مفرق</button>
                <button onClick={() => setFilterType('wholesale')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${filterType === 'wholesale' ? 'bg-orange-500 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>جملة</button>
            </div>

            <div className="flex-1 overflow-y-auto space-y-3 pr-1 custom-scrollbar">
                {currentDaysData.map(day => {
                    const filteredItems = day.items.filter(item => filterType === 'all' || item.saleType === filterType);
                    if (filteredItems.length === 0 && filterType !== 'all') return null;
                    const dayTotal = filteredItems.reduce((s, i) => s + (i.price * i.quantity), 0);
                    const isToday = day.id === 'today-active';
                    const groupedOrders = groupItemsByOrder(filteredItems);

                    return (
                        <div key={day.id} className={`rounded-xl border overflow-hidden shadow-sm transition-all ${isToday ? 'border-orange-500/50 bg-orange-500/5' : 'border-gray-700 bg-gray-800'}`}>
                            <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className={`p-4 flex justify-between items-center cursor-pointer ${isToday ? 'bg-orange-500/10' : 'bg-gray-900/50 hover:bg-gray-900'}`}>
                                <div className="flex items-center gap-3">
                                    <div className="text-gray-500">{expandedDayId === day.id ? <ChevronUp size={18} /> : <ChevronDown size={18} />}</div>
                                    <span className={`font-bold ${isToday ? 'text-orange-400' : 'text-white'}`}>{day.date}</span>
                                </div>
                                <span className="font-black text-lg text-green-400">{dayTotal.toLocaleString()} <small className="text-[10px] text-gray-500 font-normal">ل.س</small></span>
                            </div>
                            {expandedDayId === day.id && (
                                <div className="p-4 bg-gray-900/30 border-t border-gray-700 animate-fade-up space-y-4">
                                    {groupedOrders.map((orderItems, oIdx) => {
                                        const first = orderItems[0];
                                        const orderTotal = orderItems.reduce((s, i) => s + (i.price * i.quantity), 0);
                                        return (
                                            <div key={oIdx} className="bg-gray-800/80 rounded-2xl border border-gray-700 overflow-hidden shadow-inner">
                                                <div className="bg-gray-900/50 p-3 flex justify-between items-center border-b border-gray-700/50">
                                                    <div className="flex items-center gap-2">
                                                        {first.saleType === 'wholesale' ? <Store size={14} className="text-orange-400" /> : <User size={14} className="text-blue-400" />}
                                                        <span className="text-white text-xs font-black">{first.customerName || 'زبون عام'}</span>
                                                        <span className="text-[9px] bg-gray-700 text-gray-400 px-1.5 py-0.5 rounded font-bold tabular-nums">#{first.orderId.slice(-4)}</span>
                                                    </div>
                                                    <div className="flex items-center gap-3">
                                                        <div className="flex items-center gap-1 text-[9px] text-gray-500 font-bold"><Clock size={10} />{first.time}</div>
                                                        <span className="text-green-400 font-black text-sm">{orderTotal.toLocaleString()}</span>
                                                        <button onClick={() => onPreviewInvoice(orderItems)} className="text-gray-500 hover:text-white transition-colors"><Download size={14}/></button>
                                                    </div>
                                                </div>
                                                <div className="p-2 space-y-1">
                                                    {orderItems.map((item, iIdx) => (
                                                        <div key={iIdx} className="flex justify-between items-center text-[10px] px-2 py-1 bg-gray-900/20 rounded">
                                                            <span className="text-gray-300 font-bold">{item.name} <span className="text-gray-500 font-normal">({item.quantity} {item.unitType === 'kg' ? 'كغ' : 'قطعة'})</span></span>
                                                            <span className="text-gray-400 tabular-nums">{(item.price * item.quantity).toLocaleString()}</span>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
  };

  const renderProfitReport = () => (
    <div className="flex flex-col h-full animate-fade-up">
        <div className="bg-blue-500/10 border border-blue-500/20 p-4 rounded-2xl mb-4 flex items-start gap-3">
            <span className="shrink-0 mt-0.5"><Info size={20} className="text-blue-400" /></span>
            <p className="text-xs text-gray-400 leading-relaxed font-bold">هذا التقرير يحلل صافي أرباح كل منتج بشكل منفصل بناءً على الفرق بين (سعر البيع) و (سعر التكلفة) المسجل عند وقت البيع.</p>
        </div>
        <div className="bg-gray-900 rounded-2xl border border-gray-700 overflow-hidden flex-1 flex flex-col">
            <div className="overflow-x-auto custom-scrollbar">
                <table className="w-full text-right text-xs">
                    <thead className="bg-gray-800 text-gray-400 font-black uppercase text-[9px] tracking-widest sticky top-0 z-10">
                        <tr>
                            <th className="p-4 border-b border-gray-700">اسم المنتج</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح اليوم</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح الشهر</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح السنة</th>
                            <th className="p-4 border-b border-gray-700 text-center bg-[#FA8072]/10 text-[#FA8072]">إجمالي الربح</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-800">
                        {profitReport.map(([name, data], idx) => (
                            <tr key={idx} className="hover:bg-gray-800/50 transition-colors">
                                <td className="p-4 font-black text-white">{name}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.today.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.month.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.year.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums font-black text-green-400 bg-green-400/5">{data.total.toLocaleString()}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-md z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-3xl w-full max-w-5xl shadow-2xl border border-gray-700 flex flex-col h-[85vh] overflow-hidden animate-fade-up">
        <div className="p-4 md:p-5 border-b border-gray-700 flex flex-col md:flex-row justify-between items-center bg-gray-900/50 gap-4 shrink-0">
            <div className="w-full md:w-auto order-3 md:order-1 flex justify-start">
                <button onClick={onClose} className="flex items-center gap-2 bg-gray-700 hover:bg-red-600 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all shadow-lg active:scale-95 group">
                    <span>إغلاق</span>
                    <X size={18} className="group-hover:rotate-90 transition-transform" />
                </button>
            </div>
            <div className="flex items-center gap-1 bg-gray-950 p-1 rounded-xl border border-gray-700 w-full md:w-auto order-2">
                <button onClick={() => setTab('archive')} className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all ${tab === 'archive' ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}><Folder size={14} /> تصفح الأرشيف</button>
                <button onClick={() => setTab('profit-report')} className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all ${tab === 'profit-report' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}><PieChart size={14} /> تقرير الأرباح</button>
            </div>
            <div className="flex items-center gap-3 w-full md:w-auto order-1 md:order-3 justify-end">
                <h3 className="font-black text-lg md:text-xl text-white">أرشيف المبيعات</h3>
                {tab === 'archive' && step !== 'years' && (
                    <button onClick={() => { if (step === 'days') { setStep('months'); setSelectedMonth(-1); } else if (step === 'months') { setStep('years'); setSelectedYear(''); } }} className="bg-gray-700 hover:bg-[#FA8072] p-2 rounded-full text-white transition-colors shrink-0 shadow-lg"><ArrowRight size={20} /></button>
                )}
            </div>
        </div>
        <div className="p-6 flex-1 overflow-y-auto custom-scrollbar">{tab === 'archive' ? renderArchive() : renderProfitReport()}</div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { X, Copy, Check, Download, FileSpreadsheet, Printer } from 'lucide-react';
import { SaleItem } from '../types';
import { utils, writeFile } from 'xlsx';

interface InvoiceModalProps {
  items: SaleItem[];
  onClose: () => void;
}

export const InvoiceModal: React.FC<InvoiceModalProps> = ({ items, onClose }) => {
  const [copied, setCopied] = useState(false);
  const total = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const date = items[0]?.time || new Date().toLocaleTimeString('ar-SY');
  const dayDate = new Date().toLocaleDateString('ar-SY');
  const customerName = items[0]?.customerName || 'زبون عام';

  const handleDownloadExcel = () => {
    const data = items.map(i => ({ "المادة": i.name, "الكمية": i.quantity, "السعر": i.price, "الإجمالي": i.price * i.quantity }));
    data.push({ "المادة": "المجموع الكلي", "الكمية": 0, "السعر": 0, "الإجمالي": total });
    const ws = utils.json_to_sheet(data);
    const wb = utils.book_new();
    utils.book_append_sheet(wb, ws, "Invoice");
    writeFile(wb, `فاتورة-${customerName}-${Date.now()}.xlsx`);
  };

  const handleCopy = () => {
    const text = `فاتورة مخبز كوكيز\nالتاريخ: ${dayDate}\nالعميل: ${customerName}\nالمجموع: ${total} ل.س`;
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-[2.5rem] w-full max-w-lg shadow-2xl border border-gray-700 animate-fade-up overflow-hidden flex flex-col max-h-[90vh]">

        {/* Header - Hidden on Print */}
        <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 no-print">
          <h3 className="font-black text-xl text-white">معاينة الفاتورة</h3>
          <button onClick={onClose} className="p-2 text-gray-400 hover:text-white transition-colors"><X size={24} /></button>
        </div>

        {/* Invoice Body - Optimized for Printing and Previewing */}
        <div className="flex-1 overflow-y-auto bg-white p-4 sm:p-8 shadow-inner">
          <div id="invoice-content" className="bg-white text-black p-4 sm:p-6 rounded-lg min-h-full">
            <div className="text-center mb-8 border-b-2 border-black pb-4">
              <h2 className="text-3xl font-black mb-1 text-black">مخبز كوكيز</h2>
              <p className="text-black text-sm font-bold opacity-80 uppercase tracking-widest">فاتورة مبيعات</p>
            </div>

            <div className="flex justify-between mb-8 text-sm font-bold text-black border-b border-gray-100 pb-4">
              <div className="space-y-1">
                <p className="text-black opacity-60">العميل:</p>
                <p className="text-lg font-black">{customerName}</p>
              </div>
              <div className="text-left space-y-1">
                <p className="text-black opacity-60">التاريخ:</p>
                <p className="tabular-nums font-black">{dayDate}</p>
                <p className="tabular-nums text-xs opacity-60">{date}</p>
              </div>
            </div>

            <table className="w-full text-right mb-10 text-black">
              <thead className="border-b-2 border-black">
                <tr className="text-xs uppercase font-black">
                  <th className="py-2 px-1 text-right">المادة</th>
                  <th className="py-2 px-1 text-center">الكمية</th>
                  <th className="py-2 px-1 text-left">السعر</th>
                  <th className="py-2 px-1 text-left">الإجمالي</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200">
                {items.map((item, idx) => (
                  <tr key={idx} className="font-bold">
                    <td className="py-4 px-1 text-right">{item.name}</td>
                    <td className="py-4 px-1 text-center tabular-nums">{item.quantity}</td>
                    <td className="py-4 px-1 text-left tabular-nums">{item.price.toLocaleString()}</td>
                    <td className="py-4 px-1 text-left font-black tabular-nums">{(item.price * item.quantity).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>

            <div className="border-t-2 border-black pt-6">
              <div className="flex justify-between items-center text-2xl font-black text-black">
                <span>المجموع النهائي:</span>
                <span className="tabular-nums">{total.toLocaleString()} <small className="text-xs font-normal">ل.س</small></span>
              </div>
            </div>

            <div className="mt-20 text-center text-xs text-black font-bold border-t border-dashed border-gray-300 pt-6 opacity-60">
              نشكركم على اختياركم مخبز كوكيز - يرجى الاحتفاظ بالفاتورة
            </div>
          </div>
        </div>

        {/* Actions - Hidden on Print */}
        <div className="p-6 bg-gray-900/80 border-t border-gray-700 grid grid-cols-1 sm:grid-cols-3 gap-3 no-print">
            <button onClick={handlePrint} className="bg-[#FA8072] hover:bg-orange-500 text-white py-3.5 rounded-2xl font-black text-xs flex items-center justify-center gap-2 transition-all shadow-xl active:scale-95">
                <Printer size={18} /> طباعة PDF
            </button>
            <button onClick={handleDownloadExcel} className="bg-green-600 hover:bg-green-500 text-white py-3.5 rounded-2xl font-black text-xs flex items-center justify-center gap-2 transition-all shadow-xl active:scale-95">
                <FileSpreadsheet size={18} /> ملف Excel
            </button>
            <button onClick={handleCopy} className={`py-3.5 rounded-2xl font-black text-xs flex items-center justify-center gap-2 transition-all border border-gray-700 ${copied ? 'bg-blue-600 text-white border-blue-500' : 'bg-gray-800 text-gray-400 hover:text-white'}`}>
                {copied ? <Check size={18} /> : <Copy size={18} />} {copied ? 'تم النسخ' : 'نسخ نصي'}
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { X, ChevronDown, ChevronUp, ArrowRight, Folder, CalendarDays, ShoppingBag, Zap, Store, User, Filter, TrendingUp, PieChart, Info, Clock, Download, Search } from 'lucide-react';
import { ArchivedDay, SaleItem, SaleType } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  currentSales?: SaleItem[];
  onClose: () => void;
  onClearHistory: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateOrder: (date: string, orderId: string, updatedItems: SaleItem[]) => void;
}

type NavStep = 'years' | 'months' | 'days';
type FilterType = 'all' | SaleType;
type TabMode = 'archive' | 'profit-report';

export const HistoryModal: React.FC<HistoryModalProps> = ({ 
  history, currentSales = [], onClose, onClearHistory, onPreviewInvoice, onUpdateOrder 
}) => {
  const [tab, setTab] = useState<TabMode>('archive');
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);
  const [filterType, setFilterType] = useState<FilterType>('all');
  const [searchTerm, setSearchTerm] = useState('');

  const fullHistory = useMemo(() => {
      const merged = [...history];
      if (currentSales.length > 0) {
          const today = new Date();
          const todayStr = today.toLocaleDateString('ar-SY');
          const existingTodayIdx = merged.findIndex(d => d.date.includes(todayStr));

          const todayEntry: ArchivedDay = {
              id: 'today-active',
              date: `${todayStr} (مبيعات حية)`,
              timestamp: Date.now(),
              totalRevenue: currentSales.reduce((s, i) => s + (i.price * i.quantity), 0),
              totalExpenses: 0,
              totalItems: currentSales.length,
              items: currentSales,
              purchaseInvoices: []
          };

          if (existingTodayIdx > -1) merged[existingTodayIdx] = todayEntry;
          else merged.push(todayEntry);
      }
      return merged;
  }, [history, currentSales]);

  const profitReport = useMemo(() => {
    const report: Record<string, { today: number, month: number, year: number, total: number }> = {};
    const now = new Date();
    const currentYear = now.getFullYear();
    const currentMonth = now.getMonth();
    const todayStr = now.toLocaleDateString('ar-SY');

    fullHistory.forEach(day => {
        const d = new Date(day.timestamp);
        const isYear = d.getFullYear() === currentYear;
        const isMonth = isYear && d.getMonth() === currentMonth;
        const isToday = day.date.includes(todayStr);

        day.items.forEach(item => {
            const profitPerUnit = item.price - (item.costPrice || 0);
            const totalProfit = profitPerUnit * item.quantity;
            if (!report[item.name]) report[item.name] = { today: 0, month: 0, year: 0, total: 0 };
            report[item.name].total += totalProfit;
            if (isYear) report[item.name].year += totalProfit;
            if (isMonth) report[item.name].month += totalProfit;
            if (isToday) report[item.name].today += totalProfit;
        });
    });
    return Object.entries(report).sort((a, b) => b[1].total - a[1].total);
  }, [fullHistory]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(fullHistory.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [fullHistory]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      fullHistory.filter(day => new Date(day.timestamp).getFullYear().toString() === selectedYear).map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [fullHistory, selectedYear]);

  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return fullHistory.filter(day => {
      const d = new Date(day.timestamp);
      return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    }).sort((a,b) => b.timestamp - a.timestamp);
  }, [fullHistory, selectedYear, selectedMonth]);

  const getMonthName = (monthIndex: number) => new Date(2000, monthIndex).toLocaleString('ar-SY', { month: 'long' });

  const groupItemsByOrder = (items: SaleItem[]) => {
      const orders: Record<string, SaleItem[]> = {};
      items.forEach(item => {
          if (!orders[item.orderId]) orders[item.orderId] = [];
          orders[item.orderId].push(item);
      });

      let orderList = Object.values(orders);

      // تطبيق البحث
      if (searchTerm.trim()) {
        const term = searchTerm.toLowerCase();
        orderList = orderList.filter(order => 
          (order[0].customerName?.toLowerCase() || '').includes(term) ||
          order[0].orderId.includes(term) ||
          order.some(item => item.name.toLowerCase().includes(term))
        );
      }

      return orderList.sort((a, b) => b[0].orderId.localeCompare(a[0].orderId));
  };

  const renderArchive = () => {
    if (step === 'years') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {years.length > 0 ? years.map(year => (
                <button key={year} onClick={() => { setSelectedYear(year); setStep('months'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <Folder size={48} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-black text-white">{year}</span>
                </button>
            )) : (
              <div className="col-span-full py-20 text-center flex flex-col items-center gap-4">
                  <div className="bg-gray-700/30 p-6 rounded-full"><Zap size={48} className="text-gray-600" /></div>
                  <p className="text-gray-500 font-bold">لا توجد عمليات بيع مؤرشفة بعد</p>
              </div>
            )}
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => { setSelectedMonth(monthIdx); setStep('days'); }} className="bg-gray-700/50 hover:bg-gray-600 border border-gray-600 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <CalendarDays size={48} className="text-blue-400 group-hover:scale-110 transition-transform" />
                    <span className="text-xl font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-4 animate-fade-up h-full">
            <div className="flex flex-col md:flex-row items-center gap-3 shrink-0">
                <div className="relative flex-1 w-full">
                    <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
                    <input 
                      type="text" 
                      value={searchTerm}
                      onChange={e => setSearchTerm(e.target.value)}
                      placeholder="بحث في الفواتير (اسم الزبون، مادة، رقم)..." 
                      className="w-full bg-gray-900 border border-gray-700 text-white rounded-xl pr-10 pl-4 py-2 text-xs focus:border-[#FA8072] outline-none" 
                    />
                </div>
                <div className="flex items-center gap-1 bg-gray-900 p-1 rounded-xl border border-gray-700 w-full md:w-auto">
                    <button onClick={() => setFilterType('all')} className={`flex-1 md:px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${filterType === 'all' ? 'bg-white text-black shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>الكل</button>
                    <button onClick={() => setFilterType('retail')} className={`flex-1 md:px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${filterType === 'retail' ? 'bg-blue-500 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>مفرق</button>
                    <button onClick={() => setFilterType('wholesale')} className={`flex-1 md:px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${filterType === 'wholesale' ? 'bg-orange-500 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>جملة</button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto space-y-3 pr-1 custom-scrollbar">
                {currentDaysData.map(day => {
                    const filteredItems = day.items.filter(item => filterType === 'all' || item.saleType === filterType);
                    const groupedOrders = groupItemsByOrder(filteredItems);
                    if (groupedOrders.length === 0) return null;

                    const dayTotal = filteredItems.reduce((s, i) => s + (i.price * i.quantity), 0);
                    const isToday = day.id === 'today-active';

                    return (
                        <div key={day.id} className={`rounded-xl border overflow-hidden shadow-sm transition-all ${isToday ? 'border-orange-500/50 bg-orange-500/5' : 'border-gray-700 bg-gray-800'}`}>
                            <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className={`p-4 flex justify-between items-center cursor-pointer ${isToday ? 'bg-orange-500/10' : 'bg-gray-900/50 hover:bg-gray-900'}`}>
                                <div className="flex items-center gap-3">
                                    <div className="text-gray-500">{expandedDayId === day.id ? <ChevronUp size={18} /> : <ChevronDown size={18} />}</div>
                                    <span className={`font-bold ${isToday ? 'text-orange-400' : 'text-white'}`}>{day.date}</span>
                                    {searchTerm && <span className="text-[10px] bg-blue-500/20 text-blue-400 px-2 py-0.5 rounded-full font-bold">تم العثور على {groupedOrders.length} نتيجة</span>}
                                </div>
                                <span className="font-black text-lg text-green-400">{dayTotal.toLocaleString()} <small className="text-[10px] text-gray-500 font-normal">ل.س</small></span>
                            </div>
                            {(expandedDayId === day.id || searchTerm) && (
                                <div className="p-4 bg-gray-900/30 border-t border-gray-700 animate-fade-up space-y-4">
                                    {groupedOrders.map((orderItems, oIdx) => {
                                        const first = orderItems[0];
                                        const orderTotal = orderItems.reduce((s, i) => s + (i.price * i.quantity), 0);
                                        return (
                                            <div key={oIdx} className="bg-gray-800/80 rounded-2xl border border-gray-700 overflow-hidden shadow-inner">
                                                <div className="bg-gray-900/50 p-3 flex justify-between items-center border-b border-gray-700/50">
                                                    <div className="flex items-center gap-2">
                                                        {first.saleType === 'wholesale' ? <Store size={14} className="text-orange-400" /> : <User size={14} className="text-blue-400" />}
                                                        <span className="text-white text-xs font-black">{first.customerName || 'زبون عام'}</span>
                                                        <span className="text-[9px] bg-gray-700 text-gray-400 px-1.5 py-0.5 rounded font-bold tabular-nums">#{first.orderId.slice(-4)}</span>
                                                    </div>
                                                    <div className="flex items-center gap-3">
                                                        <div className="flex items-center gap-1 text-[9px] text-gray-500 font-bold"><Clock size={10} />{first.time}</div>
                                                        <span className="text-green-400 font-black text-sm">{orderTotal.toLocaleString()}</span>
                                                        <button onClick={() => onPreviewInvoice(orderItems)} className="text-gray-500 hover:text-white transition-colors"><Download size={14}/></button>
                                                    </div>
                                                </div>
                                                <div className="p-2 space-y-1">
                                                    {orderItems.map((item, iIdx) => (
                                                        <div key={iIdx} className="flex justify-between items-center text-[10px] px-2 py-1 bg-gray-900/20 rounded">
                                                            <span className="text-gray-300 font-bold">{item.name} <span className="text-gray-500 font-normal">({item.quantity} {item.unitType === 'kg' ? 'كغ' : 'قطعة'})</span></span>
                                                            <span className="text-gray-400 tabular-nums">{(item.price * item.quantity).toLocaleString()}</span>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            )}
                        </div>
                    );
                })}
                {currentDaysData.length > 0 && searchTerm && !currentDaysData.some(day => groupItemsByOrder(day.items.filter(item => filterType === 'all' || item.saleType === filterType)).length > 0) && (
                    <div className="py-10 text-center text-gray-500 text-sm">لم يتم العثور على فواتير تطابق بحثك.</div>
                )}
            </div>
        </div>
    );
  };

  const renderProfitReport = () => (
    <div className="flex flex-col h-full animate-fade-up">
        <div className="bg-blue-500/10 border border-blue-500/20 p-4 rounded-2xl mb-4 flex items-start gap-3">
            <span className="shrink-0 mt-0.5"><Info size={20} className="text-blue-400" /></span>
            <p className="text-xs text-gray-400 leading-relaxed font-bold">هذا التقرير يحلل صافي أرباح كل منتج بشكل منفصل بناءً على الفرق بين (سعر البيع) و (سعر التكلفة) المسجل عند وقت البيع.</p>
        </div>
        <div className="bg-gray-900 rounded-2xl border border-gray-700 overflow-hidden flex-1 flex flex-col">
            <div className="overflow-x-auto custom-scrollbar">
                <table className="w-full text-right text-xs">
                    <thead className="bg-gray-800 text-gray-400 font-black uppercase text-[9px] tracking-widest sticky top-0 z-10">
                        <tr>
                            <th className="p-4 border-b border-gray-700">اسم المنتج</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح اليوم</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح الشهر</th>
                            <th className="p-4 border-b border-gray-700 text-center">أرباح السنة</th>
                            <th className="p-4 border-b border-gray-700 text-center bg-[#FA8072]/10 text-[#FA8072]">إجمالي الربح</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-800">
                        {profitReport.map(([name, data], idx) => (
                            <tr key={idx} className="hover:bg-gray-800/50 transition-colors">
                                <td className="p-4 font-black text-white">{name}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.today.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.month.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums text-gray-400">{data.year.toLocaleString()}</td>
                                <td className="p-4 text-center tabular-nums font-black text-green-400 bg-green-400/5">{data.total.toLocaleString()}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-md z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-3xl w-full max-w-5xl shadow-2xl border border-gray-700 flex flex-col h-[85vh] overflow-hidden animate-fade-up">
        <div className="p-4 md:p-5 border-b border-gray-700 flex flex-col md:flex-row justify-between items-center bg-gray-900/50 gap-4 shrink-0">
            <div className="w-full md:w-auto order-3 md:order-1 flex justify-start">
                <button onClick={onClose} className="flex items-center gap-2 bg-gray-700 hover:bg-red-600 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all shadow-lg active:scale-95 group">
                    <span>إغلاق</span>
                    <X size={18} className="group-hover:rotate-90 transition-transform" />
                </button>
            </div>
            <div className="flex items-center gap-1 bg-gray-950 p-1 rounded-xl border border-gray-700 w-full md:w-auto order-2">
                <button onClick={() => setTab('archive')} className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all ${tab === 'archive' ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}><Folder size={14} /> تصفح الأرشيف</button>
                <button onClick={() => setTab('profit-report')} className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all ${tab === 'profit-report' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}><PieChart size={14} /> تقرير الأرباح</button>
            </div>
            <div className="flex items-center gap-3 w-full md:w-auto order-1 md:order-3 justify-end">
                <h3 className="font-black text-lg md:text-xl text-white">أرشيف المبيعات</h3>
                {tab === 'archive' && step !== 'years' && (
                    <button onClick={() => { if (step === 'days') { setStep('months'); setSelectedMonth(-1); } else if (step === 'months') { setStep('years'); setSelectedYear(''); } }} className="bg-gray-700 hover:bg-[#FA8072] p-2 rounded-full text-white transition-colors shrink-0 shadow-lg"><ArrowRight size={20} /></button>
                )}
            </div>
        </div>
        <div className="p-6 flex-1 overflow-y-auto custom-scrollbar">{tab === 'archive' ? renderArchive() : renderProfitReport()}</div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, Suspense } from 'react';
import { Plus, Trash2, X, ShoppingCart, UserPlus, Printer, FileText, Store, Folder, CalendarDays, ArrowRight, Zap, ChevronDown, ChevronUp, Edit3, RotateCcw, Search } from 'lucide-react';
import { PurchaseInvoice, PurchaseItem, ArchivedDay, PaymentStatus, Supplier } from '../types';

const PurchasePrintModal = React.lazy(() => import('./PurchasePrintModal').then(module => ({ default: module.PurchasePrintModal })));

interface ExpensesModalProps {
  currentPurchases: PurchaseInvoice[];
  archivedHistory: ArchivedDay[]; 
  onAddInvoice: (invoice: PurchaseInvoice) => void;
  onUpdateInvoice: (invoice: PurchaseInvoice) => void;
  onDeleteInvoice: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
  suppliers: Supplier[];
  onAddSupplier: (supplier: Omit<Supplier, 'id'>) => void;
  onDeleteSupplier: (id: string) => void;
}

type NavStep = 'years' | 'months' | 'days';

export const ExpensesModal: React.FC<ExpensesModalProps> = ({ 
  currentPurchases, archivedHistory, onAddInvoice, onUpdateInvoice, onDeleteInvoice, isOpen, onClose, suppliers = [], onAddSupplier, onDeleteSupplier
}) => {
  const [activeTab, setActiveTab] = useState<'new' | 'history' | 'suppliers'>('new');
  const [selectedSupplierId, setSelectedSupplierId] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('paid'); 
  const [itemInputs, setItemInputs] = useState({ name: '', quantity: '', unitPrice: '' });
  const [currentInvoiceItems, setCurrentInvoiceItems] = useState<PurchaseItem[]>([]);
  const [invoiceToPrint, setInvoiceToPrint] = useState<PurchaseInvoice | null>(null);
  const [newSup, setNewSup] = useState({ name: '', phone: '' });
  const [editingInvoiceId, setEditingInvoiceId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  // Navigation state for History Tab
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);

  const fullHistory = useMemo(() => {
    const merged = [...archivedHistory];
    if (currentPurchases.length > 0) {
        const today = new Date();
        const todayStr = today.toLocaleDateString('ar-SY');
        const existingTodayIdx = merged.findIndex(d => d.date.includes(todayStr));

        const todayEntry: ArchivedDay = {
            id: 'today-active-purchases',
            date: `${todayStr} (مباشر)`,
            timestamp: Date.now(),
            totalRevenue: 0,
            totalExpenses: currentPurchases.reduce((s, i) => s + i.totalAmount, 0),
            totalItems: 0,
            items: [],
            purchaseInvoices: currentPurchases
        };

        if (existingTodayIdx > -1) merged[existingTodayIdx] = { ...merged[existingTodayIdx], purchaseInvoices: [...(merged[existingTodayIdx].purchaseInvoices || []), ...currentPurchases] };
        else merged.push(todayEntry);
    }
    return merged;
  }, [archivedHistory, currentPurchases]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(fullHistory.filter(d => (d.purchaseInvoices || []).length > 0).map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [fullHistory]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      fullHistory
        .filter(day => (day.purchaseInvoices || []).length > 0 && new Date(day.timestamp).getFullYear().toString() === selectedYear)
        .map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [fullHistory, selectedYear]);

  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return fullHistory.filter(day => {
      const d = new Date(day.timestamp);
      return (day.purchaseInvoices || []).length > 0 && d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    }).sort((a,b) => b.timestamp - a.timestamp);
  }, [fullHistory, selectedYear, selectedMonth]);

  const getMonthName = (monthIndex: number) => {
    return new Date(2000, monthIndex).toLocaleString('ar-SY', { month: 'long' });
  };

  const addItem = () => {
      if (!itemInputs.name || !itemInputs.quantity || !itemInputs.unitPrice) return;
      const q = parseFloat(itemInputs.quantity); 
      const price = parseFloat(itemInputs.unitPrice);
      setCurrentInvoiceItems(prev => [...prev, { id: Date.now().toString(), name: itemInputs.name, quantity: q, cost: price, total: q * price }]);
      setItemInputs({ name: '', quantity: '', unitPrice: '' });
  };

  const handleSaveInvoice = () => {
      const supplier = suppliers.find(s => s.id === selectedSupplierId || s.name === selectedSupplierId);
      if (!supplier || currentInvoiceItems.length === 0) return alert('يرجى تحديد مورد وإضافة مواد للفاتورة');

      const totalAmount = currentInvoiceItems.reduce((sum, item) => sum + item.total, 0);

      const invoiceData: PurchaseInvoice = { 
          id: editingInvoiceId || Date.now().toString(), 
          supplierName: supplier.name, 
          date: new Date().toLocaleDateString('ar-SY'), 
          timestamp: Date.now(), 
          items: currentInvoiceItems, 
          totalAmount, 
          paymentStatus 
      };

      if (editingInvoiceId) {
          onUpdateInvoice(invoiceData);
          setEditingInvoiceId(null);
      } else {
          onAddInvoice(invoiceData);
      }

      setSelectedSupplierId(''); 
      setCurrentInvoiceItems([]); 
      setActiveTab('history');
      setStep('years');
  };

  const startEditInvoice = (inv: PurchaseInvoice) => {
      const supplier = suppliers.find(s => s.name === inv.supplierName);
      setEditingInvoiceId(inv.id);
      setSelectedSupplierId(supplier?.id || inv.supplierName);
      setPaymentStatus(inv.paymentStatus);
      setCurrentInvoiceItems(inv.items);
      setActiveTab('new');
  };

  const cancelEdit = () => {
      setEditingInvoiceId(null);
      setSelectedSupplierId('');
      setCurrentInvoiceItems([]);
      setPaymentStatus('paid');
  };

  const renderHistoryContent = () => {
    if (step === 'years') return (
        <div className="grid grid-cols-2 gap-4 animate-fade-up">
            {years.length > 0 ? years.map(year => (
                <button key={year} onClick={() => { setSelectedYear(year); setStep('months'); }} className="bg-gray-900/40 hover:bg-gray-700/50 border border-gray-700 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <Folder size={40} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                    <span className="text-lg font-black text-white">{year}</span>
                </button>
            )) : (
              <div className="col-span-full py-20 text-center flex flex-col items-center gap-4">
                  <div className="bg-gray-900/30 p-6 rounded-full"><Zap size={48} className="text-gray-700" /></div>
                  <p className="text-gray-500 font-bold">لا توجد مشتريات مؤرشفة</p>
              </div>
            )}
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => { setSelectedMonth(monthIdx); setStep('days'); }} className="bg-gray-900/40 hover:bg-gray-700/50 border border-gray-700 p-8 rounded-2xl flex flex-col items-center gap-3 transition-all group">
                    <CalendarDays size={40} className="text-blue-400 group-hover:scale-110 transition-transform" />
                    <span className="text-lg font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-3 animate-fade-up h-full">
            <div className="relative shrink-0">
                <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
                <input 
                  type="text" 
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                  placeholder="بحث في فواتير المشتريات (مورد، مادة، رقم)..." 
                  className="w-full bg-gray-900 border border-gray-700 text-white rounded-xl pr-10 pl-4 py-2.5 text-xs focus:border-[#FA8072] outline-none" 
                />
            </div>

            <div className="flex-1 overflow-y-auto space-y-2 pr-1 custom-scrollbar">
                {currentDaysData.map(day => {
                    let filteredInvoices = day.purchaseInvoices || [];

                    if (searchTerm.trim()) {
                      const term = searchTerm.toLowerCase();
                      filteredInvoices = filteredInvoices.filter(inv => 
                        inv.supplierName.toLowerCase().includes(term) ||
                        inv.id.includes(term) ||
                        inv.items.some(item => item.name.toLowerCase().includes(term))
                      );
                    }

                    if (filteredInvoices.length === 0 && searchTerm) return null;

                    const isToday = day.id === 'today-active-purchases';
                    return (
                        <div key={day.id} className={`rounded-xl border overflow-hidden transition-all ${isToday ? 'border-orange-500/30 bg-orange-500/5' : 'border-gray-700 bg-gray-900/20'}`}>
                            <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className={`p-4 flex justify-between items-center cursor-pointer ${isToday ? 'bg-orange-500/10' : 'bg-gray-900/50 hover:bg-gray-900'}`}>
                                <div className="flex items-center gap-3">
                                    <div className="text-gray-500">{(expandedDayId === day.id || searchTerm) ? <ChevronUp size={16} /> : <ChevronDown size={16} />}</div>
                                    <span className={`font-bold text-sm ${isToday ? 'text-orange-400' : 'text-white'}`}>{day.date}</span>
                                    {searchTerm && <span className="text-[10px] bg-blue-500/20 text-blue-400 px-2 py-0.5 rounded-full font-bold">{filteredInvoices.length} فواتير مطابقة</span>}
                                </div>
                                <span className="font-black text-red-400">{filteredInvoices.reduce((s,i) => s + i.totalAmount, 0).toLocaleString()} <small className="text-[9px] text-gray-600 font-normal">ل.س</small></span>
                            </div>

                            {(expandedDayId === day.id || searchTerm) && (
                                <div className="p-3 bg-black/20 border-t border-gray-700 animate-fade-up space-y-2">
                                    {filteredInvoices.map((inv) => (
                                        <div key={inv.id} className="bg-gray-800 p-3 rounded-xl border border-gray-700 flex justify-between items-center group">
                                            <div className="flex items-center gap-3">
                                                <div className="bg-gray-900 p-1.5 rounded text-red-400"><Store size={14} /></div>
                                                <div className="flex flex-col">
                                                    <span className="text-white text-xs font-bold">{inv.supplierName}</span>
                                                    <span className="text-[9px] text-gray-500">{inv.paymentStatus === 'paid' ? 'نقدي' : 'آجل'} • {inv.items.length} مواد</span>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-1.5">
                                                <span className="text-white font-bold text-xs ml-2">{inv.totalAmount.toLocaleString()}</span>
                                                <button onClick={() => setInvoiceToPrint(inv)} className="p-1.5 bg-gray-700 rounded hover:bg-blue-600 text-white transition-colors" title="طباعة"><Printer size={12}/></button>
                                                <button onClick={() => startEditInvoice(inv)} className="p-1.5 bg-gray-700 rounded hover:bg-yellow-600 text-white transition-colors" title="تعديل"><Edit3 size={12}/></button>
                                                <button onClick={() => onDeleteInvoice(inv.id)} className="p-1.5 text-gray-500 hover:text-red-500 transition-colors" title="حذف"><Trash2 size={12}/></button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
  };

  if (!isOpen) return null;

  return (
    <>
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-[2rem] w-full max-w-2xl shadow-2xl border border-gray-700 flex flex-col h-[85vh] overflow-hidden">

        <div className="p-5 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 shrink-0">
          <div className="flex items-center gap-3">
            {activeTab === 'history' && step !== 'years' && (
                <button onClick={() => {
                    if (step === 'days') { setStep('months'); setSelectedMonth(-1); } 
                    else if (step === 'months') { setStep('years'); setSelectedYear(''); }
                }} className="bg-gray-700 hover:bg-[#FA8072] p-1.5 rounded-full text-white transition-colors"><ArrowRight size={18} /></button>
            )}
            <div className="flex items-center gap-2 text-white">
                <ShoppingCart size={22} className="text-[#FA8072]" />
                <h3 className="font-black text-xl">إدارة المشتريات</h3>
            </div>
          </div>
          <div className="flex items-center gap-2">
              <button onClick={onClose} className="hidden md:flex items-center gap-2 bg-gray-700 hover:bg-red-600 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all">
                  <span>خروج</span>
                  <X size={18} />
              </button>
              <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full text-gray-400 md:hidden"><X size={24} /></button>
          </div>
        </div>

        <div className="flex border-b border-gray-700 bg-gray-900/30">
            <button onClick={() => setActiveTab('new')} className={`flex-1 py-4 text-xs font-black transition-all ${activeTab === 'new' ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500 hover:bg-gray-800'}`}>
              {editingInvoiceId ? 'تعديل الفاتورة' : 'فاتورة جديدة'}
            </button>
            <button onClick={() => { setActiveTab('history'); setStep('years'); }} className={`flex-1 py-4 text-xs font-black transition-all ${activeTab === 'history' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-800'}`}>سجل المشتريات</button>
            <button onClick={() => setActiveTab('suppliers')} className={`flex-1 py-4 text-xs font-black transition-all ${activeTab === 'suppliers' ? 'bg-gray-700 text-white' : 'text-gray-500 hover:bg-gray-800'}`}>قائمة الموردين</button>
        </div>

        <div className="p-6 overflow-y-auto flex-1 custom-scrollbar">
          {activeTab === 'new' ? (
              <div className="space-y-6">
                  {editingInvoiceId && (
                    <div className="bg-yellow-500/10 border border-yellow-500/20 p-3 rounded-xl flex items-center justify-between">
                        <span className="text-yellow-500 text-xs font-bold flex items-center gap-2">
                           <Edit3 size={14} /> أنت الآن في وضع تعديل فاتورة قديمة
                        </span>
                        <button onClick={cancelEdit} className="text-[10px] bg-gray-700 text-white px-3 py-1 rounded-lg flex items-center gap-1">
                           <RotateCcw size={10} /> إلغاء التعديل
                        </button>
                    </div>
                  )}

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 font-black uppercase pr-1">تحديد المورد:</label>
                        <select value={selectedSupplierId} onChange={e => setSelectedSupplierId(e.target.value)} className={`w-full bg-gray-900 border rounded-xl px-4 py-3 text-white text-sm outline-none transition-all ${!selectedSupplierId && suppliers.length > 0 ? 'border-orange-500' : 'border-gray-700 focus:border-[#FA8072]'}`}>
                            <option value="">اختر مورد...</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
