import React, { useState, useMemo } from 'react';
import { Trash2, Search, User, Download, Store, Edit3, Receipt, Clock, Package, ChevronDown, ChevronUp, LayoutList } from 'lucide-react';
import { SaleItem } from '../types';

interface SalesTableProps {
  items: SaleItem[];
  onDeleteItem: (id: string) => void;
  onDeleteOrder?: (orderId: string) => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateItemPrice?: (itemId: string, newPrice: number) => void; 
}

export const SalesTable: React.FC<SalesTableProps> = ({ items, onDeleteItem, onDeleteOrder, onPreviewInvoice, onUpdateItemPrice }) => {
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [isExpanded, setIsExpanded] = useState(false); // حالة التوسيع للفواتير القديمة
  const [editingPriceId, setEditingPriceId] = useState<string | null>(null);
  const [tempPrice, setTempPrice] = useState<string>('');

  const groupedOrders = useMemo(() => {
    const groups: { [key: string]: SaleItem[] } = {};
    items.forEach(item => {
        const key = item.orderId;
        if (!groups[key]) groups[key] = [];
        groups[key].push(item);
    });
    // ترتيب تنازلي (الأحدث أولاً)
    return Object.values(groups).sort((a, b) => b[0].orderId.localeCompare(a[0].orderId));
  }, [items]);

  const filteredOrders = useMemo(() => {
      const term = searchTerm.toLowerCase().trim();
      if (!term) {
          // إذا لم يكن هناك بحث، نعرض إما الكل أو الأحدث فقط بناءً على الحالة
          return isExpanded ? groupedOrders : groupedOrders.slice(0, 1);
      }
      return groupedOrders.filter(g => 
          (g[0].customerName?.toLowerCase() || '').includes(term) ||
          g[0].orderId.includes(term)
      );
  }, [groupedOrders, searchTerm, isExpanded]);

  const savePrice = (itemId: string) => {
    const price = parseFloat(tempPrice);
    if (!isNaN(price) && onUpdateItemPrice) onUpdateItemPrice(itemId, price);
    setEditingPriceId(null);
  };

  if (items.length === 0) return (
    <div className="p-16 text-center flex flex-col items-center gap-4 bg-gray-800/30 rounded-[2.5rem] border border-dashed border-gray-700">
        <Receipt size={48} className="text-gray-700" />
        <p className="text-gray-500 font-bold text-sm">لا توجد مبيعات نشطة حالياً.</p>
    </div>
  );

  return (
    <div className="space-y-4">
        {/* Search Bar & Header */}
        <div className="flex flex-col md:flex-row gap-4 items-center justify-between no-print px-2">
            <div className="relative w-full md:max-w-xs">
                <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={e => setSearchTerm(e.target.value)} 
                  placeholder="بحث في فواتير اليوم..." 
                  className="w-full bg-gray-800 border border-gray-700 text-white rounded-xl pr-10 pl-4 py-2 text-xs outline-none focus:border-[#FA8072] transition-all shadow-lg" 
                />
            </div>
            {!searchTerm && groupedOrders.length > 1 && (
                <button 
                  onClick={() => setIsExpanded(!isExpanded)}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-lg ${isExpanded ? 'bg-gray-700 text-white' : 'bg-[#FA8072] text-white animate-pulse'}`}
                >
                    {isExpanded ? (
                        <><ChevronUp size={14} /> إخفاء الفواتير القديمة</>
                    ) : (
                        <><LayoutList size={14} /> عرض كافة فواتير اليوم ({groupedOrders.length})</>
                    )}
                </button>
            )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {filteredOrders.map((group, index) => {
                const total = group.reduce((s, i) => s + (i.price * i.quantity), 0);
                const first = group[0];
                const isLatest = index === 0 && !searchTerm && !isExpanded;

                return (
                    <div 
                      key={first.orderId} 
                      className={`bg-gray-800 rounded-[2rem] border overflow-hidden shadow-2xl animate-fade-up flex flex-col transition-all group ${isLatest ? 'border-[#FA8072] ring-2 ring-[#FA8072]/20' : 'border-gray-700 opacity-90'}`}
                    >
                        {/* Invoice Header */}
                        <div className={`p-4 flex justify-between items-start border-b ${isLatest ? 'bg-[#FA8072]/5 border-[#FA8072]/20' : 'bg-gray-900/50 border-gray-700/50'}`}>
                            <div className="flex gap-3">
                                <div className={`p-2 rounded-xl ${first.saleType === 'wholesale' ? 'bg-orange-500/10 text-orange-400' : 'bg-blue-500/10 text-blue-400'}`}>
                                    {first.saleType === 'wholesale' ? <Store size={18} /> : <User size={18} />}
                                </div>
                                <div className="flex flex-col">
                                    <div className="flex items-center gap-2">
                                        <span className="font-black text-white text-sm">{first.customerName || 'زبون عام'}</span>
                                        {isLatest && <span className="bg-[#FA8072] text-white text-[8px] px-1.5 py-0.5 rounded font-black uppercase">الأحدث</span>}
                                    </div>
                                    <div className="flex items-center gap-2 mt-0.5">
                                        <span className="text-[9px] bg-gray-700 text-gray-400 px-1.5 py-0.5 rounded font-bold tabular-nums">#{first.orderId.slice(-4)}</span>
                                        <div className="flex items-center gap-1 text-[9px] text-gray-500 font-bold">
                                            <Clock size={10} /> {first.time}
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="flex flex-col items-end">
                                <span className={`font-black text-base tabular-nums ${isLatest ? 'text-[#FA8072]' : 'text-green-400'}`}>{total.toLocaleString()}</span>
                                <span className="text-[8px] text-gray-600 font-bold uppercase">ل.س</span>
                            </div>
                        </div>

                        {/* Invoice Body (Items) */}
                        <div className="p-3 space-y-2">
                            {group.map(item => (
                                <div key={item.id} className="flex justify-between items-center text-xs p-2.5 bg-gray-900/30 rounded-xl border border-gray-700/30 hover:bg-gray-900/60 transition-colors">
                                    <div className="flex items-center gap-2">
                                        <div className="w-1 h-1 rounded-full bg-gray-600"></div>
                                        <div className="flex flex-col">
                                            <span className="text-gray-200 font-bold text-[11px]">{item.name}</span>
                                            <span className="text-[9px] text-gray-500">الكمية: <span className="text-gray-300">{item.quantity}</span> {item.unitType === 'kg' ? 'كغ' : 'قطعة'}</span>
                                        </div>
                                    </div>

                                    <div className="flex items-center gap-3">
                                        <div className="flex flex-col items-end">
                                            {editingPriceId === item.id ? (
                                                <input 
                                                  type="number" 
                                                  value={tempPrice} 
                                                  onChange={e => setTempPrice(e.target.value)} 
                                                  onBlur={() => savePrice(item.id)} 
                                                  onKeyDown={e => e.key === 'Enter' && savePrice(item.id)}
                                                  className="w-14 bg-gray-950 border border-[#FA8072] text-white rounded px-1 text-center text-[10px] outline-none" 
                                                  autoFocus 
                                                />
                                            ) : (
                                                <div className="flex items-center gap-1 cursor-pointer group/price" onClick={() => { setEditingPriceId(item.id); setTempPrice(item.price.toString()); }}>
                                                    <span className="text-[10px] text-gray-500 tabular-nums">{item.price.toLocaleString()}</span>
                                                    <Edit3 size={8} className="text-[#FA8072] opacity-0 group-hover/price:opacity-100" />
                                                </div>
                                            )}
                                            <span className="font-black text-white text-[11px] tabular-nums">{(item.price * item.quantity).toLocaleString()}</span>
                                        </div>
                                        <button onClick={() => onDeleteItem(item.id)} className="text-gray-700 hover:text-red-500 transition-colors p-1"><Trash2 size={12} /></button>
                                    </div>
                                </div>
                            ))}
                        </div>

                        {/* Actions */}
                        <div className="px-4 py-3 bg-gray-900/20 border-t border-gray-700/30 flex justify-between items-center no-print">
                            <button 
                              onClick={() => onPreviewInvoice(group)} 
                              className="flex items-center gap-1.5 text-[10px] font-black text-blue-400 hover:text-blue-300 transition-colors"
                            >
                                <Download size={12} /> تصدير
                            </button>
                            <button 
                              onClick={() => onDeleteOrder && onDeleteOrder(first.orderId)} 
                              className="flex items-center gap-1.5 text-[10px] font-black text-red-400/50 hover:text-red-400 transition-colors"
                            >
                                <Trash2 size={12} /> حذف الفاتورة
                            </button>
                        </div>
                    </div>
                );
            })}
        </div>

        {!searchTerm && !isExpanded && groupedOrders.length > 1 && (
            <div className="py-8 flex flex-col items-center justify-center gap-3 no-print">
                <div className="h-px w-24 bg-gray-800"></div>
                <p className="text-[10px] text-gray-500 font-bold uppercase tracking-[0.2em]">هناك {groupedOrders.length - 1} فواتير أخرى مخفية</p>
                <button 
                  onClick={() => setIsExpanded(true)}
                  className="text-[#FA8072] font-black text-xs hover:underline"
                >
                    عرض سجل اليوم بالكامل
                </button>
            </div>
        )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ShoppingCart, Settings, Edit3, Trash2, CheckCircle, Plus, Minus, UserPlus, X, Check, Calculator } from 'lucide-react';
import { Product, UnitType, SaleType, Customer } from '../types';

interface POSInterfaceProps {
  onCompleteOrder: (items: any[], customerName?: string, customerId?: string, saleType?: SaleType) => void;
  products: Product[];
  customers: Customer[];
  onOpenProductManager: () => void;
  onOpenCustomerManager: () => void;
}

export const POSInterface: React.FC<POSInterfaceProps> = ({ 
    onCompleteOrder, products, customers, onOpenProductManager, onOpenCustomerManager 
}) => {
  const [cart, setCart] = useState<any[]>([]);
  const [saleType, setSaleType] = useState<SaleType>('retail');
  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [manualCustomerName, setManualCustomerName] = useState(''); 
  const [showCustomInput, setShowCustomInput] = useState(false);
  const [customForm, setCustomForm] = useState({ name: '', price: '', cost: '', unit: 'piece' as UnitType });

  const [editingPriceId, setEditingPriceId] = useState<string | null>(null);
  const [editingTotalId, setEditingTotalId] = useState<string | null>(null);
  const [tempValue, setTempValue] = useState<string>('');

  useEffect(() => {
    setCart(prev => prev.map(item => {
      const productDef = products.find(p => p.name === item.name && p.unitType === item.unitType);
      if (productDef) {
        return {
          ...item,
          price: saleType === 'wholesale' ? (productDef.wholesalePrice || productDef.price) : productDef.price
        };
      }
      return item;
    }));
  }, [saleType, products]);

  const addToCart = (p: Product) => {
    setCart(prev => {
      const idx = prev.findIndex(i => i.name === p.name && i.unitType === p.unitType);
      const activePrice = saleType === 'wholesale' ? (p.wholesalePrice || p.price) : p.price;

      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], quantity: next[idx].quantity + (p.unitType === 'kg' ? 0.1 : 1), price: activePrice };
        return next;
      }
      return [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: p.name, 
        price: activePrice, 
        costPrice: p.costPrice || 0, 
        quantity: p.unitType === 'kg' ? 1 : 1, 
        unitType: p.unitType 
      }];
    });
  };

  const addCustomToCart = () => {
    if (!customForm.name || !customForm.price) return;
    setCart(prev => [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: customForm.name, 
        price: parseFloat(customForm.price) || 0, 
        costPrice: parseFloat(customForm.cost) || 0,
        quantity: 1,
        unitType: customForm.unit
    }]);
    setCustomForm({ name: '', price: '', cost: '', unit: 'piece' });
    setShowCustomInput(false);
  };

  const updateQty = (id: string, delta: number) => {
    setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: Math.max(0, parseFloat((i.quantity + delta * (i.unitType === 'kg' ? 0.1 : 1)).toFixed(3))) } : i));
  };

  const handleManualQtyChange = (id: string, value: string) => {
    const newQty = parseFloat(value);
    if (!isNaN(newQty)) {
        setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: newQty } : i));
    } else if (value === '') {
        setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: 0 } : i));
    }
  };

  // تعديل سعر الوحدة (سعر الكيلو أو سعر القطعة)
  const handleStartEditUnitPrice = (item: any) => {
    setEditingPriceId(item.tempId);
    setEditingTotalId(null);
    setTempValue(item.price.toString());
  };

  // تعديل إجمالي المبلغ (لحساب الوزن)
  const handleStartEditTotalAmount = (item: any) => {
    if (item.unitType !== 'kg') return; // هذه الميزة مفيدة للكيلو فقط
    setEditingTotalId(item.tempId);
    setEditingPriceId(null);
    setTempValue((item.price * item.quantity).toString());
  };

  const handleSaveEdit = (tempId: string) => {
    const val = parseFloat(tempValue);
    if (!isNaN(val) && val >= 0) {
      setCart(prev => prev.map(i => {
        if (i.tempId === tempId) {
          if (editingTotalId) {
            // الميزة المطلوبة: تعديل الوزن بناءً على إجمالي المبلغ المدخل
            const newQty = parseFloat((val / i.price).toFixed(3));
            return { ...i, quantity: newQty };
          } else {
            // تعديل سعر الوحدة بشكل طبيعي
            return { ...i, price: val };
          }
        }
        return i;
      }));
    }
    setEditingPriceId(null);
    setEditingTotalId(null);
  };

  const isCheckoutDisabled = cart.length === 0 || (saleType === 'wholesale' && !selectedCustomerId);

  const handleCheckout = () => {
    if (isCheckoutDisabled) return;
    const items = cart.map(({ name, price, costPrice, quantity, unitType }) => ({ name, price, costPrice, quantity, unitType }));
    const name = saleType === 'wholesale' ? customers.find(c => c.id === selectedCustomerId)?.name : manualCustomerName;
    onCompleteOrder(items, name, selectedCustomerId || undefined, saleType);
    setCart([]); setManualCustomerName(''); setSelectedCustomerId(''); setSaleType('retail');
  };

  const total = cart.reduce((s, i) => s + (i.price * i.quantity), 0);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">
      <div className="lg:col-span-2 space-y-4">
        <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
             <h2 className="font-bold text-white flex items-center gap-2"><ShoppingCart size={20} className="text-[#FA8072]" /> قائمة المنتجات</h2>
             <button onClick={onOpenProductManager} className="text-xs bg-gray-700 hover:bg-gray-600 text-gray-300 px-3 py-1.5 rounded-lg transition-colors">تعديل الأصناف</button>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
            {products.map(p => (
                <button key={p.id} onClick={() => addToCart(p)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-gray-700 hover:bg-gray-700 hover:border-[#FA8072] text-white rounded-2xl transition-all shadow-sm active:scale-95 h-32 relative group">
                    <div className={`absolute top-2 right-2 px-1.5 py-0.5 rounded text-[10px] font-bold ${p.unitType === 'kg' ? 'bg-yellow-400 text-black' : 'bg-blue-300 text-black'}`}>{p.unitType === 'kg' ? 'كغ' : 'قطعة'}</div>
                    <span className="font-bold text-sm text-center mb-1 group-hover:text-[#FA8072]">{p.name}</span>
                    <span className="text-xs text-gray-400 bg-gray-900/50 px-2 py-1 rounded-md">
                      {(saleType === 'wholesale' ? (p.wholesalePrice || p.price) : p.price).toLocaleString()} ل.س
                    </span>
                </button>
            ))}
