import React, { useState, useEffect } from 'react';
import { X, Copy, Check, Download, FileSpreadsheet, Printer } from 'lucide-react';
import { SaleItem } from '../types';
import { utils, writeFile } from 'xlsx';

interface InvoiceModalProps {
  items: SaleItem[];
  onClose: () => void;
}

export const InvoiceModal: React.FC<InvoiceModalProps> = ({ items, onClose }) => {
  const [copied, setCopied] = useState(false);
  const [confirmPrint, setConfirmPrint] = useState(false);

  const total = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const timeStr = items[0]?.time || new Date().toLocaleTimeString('ar-SY');
  const dayDate = new Date().toLocaleDateString('ar-SY');
  const customerName = items[0]?.customerName || 'زبون عام';
  const orderId = items[0]?.orderId || '0000';

  const handleDownloadExcel = () => {
    const data = items.map(i => ({ 
      "المادة": i.name, 
      "الكمية": i.quantity, 
      "السعر": i.price, 
      "الإجمالي": i.price * i.quantity 
    }));
    data.push({ "المادة": "المجموع الكلي", "الكمية": 0, "السعر": 0, "الإجمالي": total });
    const ws = utils.json_to_sheet(data);
    const wb = utils.book_new();
    utils.book_append_sheet(wb, ws, "Invoice");
    writeFile(wb, `فاتورة-${customerName}-${dayDate}.xlsx`);
  };

  const handleCopy = () => {
    const text = `مخبز كوكيز - فاتورة مبيعات\nالتاريخ: ${dayDate}\nالعميل: ${customerName}\nالمواد: ${items.map(i => `${i.name} (${i.quantity})`).join(' - ')}\nالمجموع: ${total} ل.س`;
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const handlePrint = () => {
    window.print();
    setConfirmPrint(false);
  };

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-sm z-[100] flex items-center justify-center p-4 no-print-overlay">
      <div className="bg-gray-800 rounded-[2.5rem] w-full max-w-xl shadow-2xl border border-gray-700 animate-fade-up overflow-hidden flex flex-col max-h-[90vh] print:max-h-none print:shadow-none print:border-none print:bg-white print:w-[80mm]">

        {/* Header - Hidden on Print */}
        <div className="p-5 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 no-print">
          <div className="flex items-center gap-2">
            <Printer size={20} className="text-[#FA8072]" />
            <h3 className="font-black text-lg text-white">معاينة الفاتورة</h3>
          </div>
          <button onClick={onClose} className="p-2 text-gray-400 hover:text-white transition-colors"><X size={24} /></button>
        </div>

        {/* Invoice Body */}
        <div className="flex-1 overflow-y-auto bg-white print:overflow-visible">
           <div id="invoice-content" className="bg-white text-black p-8 sm:p-12 min-h-full print:p-4 print:w-[80mm] print:mx-auto">
            {/* Logo & Info */}
            <div className="text-center mb-6 border-b-2 border-black pb-4">
              <h2 className="text-2xl font-black mb-1 print:text-black">مخبز كوكيز</h2>
              <p className="text-xs font-bold uppercase tracking-widest print:text-black">فاتورة مبيعات / سند تسليم</p>
              <div className="flex justify-between items-center mt-2 px-2">
                 <p className="text-[10px] font-bold tabular-nums print:text-black">{dayDate}</p>
                 <p className="text-[10px] font-bold tabular-nums print:text-black">{timeStr}</p>
              </div>
              <div className="mt-3 inline-block px-3 py-0.5 border-2 border-black rounded-md text-[10px] font-black print:text-black">
                رقم الفاتورة: #{orderId.slice(-6)}
              </div>
            </div>

            {/* Customer & Date */}
            <div className="flex flex-col gap-1 mb-6 border-b border-black pb-4">
              <span className="text-[9px] uppercase font-black text-black block">الزبون:</span>
              <p className="text-lg font-black print:text-black">{customerName}</p>
              <div className="flex justify-between items-center mt-1">
                 <span className="text-[10px] font-bold print:text-black">النوع: {items[0]?.saleType === 'wholesale' ? 'جملة' : 'مفرق'}</span>
              </div>
            </div>

            {/* Items Table */}
            <table className="w-full text-right mb-8">
              <thead>
                <tr className="border-b-2 border-black">
                  <th className="py-2 px-1 text-right font-black text-xs uppercase print:text-black">المادة</th>
                  <th className="py-2 px-1 text-center font-black text-xs uppercase print:text-black">الكمية</th>
                  <th className="py-2 px-1 text-left font-black text-xs uppercase print:text-black">الإجمالي</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-black/20 print:divide-black">
                {items.map((item, idx) => (
                  <tr key={idx} className="font-bold text-[11px] print:text-black">
                    <td className="py-3 px-1 text-right">{item.name}</td>
                    <td className="py-3 px-1 text-center tabular-nums">{item.quantity}</td>
                    <td className="py-3 px-1 text-left font-black tabular-nums">{(item.price * item.quantity).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>

            {/* Total Section */}
            <div className="border-t-2 border-black pt-4 mb-10">
              <div className="flex justify-between items-center text-xl font-black print:text-black">
                <span>المجموع:</span>
                <span className="tabular-nums underline decoration-2">{total.toLocaleString()} ل.س</span>
              </div>
            </div>

            {/* Signature Area */}
            <div className="mt-10 flex justify-between items-end px-2 opacity-0 print:opacity-100">
               <div className="text-center">
                   <p className="mb-8 font-black text-black text-[9px]">المستلم</p>
                   <div className="w-20 border-b border-black"></div>
               </div>
               <div className="text-center">
                   <p className="mb-8 font-black text-black text-[9px]">المحاسب</p>
                   <div className="w-20 border-b border-black"></div>
               </div>
            </div>

            <div className="mt-8 text-center text-[9px] font-black border-t border-dashed border-black pt-4 print:text-black">
              صنع بكل حب في مخبز كوكيز
            </div>
          </div>
        </div>

        {/* Actions - Hidden on Print */}
        <div className="p-6 bg-gray-900/80 border-t border-gray-700 no-print">
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mb-3">
                {confirmPrint ? (
                    <div className="sm:col-span-2 flex items-center gap-2">
                        <button onClick={handlePrint} className="flex-1 bg-green-600 hover:bg-green-500 text-white py-3.5 rounded-2xl font-black text-[10px] transition-all shadow-xl active:scale-95">تأكيد الطباعة (80mm)</button>
                        <button onClick={() => setConfirmPrint(false)} className="flex-1 bg-gray-700 text-white py-3.5 rounded-2xl font-black text-[10px]">إلغاء</button>
                    </div>
                ) : (
                    <button onClick={() => setConfirmPrint(true)} className="sm:col-span-2 bg-[#FA8072] hover:bg-orange-500 text-white py-3.5 rounded-2xl font-black text-[10px] flex items-center justify-center gap-2 transition-all shadow-xl active:scale-95">
                        <Printer size={16} /> طباعة للفاتورة
                    </button>
                )}

                <button onClick={handleDownloadExcel} className="bg-green-700 hover:bg-green-600 text-white py-3.5 rounded-2xl font-black text-[10px] flex items-center justify-center gap-2 transition-all shadow-xl active:scale-95">
                    <FileSpreadsheet size={16} /> ملف Excel
                </button>
            </div>

            <button 
                onClick={handleCopy} 
                className={`w-full py-3.5 rounded-2xl font-black text-[10px] flex items-center justify-center gap-2 transition-all border border-gray-700 ${copied ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-gray-800 text-gray-400 hover:text-white'}`}
            >
                {copied ? <Check size={16} /> : <Copy size={16} />} 
                {copied ? 'تم نسخ بيانات الفاتورة' : 'نسخ الفاتورة كنص'}
            </button>
        </div>
      </div>
    </div>
  );
};

