import React, { useState } from 'react';
import { X, Copy, Check, FileSpreadsheet, Printer } from 'lucide-react';
import { SaleItem } from '../types';
import { utils, writeFile } from 'xlsx';

interface InvoiceModalProps {
  items: SaleItem[];
  onClose: () => void;
}

export const InvoiceModal: React.FC<InvoiceModalProps> = ({ items, onClose }) => {
  const [copied, setCopied] = useState(false);

  const total = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const timeStr = items[0]?.time || new Date().toLocaleTimeString('ar-SY');
  const dayDate = new Date().toLocaleDateString('ar-SY');
  const customerName = items[0]?.customerName || 'زبون عام';
  const customerNumber = items[0]?.customerNumber || 0;

  const handleDownloadExcel = () => {
    const data = items.map(i => ({ 
      "المادة": i.name, 
      "الكمية": i.quantity, 
      "السعر": i.price, 
      "الإجمالي": i.price * i.quantity 
    }));
    data.push({ "المادة": "المجموع الكلي", "الكمية": 0, "السعر": 0, "الإجمالي": total });
    const ws = utils.json_to_sheet(data);
    const wb = utils.book_new();
    utils.book_append_sheet(wb, ws, "Invoice");
    writeFile(wb, `فاتورة-${customerNumber}-${customerName}-${dayDate}.xlsx`);
  };

  const handlePrint = () => {
    const printContent = document.getElementById('pos-invoice-content');
    const printArea = document.getElementById('print-area');

    if (printContent && printArea) {
      // حقن المحتوى في حاوية الطباعة المخصصة في index.html
      printArea.innerHTML = printContent.innerHTML;
      printArea.className = 'print-mode-80mm';

      // تأخير بسيط لضمان استقرار العناصر
      setTimeout(() => {
        window.print();
        // تنظيف الحاوية بعد الطباعة
        setTimeout(() => {
          printArea.innerHTML = ''; 
          printArea.className = '';
        }, 500);
      }, 300);
    }
  };

  const handleCopy = () => {
    const text = `مخبز كوكيز - فاتورة مبيعات\nرقم الفاتورة: ${customerNumber}\nالتاريخ: ${dayDate}\nالعميل: ${customerName}\nالمواد: ${items.map(i => `${i.name} (${i.quantity})`).join(' - ')}\nالمجموع: ${total} ل.س`;
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  return (
    <div className="fixed inset-0 bg-black/95 backdrop-blur-md z-[100] flex items-center justify-center p-4 overflow-y-auto no-print">
      <div className="bg-gray-800 rounded-[2.5rem] w-full max-w-lg shadow-2xl border border-gray-700 animate-fade-up overflow-hidden flex flex-col h-[90vh]">

        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900 shrink-0">
          <div className="flex items-center gap-3">
            <div className="bg-[#FA8072]/20 p-2 rounded-xl"><Printer size={20} className="text-[#FA8072]" /></div>
            <h3 className="font-black text-sm text-white">معاينة الفاتورة (80mm)</h3>
          </div>
          <button onClick={onClose} className="p-2 text-gray-400 hover:text-white transition-colors"><X size={24} /></button>
        </div>

        <div className="flex-1 overflow-y-auto bg-gray-950/50 p-6 flex justify-center">
           <div id="pos-invoice-content" className="bg-white text-black p-4 w-[80mm] shadow-2xl h-fit">
            <div className="text-center mb-4 border-b-2 border-black pb-2">
              <h2 className="text-xl font-black mb-0 text-black">مخبز كوكيز</h2>
              <p className="text-[10px] font-black text-black uppercase">فاتورة مبيعات</p>
              <div className="flex justify-between items-center mt-2 text-[9px] font-black">
                 <span>رقم: #{customerNumber}</span>
                 <span>{dayDate} - {timeStr}</span>
              </div>
            </div>

            <div className="mb-4">
              <span className="text-[9px] font-black block text-gray-500">الزبون:</span>
              <p className="text-lg font-black text-black leading-tight">{customerName}</p>
            </div>

            <table className="w-full text-right mb-4 border-t border-black">
              <thead>
                <tr className="text-[10px] font-black border-b border-black">
                  <th className="py-1">المادة</th>
                  <th className="py-1 text-center">الكمية</th>
                  <th className="py-1 text-left">الإجمالي</th>
                </tr>
              </thead>
              <tbody>
                {items.map((item, idx) => (
                  <tr key={idx} className="text-[11px] font-black border-b border-black/10">
                    <td className="py-2 leading-tight">{item.name}</td>
                    <td className="py-2 text-center">{item.quantity}</td>
                    <td className="py-2 text-left">{(item.price * item.quantity).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>

            <div className="border-t-2 border-black pt-2 mb-6">
              <div className="flex justify-between items-center text-xl font-black">
                <span>المجموع:</span>
                <span>{total.toLocaleString()}</span>
              </div>
            </div>

            <div className="text-center text-[9px] font-black border-t border-dashed border-black pt-2 mb-8">
              شكراً لزيارتكم - مخبز كوكيز
            </div>
            {/* سبيس إضافي للطباعة الحرارية */}
            <div className="h-10 print:block hidden"></div>
          </div>
        </div>

        <div className="p-6 bg-gray-900 border-t border-gray-700 shrink-0">
            <div className="grid grid-cols-2 gap-3 mb-3">
                <button onClick={handlePrint} className="bg-[#FA8072] hover:bg-orange-500 text-white py-4 rounded-2xl font-black text-xs flex items-center justify-center gap-2 shadow-xl">
                    <Printer size={18} /> طباعة الفاتورة
                </button>
                <button onClick={handleDownloadExcel} className="bg-green-700 hover:bg-green-600 text-white py-4 rounded-2xl font-black text-xs flex items-center justify-center gap-2 shadow-xl">
                    <FileSpreadsheet size={18} /> تصدير Excel
                </button>
            </div>
            <button onClick={handleCopy} className={`w-full py-3.5 rounded-2xl font-black text-[10px] flex items-center justify-center gap-2 transition-all border border-gray-700 ${copied ? 'bg-indigo-600 text-white' : 'bg-gray-800 text-gray-400'}`}>
                {copied ? <Check size={16} /> : <Copy size={16} />} 
                {copied ? 'تم النسخ' : 'نسخ كـنص'}
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { X, BarChart3, Printer, Activity, Target } from 'lucide-react';
import { ArchivedDay, SaleItem, PurchaseInvoice } from '../types';

interface AnalyticsModalProps {
  history: ArchivedDay[];
  currentSales: SaleItem[];
  currentPurchases: PurchaseInvoice[];
  onClose: () => void;
}

export const AnalyticsModal: React.FC<AnalyticsModalProps> = ({ history, currentSales, currentPurchases, onClose }) => {
  const [viewMode, setViewMode] = useState<'days' | 'monthly'>('days');
  const [daysCount, setDaysCount] = useState<7 | 15 | 30>(7);

  const now = new Date();
  const [selectedMonth, setSelectedMonth] = useState(now.getMonth());
  const [selectedYear, setSelectedYear] = useState(now.getFullYear());

  const allData = useMemo(() => {
    const todayStr = now.toLocaleDateString('ar-SY');
    const combined = [
      ...history.map(day => ({
        date: day.date,
        revenue: day.totalRevenue,
        purchases: (day.purchaseInvoices || []).reduce((s, i) => s + i.totalAmount, 0),
        profit: day.items.reduce((s, i) => s + ((i.price - (i.costPrice || 0)) * i.quantity), 0),
        items: day.items,
        timestamp: day.timestamp
      })),
      {
        date: todayStr,
        revenue: currentSales.reduce((s, i) => s + (i.price * i.quantity), 0),
        purchases: currentPurchases.reduce((s, i) => s + i.totalAmount, 0),
        profit: currentSales.reduce((s, i) => s + ((i.price - (i.costPrice || 0)) * i.quantity), 0),
        items: currentSales,
        timestamp: Date.now()
      }
    ].sort((a, b) => a.timestamp - b.timestamp);
    return combined;
  }, [history, currentSales, currentPurchases]);

  const filteredData = useMemo(() => {
    if (viewMode === 'days') return allData.slice(-daysCount);
    return allData.filter(d => {
      const date = new Date(d.timestamp);
      return date.getMonth() === selectedMonth && date.getFullYear() === selectedYear;
    });
  }, [allData, viewMode, daysCount, selectedMonth, selectedYear]);

  const totals = useMemo(() => {
    const revenue = filteredData.reduce((s, d) => s + d.revenue, 0);
    const purchases = filteredData.reduce((s, d) => s + d.purchases, 0);
    const profit = filteredData.reduce((s, d) => s + d.profit, 0);
    const expenseRatio = revenue > 0 ? (purchases / revenue * 100) : 0;
    const profitMargin = revenue > 0 ? (profit / revenue * 100) : 0;

    return { revenue, purchases, profit, expenseRatio, profitMargin };
  }, [filteredData]);

  const productStats = useMemo(() => {
    const stats: Record<string, { qty: number, revenue: number, profit: number, cost: number }> = {};
    filteredData.forEach(day => {
      day.items.forEach(item => {
        if (!stats[item.name]) stats[item.name] = { qty: 0, revenue: 0, profit: 0, cost: 0 };
        stats[item.name].qty += item.quantity;
        stats[item.name].revenue += (item.price * item.quantity);
        stats[item.name].cost += ((item.costPrice || 0) * item.quantity);
        stats[item.name].profit += ((item.price - (item.costPrice || 0)) * item.quantity);
      });
    });
    return Object.entries(stats).sort((a, b) => b[1].revenue - a[1].revenue);
  }, [filteredData]);

  const renderTimelineChart = () => {
    if (filteredData.length < 2) return (
        <div className="h-32 flex items-center justify-center border border-dashed border-gray-300 text-gray-400 text-[10px]">
            لا توجد بيانات كافية لرسم المنحنى الزمني حالياً
        </div>
    );

    const width = 800;
    const height = 150;
    const padding = 40;

    const maxVal = Math.max(...filteredData.map(d => Math.max(d.revenue, d.purchases, d.profit, 1000)));
    const getX = (index: number) => padding + (index * (width - 2 * padding) / (filteredData.length - 1));
    const getY = (val: number) => height - padding - (val * (height - 2 * padding) / maxVal);

    const revPath = filteredData.map((d, i) => `${i === 0 ? 'M' : 'L'} ${getX(i)} ${getY(d.revenue)}`).join(' ');
    const purPath = filteredData.map((d, i) => `${i === 0 ? 'M' : 'L'} ${getX(i)} ${getY(d.purchases)}`).join(' ');
    const profPath = filteredData.map((d, i) => `${i === 0 ? 'M' : 'L'} ${getX(i)} ${getY(d.profit)}`).join(' ');

    return (
      <div className="py-4">
        <h4 className="text-[10px] font-black mb-4 flex items-center gap-2 text-gray-800 uppercase tracking-wider">
           <Activity size={12} className="text-black" /> الاتجاه المالي المباشر (الزمن vs القيمة):
        </h4>
        <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-auto overflow-visible">
          <line x1={padding} y1={height - padding} x2={width - padding} y2={height - padding} stroke="black" strokeWidth="1" />
          {filteredData.map((d, i) => {
             if (filteredData.length > 10 && i % 4 !== 0) return null;
             return (
               <text key={i} x={getX(i)} y={height - padding + 15} fontSize="8" fontWeight="bold" textAnchor="middle" fill="#999">
                 {d.date.split('/')[0]}
               </text>
             );
          })}
          <path d={revPath} fill="none" stroke="#10b981" strokeWidth="2.5" strokeLinecap="round" />
          <path d={purPath} fill="none" stroke="#ef4444" strokeWidth="1.5" strokeDasharray="4,2" />
          <path d={profPath} fill="none" stroke="#000000" strokeWidth="3" strokeLinecap="round" />
          {filteredData.map((d, i) => (
            <circle key={i} cx={getX(i)} cy={getY(d.profit)} r="3" fill="black" />
          ))}
        </svg>
        <div className="flex justify-center gap-8 mt-6 text-[8px] font-black border-t border-gray-100 pt-3">
           <div className="flex items-center gap-2"><div className="w-3 h-3 bg-[#10b981] rounded-full"></div> <span>المبيعات</span></div>
           <div className="flex items-center gap-2"><div className="w-3 h-1 bg-[#ef4444]"></div> <span>المشتريات</span></div>
           <div className="flex items-center gap-2"><div className="w-3 h-3 bg-black rounded-full"></div> <span>الربح الصافي</span></div>
        </div>
      </div>
    );
  };

  const handlePrint = () => {
    const printContent = document.getElementById('report-a4-content');
    const printArea = document.getElementById('print-area');
    if (printContent && printArea) {
      printArea.innerHTML = printContent.innerHTML;
      printArea.className = 'print-mode-a4';
      setTimeout(() => {
        window.print();
        setTimeout(() => { printArea.innerHTML = ''; printArea.className = ''; }, 500);
      }, 300);
    }
  };

  const getMonthName = (m: number) => new Date(2000, m).toLocaleString('ar-SY', { month: 'long' });

  return (
    <div className="fixed inset-0 bg-black/95 backdrop-blur-md z-50 flex items-center justify-center p-4 no-print">
